-- Poems batch 11
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('af90c196-d5f3-4b4b-a11a-e7565c1c2ede','銅雀臺','王建','唐','唐诗','tang','','[]','嬌愛更何日，高臺空數層。',107,'全唐诗/poet.tang.16000.json','["嬌愛更何日，高臺空數層。", "含啼暎雙袖，不忍看西陵。", "漳水東流無復來，百花輦路爲蒼苔。", "青樓月夜長寂寞，碧雲日莫空裴回。", "君不見鄴中萬事非昔時，古人不在今人悲。", "春風不逐君王去，草色年年舊宮路。", "宮中歌舞已浮雲，空指行日往來處。"]'),
('95549428-993a-4bb5-8df5-5314a1d1a0b7','雞鳴曲','王建','唐','唐诗','tang','','[]','雞初鳴，明星照東屋。',100,'全唐诗/poet.tang.16000.json','["雞初鳴，明星照東屋。", "雞再鳴，紅霞生海腹。", "百官待漏雙闕前，聖人亦挂山龍服。", "寶釵命婦燈下起，環珮玲瓏曉光裏。", "直內初燒玉案香，司更尚滴銅壺水。", "金吾衞裏直郎妻，到明不睡聽晨雞。", "天頭日月相送迎，夜棲旦鳴人不迷。"]'),
('6506d657-132c-4a38-8f74-f806603d7be4','送衣曲','王建','唐','唐诗','tang','','["\u9ec4\u6cb3"]','去秋送衣渡黃河，今秋送衣上隴坂。',96,'全唐诗/poet.tang.16000.json','["去秋送衣渡黃河，今秋送衣上隴坂。", "婦人不知道徑處，但問新移軍近遠。", "半年著道經雨濕，開籠見風衣領急。", "舊來十月初點衣，與郎著向營中集。", "絮時厚厚綿纂纂，貴欲征人身上暖。", "願身莫著裹屍歸，願妾不死長送衣。"]'),
('aad76797-2f87-4dce-ac75-4d14e9a04b6a','斜路行','王建','唐','唐诗','tang','','[]','世間娶容非娶婦，中庭牡丹勝松樹。',112,'全唐诗/poet.tang.16000.json','["世間娶容非娶婦，中庭牡丹勝松樹。", "九衢大道人不行，走馬奔車逐斜路。", "斜路行熟直路荒，東西豈是橫太行。", "南樓彈弦北戶舞，行人到此多回徨。", "頭白如絲面如繭，亦學少年行不返。", "縱令自解思故鄉，輪折蹄穿白日晚。", "誰將古曲換斜音，回取行人斜路心。"]'),
('dff401cb-6ddc-4559-a19a-075a15f132f1','織錦曲','王建','唐','唐诗','tang','','[]','大女身爲織錦戶，名在縣家供進簿。',160,'全唐诗/poet.tang.16000.json','["大女身爲織錦戶，名在縣家供進簿。", "長頭起樣呈作官，聞道官家中苦難。", "回花側葉與人別，唯恐秋天絲線乾。", "紅縷葳蕤紫茸軟，蝶飛參差花宛轉。", "一梭聲盡重一梭，玉腕不停羅袖卷。", "窗中夜久睡髻偏，橫釵欲墮垂著肩。", "合衣臥時參沒後，停燈起在雞鳴前。", "一匹千金亦不賣，限日未成宮裏怪。", "錦江水涸貢轉多，宮中盡著單絲羅。", "莫言山積無盡日，百丈高樓一曲歌。"]'),
('90abcad7-1574-4787-835d-802f9afd9437','擣衣曲','王建','唐','唐诗','tang','','[]','月明中庭擣衣石，掩帷下堂來擣帛。',112,'全唐诗/poet.tang.16000.json','["月明中庭擣衣石，掩帷下堂來擣帛。", "婦姑相對神力生，雙揎白腕調杵聲。", "高樓敲玉節會成，家家不睡皆起聽。", "秋天丁丁復凍凍，玉釵低昂衣帶動。", "夜深月落冷如刀，濕著一雙纖手痛。", "回編易裂看生熟，鴛鴦紋成水波曲。", "重燒熨斗帖兩頭，與郎裁作迎寒裘。"]'),
('0d9de0db-ce2e-4f00-8736-7eea7b2dcadb','秋夜曲二首 一','王建','唐','唐诗','tang','','[]','天清漏長霜泊泊，蘭綠收榮桂膏涸。',80,'全唐诗/poet.tang.16000.json','["天清漏長霜泊泊，蘭綠收榮桂膏涸。", "高樓雲鬟弄嬋娟，古瑟暗斷秋風弦。", "玉關遙隔萬里道，金刀不翦雙淚泉。", "香囊火死香氣少，向帷合眼何時曉。", "城烏作營啼野月，秦州少婦生離別。"]'),
('4eb1dc7c-cb19-43e4-96d6-12b78af04b91','秋夜曲二首 二','王建','唐','唐诗','tang','','[]','秋燈向壁掩洞房，良人此夜直明光。',32,'全唐诗/poet.tang.16000.json','["秋燈向壁掩洞房，良人此夜直明光。", "天河悠悠漏水長，南樓北斗兩相當。"]'),
('7fb9f6d7-d085-49dc-9124-4b47f27575eb','題台州隱靜寺','王建','唐','唐诗','tang','','[]','隱靜靈仙寺天鑿，杯度飛來建巖壑。',64,'全唐诗/poet.tang.16000.json','["隱靜靈仙寺天鑿，杯度飛來建巖壑。", "五峰直上插銀河，一澗當空瀉寥廓。", "崆峒黯淡碧琉璃，白雲吞吐紅蓮閣。", "不知勢壓天幾重，鐘聲常聞月中落。"]'),
('ef994740-d876-4ef2-871b-2f4e337676d6','送人遊塞','王建','唐','唐诗','tang','','["\u9001\u522b", "\u8fb9\u585e"]','初晴天墮絲，晚色上春枝。',48,'全唐诗/poet.tang.16000.json','["初晴天墮絲，晚色上春枝。", "城下路分處，邊頭人去時。", "停車數行日，勸酒問回期。", "亦是茫茫客，還從此別離。"]'),
('7a610134-8296-4b06-8db8-44806faa9a56','塞上逢故人','王建','唐','唐诗','tang','','[]','百戰一身在，相逢白髮生。',48,'全唐诗/poet.tang.16000.json','["百戰一身在，相逢白髮生。", "何時得鄉信，每日算歸程。", "走馬登寒壠，驅羊入廢城。", "羌笳三兩曲，人醉海西營。"]'),
('170cddac-82c2-423c-a1ed-f9f1e21b3e10','南中','王建','唐','唐诗','tang','','[]','天南多鳥聲，州縣半無城。',48,'全唐诗/poet.tang.16000.json','["天南多鳥聲，州縣半無城。", "野市依蠻姓，山邨逐水名。", "瘴煙沙上起，陰火雨中生。", "獨有求珠客，年年入海行。"]'),
('b3287bda-4b03-491e-af7a-63ee23c2b71d','汴路水驛','王建','唐','唐诗','tang','','[]','晚泊水邊驛，柳塘初起風。',48,'全唐诗/poet.tang.16000.json','["晚泊水邊驛，柳塘初起風。", "蛙鳴蒲葉下，魚入稻花中。", "去舍已云遠，問程猶向東。", "近來多怨別，不與少年同。"]'),
('7d925f9e-839f-4683-a033-b927a43d1938','淮南使廻留別竇侍御','王建','唐','唐诗','tang','','[]','戀戀春恨結，綿綿淮草深。',48,'全唐诗/poet.tang.16000.json','["戀戀春恨結，綿綿淮草深。", "病身愁至夜，遠道畏逢陰。", "忽逐酒盃會，暫同風景心。", "從今一分散，還是曉枝禽。"]'),
('18d4539c-2111-475f-9834-b502125a482b','汴路即事','王建','唐','唐诗','tang','','[]','千里河煙直，青槐夾岸長。',48,'全唐诗/poet.tang.16000.json','["千里河煙直，青槐夾岸長。", "天涯同此路，人語各殊方。", "草市迎江貨，津橋稅海商。", "廻看故宮柳，憔悴不成行。"]'),
('ca5edd9f-b86c-46df-a7bc-9ada960961ec','山居','王建','唐','唐诗','tang','','[]','屋在瀑泉西，茅簷下有溪。',48,'全唐诗/poet.tang.16000.json','["屋在瀑泉西，茅簷下有溪。", "閉門留野鹿，分食養山雞。", "桂熟長收子，蘭生不作畦。", "初開洞中路，深處轉松梯。"]'),
('4765f562-e574-40e2-85d5-bc946bd3d7c5','醉後憶山中故人','王建','唐','唐诗','tang','','[]','花開草復秋，雲水自悠悠。',48,'全唐诗/poet.tang.16000.json','["花開草復秋，雲水自悠悠。", "因醉暫無事，在山難免愁。", "遇晴須看月，鬬健且登樓。", "暗想山中伴，如今盡白頭。"]'),
('a21cac65-f792-4c23-b9dd-2a26b0f4cb79','送流人','王建','唐','唐诗','tang','','[]','見說長沙去，無親亦共愁。',48,'全唐诗/poet.tang.16000.json','["見說長沙去，無親亦共愁。", "陰雲鬼門夜，寒雨瘴江秋。", "水國山魈引，蠻鄉洞主留。", "漸看歸處遠，垂白住炎州。"]'),
('6032689f-fa7e-4cce-986b-bcd9e827845e','貧居','王建','唐','唐诗','tang','','[]','眼底貧家計，多時總莫嫌。',48,'全唐诗/poet.tang.16000.json','["眼底貧家計，多時總莫嫌。", "蠹生騰藥紙，字暗換書籤。", "避雨拾黃葉，遮風下黑簾。", "近來身不健，時就六壬占。"]'),
('6c1cfbf4-0e02-42ae-a6d2-5308cc780b44','過趙居士擬置草堂處所','王建','唐','唐诗','tang','','[]','休師竹林北，空可兩三間。',48,'全唐诗/poet.tang.16000.json','["休師竹林北，空可兩三間。", "雖愛獨居好，終來相伴閑。", "猶嫌近前樹，爲礙看南山。", "的有深耕處，春初須早還。"]'),
('49a81a19-8085-4d98-9f51-bdbc98b2b594','新開望山處','王建','唐','唐诗','tang','','[]','新開望山處，今朝減病眠。',48,'全唐诗/poet.tang.16000.json','["新開望山處，今朝減病眠。", "應移千里道，猶自數峰偏。", "故欲遮春巷，還來遶暮天。", "老夫行步弱，免到寺門前。"]'),
('b716f4f8-b3d6-49b7-82a1-258948fa11ce','題東華觀','王建','唐','唐诗','tang','','[]','路盡煙水外，院門題上清。',36,'全唐诗/poet.tang.16000.json','["路盡煙水外，院門題上清。", "鶴雛靈解語，瓊葉軟無聲。", "白髮道心熟，黃衣仙骨輕。"]'),
('71571557-6ab0-4cd7-b9f6-f5d3b991e7b2','飯僧','王建','唐','唐诗','tang','','[]','別屋炊香飯，薰辛不入家。',48,'全唐诗/poet.tang.16000.json','["別屋炊香飯，薰辛不入家。", "溫泉調葛麵，淨手摘藤花。", "蒲鮓除青葉，芹虀帶紫芽。", "願師常伴食，消氣有薑茶。"]'),
('a3e2115b-2005-4ef0-8116-9731c8974e5b','照鏡','王建','唐','唐诗','tang','','[]','忽自見憔悴，壯年人亦疑。',48,'全唐诗/poet.tang.16000.json','["忽自見憔悴，壯年人亦疑。", "髮緣多病落，力爲不行衰。", "暖手揉雙目，看圖引四肢。", "老來真愛道，所恨覺還遲。"]'),
('ff29f941-f02a-4e39-a913-c8e8e4b30256','歸昭應留別城中','王建','唐','唐诗','tang','','[]','喜得近京城，官卑意亦榮。',48,'全唐诗/poet.tang.16000.json','["喜得近京城，官卑意亦榮。", "竝牀歡未定，離室思還生。", "計拙偷閑住，經過買日行。", "如無自來分，一驛是遙程。"]'),
('e76a9e8e-c640-40b3-bf3d-dc0ca2985fe4','答寄芙蓉冠子','王建','唐','唐诗','tang','','[]','一學芙蓉葉，初開映水幽。',48,'全唐诗/poet.tang.16000.json','["一學芙蓉葉，初開映水幽。", "雖經小兒手，不稱老夫頭。", "枕上眠常戴，風前醉恐柔。", "明年有閨閣，此樣必難求。"]'),
('6b31ad9c-80b8-4451-853b-dddffb7869d8','長安春遊','王建','唐','唐诗','tang','','[]','騎馬傍閑坊，新衣著雨香。',48,'全唐诗/poet.tang.16000.json','["騎馬傍閑坊，新衣著雨香。", "桃花紅粉醉，柳樹白雲狂。", "不覺愁春去，何曾得日長。", "牡丹相次發，城裏又須忙。"]'),
('0d331180-0118-4958-aaca-e3592921811b','冬夜感懷','王建','唐','唐诗','tang','','[]','晚年恩愛少，耳目靜於僧。',48,'全唐诗/poet.tang.16000.json','["晚年恩愛少，耳目靜於僧。", "竟夜不聞語，空房唯有燈。", "氣噓寒被濕，霜入破窗凝。", "斷得人間事，長如此亦能。"]'),
('c67affe1-5356-4f31-ae7a-aa5ce2d4156d','初到昭應呈同僚','王建','唐','唐诗','tang','','[]','白髮初爲吏，有慙年少郎。',48,'全唐诗/poet.tang.16000.json','["白髮初爲吏，有慙年少郎。", "自知身上拙，不稱世間忙。", "秋雨懸牆綠，暮山宮樹黃。", "同官若容許，長借老僧房。"]'),
('c0e4aa1a-c2f4-42d5-b201-a79b0d8229ae','縣丞廳即事','王建','唐','唐诗','tang','','[]','宮殿半山上，人家高下居。',48,'全唐诗/poet.tang.16000.json','["宮殿半山上，人家高下居。", "古廳眠受魘，老吏語多虛。", "雨水洗荒竹，溪沙填廢渠。", "聖朝收外府，皆自九天除。"]'),
('689890f4-b6bf-444c-8377-2ef92457a284','閑居即事','王建','唐','唐诗','tang','','[]','老病貪光景，尋常不下簾。',48,'全唐诗/poet.tang.16000.json','["老病貪光景，尋常不下簾。", "妻愁耽酒僻，人怪考詩嚴。", "小婢偷紅紙，嬌兒弄白髯。", "有時看舊卷，未免意中嫌。"]'),
('5320c3fa-65c0-4a38-bf28-8979e634bdac','林居','王建','唐','唐诗','tang','','[]','荒林四面通，門在野田中。',48,'全唐诗/poet.tang.16000.json','["荒林四面通，門在野田中。", "頑僕長如客，貧居未勝蓬。", "舊綿衣不煖，新草屋多風。", "唯去山南近，閑親販藥翁。"]'),
('b527b410-01c6-48d3-927a-75a83d29e133','原上新居十三首 一','王建','唐','唐诗','tang','','[]','新占原頭地，本無山可歸。',48,'全唐诗/poet.tang.16000.json','["新占原頭地，本無山可歸。", "荒藤生葉晚，老杏著花稀。", "廚舍近泥竈，家人初飽薇。", "弟兄今四散，何日更相依。"]'),
('c5209a20-95ea-4d32-8c8c-5f923d3a83a1','原上新居十三首 二','王建','唐','唐诗','tang','','[]','一家榆柳新，四面遠無鄰。',50,'全唐诗/poet.tang.16000.json','["一家榆柳新，四面遠無鄰。", "人少愁聞病，莊孤幸得貧。", "耕牛長願飽，樵僕每憐勤。", "終日憂衣食，何由[脫]此身。"]'),
('e3732f10-c783-447f-be17-1e6368c107c7','原上新居十三首 三','王建','唐','唐诗','tang','','[]','長安無舊識，百里是天涯。',48,'全唐诗/poet.tang.16000.json','["長安無舊識，百里是天涯。", "寂寞思逢客，荒涼喜見花。", "訪僧求賤藥，將馬中豪家。", "乍得新蔬菜，朝盤忽覺奢。"]'),
('a676b731-62c9-4e8b-9ca1-5b543cb1aa7a','原上新居十三首 四','王建','唐','唐诗','tang','','[]','雞鳴村舍遙，花發亦蕭條。',48,'全唐诗/poet.tang.16000.json','["雞鳴村舍遙，花發亦蕭條。", "野竹初生笋，溪田未得苗。", "家貧僮僕瘦，春冷菜蔬焦。", "甘分長如此，無名在聖朝。"]'),
('913c9b6d-d12a-4fb7-b56a-2fca16d7074c','原上新居十三首 五','王建','唐','唐诗','tang','','[]','春來梨棗盡，啼哭小兒飢。',48,'全唐诗/poet.tang.16000.json','["春來梨棗盡，啼哭小兒飢。", "鄰富雞常去，莊貧客漸稀。", "借牛畊地晚，賣樹納錢遲。", "牆下當官路，依山補竹籬。"]'),
('4b17bd7e-2016-4e0d-8975-ff7a3e9b7d5d','原上新居十三首 六','王建','唐','唐诗','tang','','[]','自埽一間房，唯鋪獨臥牀。',48,'全唐诗/poet.tang.16000.json','["自埽一間房，唯鋪獨臥牀。", "野羹溪菜滑，山紙水苔香。", "陳藥初和白，新經未入黃。", "近來心力少，休讀養生方。"]'),
('3c7bedba-c2eb-4bba-ae14-eb6e3c6bb708','原上新居十三首 七','王建','唐','唐诗','tang','','[]','擬作讀經人，空房置淨巾。',48,'全唐诗/poet.tang.16000.json','["擬作讀經人，空房置淨巾。", "鎖茶藤篋密，曝藥竹牀新。", "老病應隨業，因緣不離身。", "焚香向居士，無計出諸塵。"]'),
('4e74f786-a48a-477c-a887-601347607cdb','原上新居十三首 八','王建','唐','唐诗','tang','','[]','移家近住邨，貧苦自安存。',48,'全唐诗/poet.tang.16000.json','["移家近住邨，貧苦自安存。", "細問梨果植，遠求花藥根。", "倩人開廢井，趂犢入新園。", "長愛當山立，黃昏不閉門。"]'),
('4b5ed30e-8934-448f-855c-22420981dc3c','原上新居十三首 九','王建','唐','唐诗','tang','','[]','和煖遶林行，新貧足喜聲。',48,'全唐诗/poet.tang.16000.json','["和煖遶林行，新貧足喜聲。", "埽渠憂竹旱，澆地引蘭生。", "山客憑栽樹，家僮使入城。", "門前粉壁上，書著縣官名。"]'),
('dfc4e7eb-372c-4b4e-86e1-c578c85bf9ae','原上新居十三首 十','王建','唐','唐诗','tang','','[]','住處鐘鼓外，免爭當路橋。',48,'全唐诗/poet.tang.16000.json','["住處鐘鼓外，免爭當路橋。", "身閑時却困，兒病可來嬌。", "雞睡日陽暖，蜂狂花豔燒。", "長安足門戶，疊疊看登朝。"]'),
('f6dff067-8bb1-488f-a875-388a885e1a1e','原上新居十三首 十一','王建','唐','唐诗','tang','','[]','近來年紀到，世事總無心。',48,'全唐诗/poet.tang.16000.json','["近來年紀到，世事總無心。", "古碣憑人搨，閑詩任客吟。", "送經還野苑，移石入幽林。", "谷口春風惡，梨花蓋地深。"]'),
('a8661bc2-6231-467f-a0ea-00e9cc151d28','原上新居十三首 十二','王建','唐','唐诗','tang','','[]','嬾更學諸餘，林中埽地居。',48,'全唐诗/poet.tang.16000.json','["嬾更學諸餘，林中埽地居。", "膩衣穿不洗，白髮短慵梳。", "苦相常多淚，勞生自悟虛。", "閑行人事絕，親故亦無書。"]'),
('5569d79a-ee47-493e-9582-558649e6d148','原上新居十三首 十三','王建','唐','唐诗','tang','','[]','住處去山近，傍園麋鹿行。',48,'全唐诗/poet.tang.16000.json','["住處去山近，傍園麋鹿行。", "野桑穿井長，荒竹過牆生。", "新識鄰里面，未諳邨社情。", "石田無力及，賤賃與人耕。"]'),
('1c508294-ca48-4936-a8c2-770107340b73','送李評事使蜀','王建','唐','唐诗','tang','','[]','勸酒不依巡，明朝萬里人。',48,'全唐诗/poet.tang.16000.json','["勸酒不依巡，明朝萬里人。", "轉江雲棧細，近驛板橋新。", "石冷啼猿影，松昏戲鹿塵。", "少年爲客好，況是益州春。"]'),
('0ed188d5-5225-4dc9-a6c4-a0f563debecd','新修道居','王建','唐','唐诗','tang','','[]','世間無所入，學道處新成。',48,'全唐诗/poet.tang.16000.json','["世間無所入，學道處新成。", "兩面有山色，六時聞磬聲。", "閑加經遍數，老愛字分明。", "若得離煩惱，焚香過一生。"]'),
('68e6b2b5-5a33-40a2-8396-b5b339e5ffdf','贈洪誓師','王建','唐','唐诗','tang','','[]','老僧真古畫，閑坐語中聽。',48,'全唐诗/poet.tang.16000.json','["老僧真古畫，閑坐語中聽。", "識病方書聖，諳山草木靈。", "人來多施藥，願滿不持經。", "相伴尋溪竹，秋苔襪履青。"]'),
('d8d6a9a4-7c86-48b3-82d4-1a77459910a4','題法雲禪院僧','王建','唐','唐诗','tang','','[]','不剃頭多日，禪來白髮長。',48,'全唐诗/poet.tang.16000.json','["不剃頭多日，禪來白髮長。", "合邨迎住寺，同學乞修房。", "覺少持經力，憂無養病糧。", "上山猶得在，自解衲衣裳。"]'),
('32bc0af6-a95d-426f-b82e-515b24a19b32','贈溪翁','王建','唐','唐诗','tang','','[]','溪田借四鄰，不省解憂身。',48,'全唐诗/poet.tang.16000.json','["溪田借四鄰，不省解憂身。", "看日和仙藥，書符救病人。", "伴僧齋過夏，中酒臥經旬。", "應得丹砂力，春來黑髮新。"]'),
('7da6446b-3c9d-4633-9fa5-77f28f08b288','謝李續主簿','王建','唐','唐诗','tang','','[]','館舍幸相近，因風及病身。',48,'全唐诗/poet.tang.16000.json','["館舍幸相近，因風及病身。", "一官雖隔水，四韵是同人。", "衰臥朦朧曉，貧居冷落春。", "少年無不好，莫恨滿頭塵。"]'),
('4f8a7344-8981-46af-acdf-48ce14c9ce5e','寒食','王建','唐','唐诗','tang','','["\u5bd2\u98df\u8282"]','田舍清明日，家家出火遲。',48,'全唐诗/poet.tang.16000.json','["田舍清明日，家家出火遲。", "白衫眠古巷，紅索搭高枝。", "紗帶生難結，銅釵重欲垂。", "斬新衣踏盡，還似去年時。"]'),
('2886c09d-4cb4-43cd-a608-20d0c55892d8','貽小尼師','王建','唐','唐诗','tang','','[]','新剃青頭髮，生來未埽眉。',48,'全唐诗/poet.tang.16000.json','["新剃青頭髮，生來未埽眉。", "身輕禮拜穩，心慢記經遲。", "喚起猶侵曉，催齋已過時。", "春晴堦下立，私地弄花枝。"]'),
('5c0a4993-92cd-441c-9de5-b501acd4101c','惜歡','王建','唐','唐诗','tang','','[]','當歡須且歡，過後買應難。',48,'全唐诗/poet.tang.16000.json','["當歡須且歡，過後買應難。", "歲去停燈守，花開把火看。", "狂來欺酒淺，愁盡覺天寬。", "次第頭皆白，齊年人已殘。"]'),
('037361bc-7010-45e5-8818-d5cf63da147c','山中惜花','王建','唐','唐诗','tang','','[]','忽看花漸稀，罪過酒醒時。',48,'全唐诗/poet.tang.16000.json','["忽看花漸稀，罪過酒醒時。", "尋覓風來處，驚張夜落時。", "遊絲纏故蘂，宿夜守空枝。", "開取當軒地，年年樹底期。"]'),
('f41e61ce-7618-475f-96e1-9b9491696f4a','和武門下傷韋令孔雀','王建','唐','唐诗','tang','','[]','孤號秋閣陰，韋令在時禽。',48,'全唐诗/poet.tang.16000.json','["孤號秋閣陰，韋令在時禽。", "覓伴海山黑，思鄉橘柚深。", "舉頭聞舊曲，顧尾惜殘金。", "顦顇不飛去，重君池上心。"]'),
('5fd29e82-2daa-46ea-accd-ffaeb0642e75','題所賃宅牡丹花','王建','唐','唐诗','tang','','["\u5199\u82b1", "\u7261\u4e39", "\u7737\u604b", "\u82b1", "\u8d5e\u7f8e"]','賃宅得花饒，初開恐是妖。',48,'全唐诗/poet.tang.16000.json','["賃宅得花饒，初開恐是妖。", "粉光深紫膩，肉色退紅嬌。", "且願風留著，惟愁日炙燋。", "可憐零落蘂，收取作香燒。"]'),
('e7fb06b2-a9ea-4271-a01d-cab3ca65376b','隱者居','王建','唐','唐诗','tang','','[]','山人住處高。',48,'全唐诗/poet.tang.16000.json','["山人住處高。", "看日上蟠桃，雪縷青山脈。", "雲生白鶴毛，朱書護身咒。", "水噀斷邪刀，何物中長食。", "胡麻慢火熬。"]'),
('0afd3bc9-7bed-4bad-ad80-20e5d730ffaa','昭應官舍','王建','唐','唐诗','tang','','[]','繞廳春草合，知道縣家閑。',48,'全唐诗/poet.tang.16000.json','["繞廳春草合，知道縣家閑。", "行見雨遮院，臥看人上山。", "避風新浴後，請假未醒間。", "朝客輕卑吏，從他不往還。"]'),
('0c4b92a4-cee6-42ee-8135-c9f00960cd76','送嚴大夫赴桂州','王建','唐','唐诗','tang','','[]','嶺頭分界候，一半屬湘潭。',48,'全唐诗/poet.tang.16000.json','["嶺頭分界候，一半屬湘潭。", "水驛門旗出，山巒洞主參。", "辟邪犀角重，解酒荔枝甘。", "莫歎京華遠，安南更有南。"]'),
('ea646ac3-707d-4278-ae94-151dbfec3d65','望行人','王建','唐','唐诗','tang','','[]','自從江樹秋，日日望江樓。',48,'全唐诗/poet.tang.16000.json','["自從江樹秋，日日望江樓。", "夢見離珠浦，書來在桂州。", "不同魚比目，終恨水分流。", "久不開明鏡，多應是白頭。"]'),
('6eedd100-e0e3-4dd3-9d6c-dfa2ef4090aa','塞上','王建','唐','唐诗','tang','','[]','漫漫復淒淒，黃沙暮漸迷。',48,'全唐诗/poet.tang.16000.json','["漫漫復淒淒，黃沙暮漸迷。", "人當故鄉立，馬過舊營嘶。", "斷雁逢冰磧，回軍占雪溪。", "夜來山下哭，應是送降奚。"]'),
('60b400e0-ad92-455c-bd50-e6c2f1cfaf88','杜中丞書院新移小竹','王建','唐','唐诗','tang','','[]','此地本無竹，遠從山寺移。',72,'全唐诗/poet.tang.16000.json','["此地本無竹，遠從山寺移。", "經年求養法，隔日記澆時。", "嫩綠卷新葉，殘黃收故枝。", "色輕寒不動，聲與靜相宜。", "愛護出常數，稀稠看自知。", "貧來緣未有，客散獨行遲。"]'),
('45b8f479-c19c-42d9-ab71-4bc9d67136a7','同于汝錫賞白牡丹','王建','唐','唐诗','tang','','[]','曉日花初吐，春寒白未凝。',96,'全唐诗/poet.tang.16000.json','["曉日花初吐，春寒白未凝。", "月光裁不得，蘇合點難勝。", "柔膩於雲葉，新鮮掩鶴膺。", "統心黃倒暈，側莖紫重稜。", "乍斂看如睡，初開問欲譍。", "竝香幽蕙死，比豔美人憎。", "價數千金貴，形相兩眼疼。", "自知顏色好，愁被彩光凌。"]'),
('07767a89-9e4b-4fd7-a149-d87ece400a3e','送吳郎中赴忠州','王建','唐','唐诗','tang','','[]','西臺復南省，清白上天知。',72,'全唐诗/poet.tang.16000.json','["西臺復南省，清白上天知。", "家每因窮散，官多爲直移。", "遙邊過驛近，買藥出城遲。", "朝野憑人別，親情伴酒悲。", "故園愁去後，白髮想迴時。", "何處忠州界，山頭卓望旗。"]'),
('0bd7eeb9-42b1-4c44-8ac5-93cce080ddc4','照鏡','王建','唐','唐诗','tang','','[]','終日自纏繞，此身無適緣。',72,'全唐诗/poet.tang.16000.json','["終日自纏繞，此身無適緣。", "萬愁生旅夜，百病湊衰年。", "少睡憎明屋，慵行待暖天。", "癢頭梳有蝨，風耳炙聞蟬。", "搖白方多錯，迴金法不全。", "家貧何所戀，時在老僧邊。"]'),
('c9dba129-cabd-4083-9fe5-d3ace11ed2d4','秋日送杜虔州','王建','唐','唐诗','tang','','[]','憶得宿新宅，別來餘蕙香。',72,'全唐诗/poet.tang.16000.json','["憶得宿新宅，別來餘蕙香。", "初聞守郡遠，一日臥空牀。", "野驛煙火濕，路人消息狂。", "山樓添鼓角，村柵立旗槍。", "晚渚露荷敗，早衙風桂涼。", "謝家章句出，江月少輝光。"]'),
('7dfd67f3-45f7-404f-a5b2-f25e123508ea','送鄭權尚書南海','王建','唐','唐诗','tang','','[]','七郡雙旌貴，人皆不憶廻。',72,'全唐诗/poet.tang.16000.json','["七郡雙旌貴，人皆不憶廻。", "戍頭龍腦鋪，關口象牙堆。", "勅設熏鑪出，蠻辭咒節開。", "市喧山賊破，金賤海船來。", "白氎家家織，紅蕉處處栽。", "已將身報國，莫起望鄉臺。"]'),
('ebf0dea4-9e91-44d1-aefc-af34b36b8277','題別遺愛草堂兼呈李十使君','王建','唐','唐诗','tang','','[]','曾住鑪峰下，書堂對藥臺。',72,'全唐诗/poet.tang.16000.json','["曾住鑪峰下，書堂對藥臺。", "斬新蘿徑合，依舊竹牕開。", "砌水親看決，池荷手自栽。", "五年方蹔至，一宿又須回。", "縱未長歸得，猶勝不到來。", "君家白鹿洞，聞道亦生苔。"]'),
('9e7315fd-cae3-4fa8-84d1-bcc1e8dc300a','賞牡丹','王建','唐','唐诗','tang','','["\u548f\u7269", "\u60dc\u82b1", "\u548f\u7269\u8bd7", "\u7261\u4e39", "\u82b1", "\u5199\u82b1"]','此花名價別，開豔益皇都。',96,'全唐诗/poet.tang.16000.json','["此花名價別，開豔益皇都。", "香遍苓菱死，紅燒躑躅枯。", "軟光籠細脈，妖色暖鮮膚。", "滿蘂攢黃粉，含稜縷絳蘇。", "好和薰御服，堪畫入宮圖。", "晚態愁新婦，殘粧望病夫。", "教人知箇數，留客賞斯須。", "一夜輕風起，千金買亦無。"]'),
('fb4a72fa-c1f2-4ce1-936b-ae3c6c947faf','贈王樞密','王建','唐','唐诗','tang','','[]','三朝行坐鎮相隨，今上春宮見小時。',64,'全唐诗/poet.tang.16000.json','["三朝行坐鎮相隨，今上春宮見小時。", "脫下御衣先賜著，進來龍馬每教騎。", "長承密旨歸家少，獨奏邊機出殿遲。", "自是姓同親向說，九重爭得外人知。"]'),
('819e5bd5-ce98-460f-8c8a-508dd91722a7','早秋過龍武李將軍書齋','王建','唐','唐诗','tang','','[]','高樹蟬聲秋巷裏，朱門冷靜似閑居。',64,'全唐诗/poet.tang.16000.json','["高樹蟬聲秋巷裏，朱門冷靜似閑居。", "重裝墨畫數莖竹，長著香薰一架書。", "語笑侍兒知禮數，吟哦野客任狂疎。", "就中愛讀英雄傳，欲立功勳恐不如。"]'),
('ab9525f6-c284-4172-82b9-636057029200','江陵即事','王建','唐','唐诗','tang','','[]','瘴雲梅雨不成泥，十里津樓壓大堤。',64,'全唐诗/poet.tang.16000.json','["瘴雲梅雨不成泥，十里津樓壓大堤。", "蜀女下沙迎水客，巴童傍驛賣山雞。", "寺多紅藥燒人眼，地足青苔染馬蹄。", "夜半獨眠愁在遠，北看歸路隔蠻溪。"]'),
('e0824f0c-e549-40e8-b9a5-5f3b4ca18bc7','題花子贈渭州陳判官','王建','唐','唐诗','tang','','[]','膩如雲母輕如粉，豔勝香黃薄勝蟬。',64,'全唐诗/poet.tang.16000.json','["膩如雲母輕如粉，豔勝香黃薄勝蟬。", "點綠斜蒿新葉嫩，添紅石竹晚花鮮。", "鴛鴦比翼人初帖，蛺蝶重飛樣未傳。", "況復蕭郎有情思，可憐春日鏡臺前。"]'),
('b546d9e2-8528-4aef-9b4c-3ccedfe647d1','送從姪擬赴江陵少尹','王建','唐','唐诗','tang','','[]','江陵少尹好閑官，親故皆來勸自寬。',64,'全唐诗/poet.tang.16000.json','["江陵少尹好閑官，親故皆來勸自寬。", "無事日長貧不易，有才年少屈終難。", "沙頭欲買紅螺盞，渡口多呈白角盤。", "應向章華臺下醉，莫衝雲雨夜深寒。"]'),
('e1c0571b-40e4-43a1-9561-53f27eb82192','華清宮感舊','王建','唐','唐诗','tang','','[]','塵到朝元邊使急，千官夜發六龍回。',64,'全唐诗/poet.tang.16000.json','["塵到朝元邊使急，千官夜發六龍回。", "輦前月照羅衫淚，馬上風吹蠟燭灰。", "公主妝樓金鎖澀，貴妃湯殿玉蓮開。", "有時雲外聞天樂，知是先皇沐浴來。"]'),
('d7d98471-ce0f-453e-bf72-f0bb99823825','九仙公主舊莊','王建','唐','唐诗','tang','','[]','仙居五里外門西，石路親回御馬蹄。',64,'全唐诗/poet.tang.16000.json','["仙居五里外門西，石路親回御馬蹄。", "天使來栽宮裏樹，羅衣自買院前溪。", "野牛行傍澆花井，本主分將灌藥畦。", "樓上鳳皇飛去後，白雲紅葉屬山雞。"]'),
('2fd3d8c0-1ed1-4f37-8580-5d4b67100e91','郭家溪亭','王建','唐','唐诗','tang','','[]','高亭望見長安樹，春草岡西舊院斜。',64,'全唐诗/poet.tang.16000.json','["高亭望見長安樹，春草岡西舊院斜。", "光動綠煙遮岸行，粉開紅豔塞溪花。", "野泉聞洗親王馬，古柳曾停貴主車。", "妝閣書樓傾側盡，雲山新賣與官家。"]'),
('7545545f-e9d3-4382-a987-89262e9fd3ae','題金家竹溪','王建','唐','唐诗','tang','','[]','少年因病離天仗，乞得歸家自養身。',64,'全唐诗/poet.tang.16000.json','["少年因病離天仗，乞得歸家自養身。", "買斷竹溪無別主，散分泉水與新鄰。", "山頭鹿下長驚犬，池面魚行不怕人。", "鄉使到來常欵語，還聞世上有功臣。"]'),
('a00e1a8d-1d74-436a-8331-8624fd11038a','題應聖觀','王建','唐','唐诗','tang','','[]','精思堂上畫三身，回作仙宮度美人。',64,'全唐诗/poet.tang.16000.json','["精思堂上畫三身，回作仙宮度美人。", "賜額御書金字貴，行香天樂羽衣新。", "空廊鳥啄花甎縫，小殿蟲緣玉像塵。", "頭白女冠猶說得，薔薇不似已前春。"]'),
('c05d134f-f7c0-487e-972d-94bbe2618421','同于汝錫遊降聖觀','王建','唐','唐诗','tang','','[]','秦時桃樹滿山坡，騎鹿先生降大羅。',64,'全唐诗/poet.tang.16000.json','["秦時桃樹滿山坡，騎鹿先生降大羅。", "路盡溪頭逢地少，門連內裏見天多。", "荒泉壞簡朱砂暗，古塔殘經篆字訛。", "聞說開元齋醮日，曉移行漏帝親過。"]'),
('72cf81fc-6d8c-41e2-b6f8-f7496dfdfbe7','逍遙翁溪亭','王建','唐','唐诗','tang','','[]','逍遙翁在此裴回，帝改溪名起石臺。',64,'全唐诗/poet.tang.16000.json','["逍遙翁在此裴回，帝改溪名起石臺。", "車馬到春常借問，子孫因選暫歸來。", "稀疎野竹人移折，零落蕉花雨打開。", "無主青山何所直，賣供官稅不如灰。"]'),
('f4240c8a-839e-4e98-b130-f652b553649a','尋李山人不遇','王建','唐','唐诗','tang','','[]','山客長須少在時，溪中放鶴洞中碁。',64,'全唐诗/poet.tang.16000.json','["山客長須少在時，溪中放鶴洞中碁。", "生金有氣尋還遠，仙藥成窠見即移。", "莫爲無家陪寺食，應緣將米寄人炊。", "從頭石上留名去，獨向南峰問老師。"]'),
('f9dec966-d9d8-4189-8c9e-4003a3b74981','題石甕寺','王建','唐','唐诗','tang','','[]','青崖白石夾城東，泉脈鐘聲內裏通。',64,'全唐诗/poet.tang.16000.json','["青崖白石夾城東，泉脈鐘聲內裏通。", "地壓龍蛇山色別，屋連宮殿匠名同。", "簷燈經夏紗籠黑，溪葉先秋臘樹紅。", "天子親題詩總在，畫扉長鏁碧龕中。"]'),
('b945c419-d274-4b24-b2f4-6098bd7413dd','早登西禪寺閣','王建','唐','唐诗','tang','','[]','上方臺殿第三層，朝壁紅窗日氣凝。',64,'全唐诗/poet.tang.16000.json','["上方臺殿第三層，朝壁紅窗日氣凝。", "煙霧開時分遠寺，山川晴處見崇陵。", "沙灣漾水圖新粉，綠野荒阡暈色繒。", "莫說城南月燈閣，自諸樓看總難勝。"]'),
('fe949c81-1d23-4cb2-b163-be7405a84d91','題江寺兼求藥子','王建','唐','唐诗','tang','','[]','隋朝舊寺楚江頭，深謝師僧引客遊。',64,'全唐诗/poet.tang.16000.json','["隋朝舊寺楚江頭，深謝師僧引客遊。", "空賞野花無過夜，若看琪樹即須秋。", "紅珠落地求誰與，青角垂階自不收。", "願乞野人三兩粒，歸家將助小庭幽。"]'),
('5b8ac5d5-09f9-4a42-9e7c-453445ad25a4','題詵法師院','王建','唐','唐诗','tang','','[]','三年說戒龍宮裏，巡禮還來向水行。',64,'全唐诗/poet.tang.16000.json','["三年說戒龍宮裏，巡禮還來向水行。", "多愛貧窮人遠請，長修破落寺先成。", "秋天盆底新荷色，夜地房前小竹聲。", "僧院不求諸處好，轉經唯有一窗明。"]'),
('f93ba4fe-2aa4-4afb-9481-dc36cfaedd57','酬于汝錫曉雪見寄','王建','唐','唐诗','tang','','[]','欲明天色白漫漫，打葉穿簾雪未乾。',64,'全唐诗/poet.tang.16000.json','["欲明天色白漫漫，打葉穿簾雪未乾。", "薄落堦前人踏盡，差池樹裏鳥銜殘。", "旋銷迎暖沾牆少，斜舞遮春到地難。", "勞動更裁新樣綺，紅燈一夜剪刀寒。"]'),
('2367a6c8-4685-4c38-98c8-bb4bafac2ab5','從軍後寄山中友人','王建','唐','唐诗','tang','','[]','愛仙無藥住溪貧，脫却山衣事漢臣。',64,'全唐诗/poet.tang.16000.json','["愛仙無藥住溪貧，脫却山衣事漢臣。", "夜半聽雞梳白髮，天明走馬入紅塵。", "村童近去嫌腥食，野鶴高飛避俗人。", "勞動先生遠相示，別來弓箭不離身。"]'),
('2a2699ac-c6ea-4674-b778-637a98cd6152','寄汴州令狐相公','王建','唐','唐诗','tang','','[]','三軍江口擁雙旌，虎帳長開自教兵。',64,'全唐诗/poet.tang.16000.json','["三軍江口擁雙旌，虎帳長開自教兵。", "機鏁惡徒狂寇盡，恩驅老將壯心生。", "水門向晚茶商鬧，橋市通宵酒客行。", "秋日梁王池閣好，新歌散入管絃聲。"]'),
('b3591dc7-e041-4163-9dfc-dd9dcd3ec49f','別李贊侍御','王建','唐','唐诗','tang','','[]','同受艱難驃騎營，半年中聽揭槍聲。',64,'全唐诗/poet.tang.16000.json','["同受艱難驃騎營，半年中聽揭槍聲。", "草頭送酒驅村樂，賊裏看花著探兵。", "講易工夫尋已聖，說詩門戶別來情。", "薦書自入無消息，賣盡寒衣却出城。"]'),
('ee87f4d0-417a-4108-9d5a-f61c24d0b36d','和蔣學士新授章服','王建','唐','唐诗','tang','','[]','五色箱中絳服春，笏花成就白魚新。',64,'全唐诗/poet.tang.16000.json','["五色箱中絳服春，笏花成就白魚新。", "看宣賜處驚回眼，著謝恩時便稱身。", "瑞草唯承天上露，紅鸞不受世間塵。", "翰林同賀文章出，驚動茫茫下界人。"]'),
('ead7332c-f399-449c-889e-f3813b14423a','歲晚自感','王建','唐','唐诗','tang','','[]','人皆欲得長年少，無那排門白髮催。',64,'全唐诗/poet.tang.16000.json','["人皆欲得長年少，無那排門白髮催。", "一向破除愁不盡，百方回避老須來。", "草堂未辦終須置，松樹難成亦且栽。", "瀝酒願從今日後，更逢二十度花開。"]'),
('0d8b6873-1bd9-434a-9c2f-0cd0c0f3e6ac','昭應官舍','王建','唐','唐诗','tang','','[]','癡頑終日羨人閑，却喜因官得近山。',64,'全唐诗/poet.tang.16000.json','["癡頑終日羨人閑，却喜因官得近山。", "斜對寺樓分寂寂，遠從溪路借潺潺。", "眇身多病唯親藥，空院無錢不要關。", "文案把來看未會，雖書一字甚慙顏。"]'),
('45e00d2a-c1fc-44ca-a10f-8bbf23f15341','寄舊山僧','王建','唐','唐诗','tang','','["\u5c71", "\u751f\u6d3b"]','因依老宿發心初，半學修心半讀書。',64,'全唐诗/poet.tang.16000.json','["因依老宿發心初，半學修心半讀書。", "雪後每常同席臥，花時未省兩山居。", "獵人箭底求傷雁，釣戶竿頭乞活魚。", "一向風塵取煩惱，不知衰病日難除。"]'),
('990fcce5-9eed-4401-b5b4-e72eb0b05d5f','武陵春日','王建','唐','唐诗','tang','','[]','尋春何事却悲涼，春到他鄉憶故鄉。',64,'全唐诗/poet.tang.16000.json','["尋春何事却悲涼，春到他鄉憶故鄉。", "秦女洞桃欹澗碧，楚王堤柳舞煙黃。", "波濤入夢家山遠，名利關身客路長。", "不似冥心叩塵寂，玉編金軸有仙方。"]'),
('e782fa05-af72-4dc1-a505-2bad2d9f324b','寄分司張郎中','王建','唐','唐诗','tang','','[]','一別京華年歲久，卷中多見嶺南詩。',64,'全唐诗/poet.tang.16000.json','["一別京華年歲久，卷中多見嶺南詩。", "聲名已壓衆人上，愁思未平雙鬢知。", "江郡遷移猶遠地，仙官榮龐是分司。", "青天白日當頭上，會有求閑不得時。"]'),
('aed11808-e156-4106-8758-d2cf0293d999','上武元衡相公','王建','唐','唐诗','tang','','[]','旌旗坐鎮蜀江雄，帝命重開舊閤崇。',64,'全唐诗/poet.tang.16000.json','["旌旗坐鎮蜀江雄，帝命重開舊閤崇。", "襃貶唐書天曆上，捧持堯日慶雲中。", "孤情逈出鸞皇遠，健思潛搜海嶽空。", "長得蕭何爲國相，自西流水盡朝宗。"]'),
('b69e6a11-7091-4bfa-9fe3-5d5058996fc4','上張弘靖相公','王建','唐','唐诗','tang','','[]','傳封三世盡河東，家占中條第一峰。',64,'全唐诗/poet.tang.16000.json','["傳封三世盡河東，家占中條第一峰。", "旱歲天教作霖雨，明時帝用補山龍。", "草開舊路沙痕在，日照新池鳳跡重。", "卑散自知霄漢隔，若爲門下賜從容。"]'),
('22f55472-b760-42db-b097-663f3c7e1833','上裴度舍人','王建','唐','唐诗','tang','','[]','小松雙對鳳池開，履跡衣香逼上台。',64,'全唐诗/poet.tang.16000.json','["小松雙對鳳池開，履跡衣香逼上台。", "天意皆從彩毫出，宸心盡向紫煙來。", "非時玉案呈宣旨，每日金堦謝賜回。", "仙侶何因記名姓，縣丞頭白走塵埃。"]'),
('ad2b9baa-2749-4d57-8b3c-31090d1da8f6','上杜元穎相公','王建','唐','唐诗','tang','','[]','學士金鑾殿後居，天中行坐侍龍輿。',64,'全唐诗/poet.tang.16000.json','["學士金鑾殿後居，天中行坐侍龍輿。", "承恩不許離牀謝，密詔常教倚案書。", "馬上喚遮紅觜鴨，船頭看釣赤鱗魚。", "閑曹散吏無相識，猶記荆州拜謁初。"]'),
('4feeb63c-0bcd-4c01-abcd-b83d88e00b8c','贈盧汀諫議','王建','唐','唐诗','tang','','[]','青蛾不得在牀前，空室焚香獨自眠。',64,'全唐诗/poet.tang.16000.json','["青蛾不得在牀前，空室焚香獨自眠。", "功證詩篇離景象，藥成官位屬神仙。", "閑過寺觀長衝夜，立送封章直上天。", "近見蘭臺諸吏說，御詩新集未教傳。"]'),
('82b591b7-15eb-4bc8-aa66-1052cd87b22a','賀楊巨源博士拜虞部員外','王建','唐','唐诗','tang','','[]','合歸蘭署已多時，上得金梯亦未遲。',64,'全唐诗/poet.tang.16000.json','["合歸蘭署已多時，上得金梯亦未遲。", "兩省郎官開道路，九州山澤屬曹司。", "諸生拜別收書卷，舊客看來讀制詞。", "殘著幾丸仙藥在，分張還遣病夫知。"]'),
('c442e8aa-bce5-4547-a996-eef296a0b427','贈郭將軍','王建','唐','唐诗','tang','','[]','承恩新拜上將軍，當直巡更近五雲。',64,'全唐诗/poet.tang.16000.json','["承恩新拜上將軍，當直巡更近五雲。", "天下表章經院過，宮中語笑隔牆聞。", "密封計策非時奏，別賜衣裳到處薰。", "向晚臨堦看號簿，眼前風景任支分。"]'),
('e384c76b-0d89-437d-adc0-1b176fa74c24','贈田將軍','王建','唐','唐诗','tang','','[]','初從學院別先生，便領偏師得戰名。',64,'全唐诗/poet.tang.16000.json','["初從學院別先生，便領偏師得戰名。", "大小獨當三百陣，縱橫祗用五千兵。", "回殘匹帛歸天庫，分好旌旗入禁營。", "自執金吾長上直，蓬萊宮裏夜巡更。"]'),
('b122f204-a414-43f7-ad88-14de3eb1b44a','贈胡泟將軍','王建','唐','唐诗','tang','','[]','書生難得是金吾，近日登科記總無。',64,'全唐诗/poet.tang.16000.json','["書生難得是金吾，近日登科記總無。", "半夜進儺當玉殿，未明排仗到銅壺。", "朱牌面上分官契，黃紙頭邊押勅符。", "恐要蕃中新道路，指揮重畫五城圖。"]'),
('6a67eb88-3d0d-4513-9852-5b191649c806','留別田尚書','王建','唐','唐诗','tang','','[]','擬報平生未殺身，難離門館起居頻。',64,'全唐诗/poet.tang.16000.json','["擬報平生未殺身，難離門館起居頻。", "不看匣裏釵頭古，猶戀機中錦樣新。", "一旦甘爲漳岸老，全家却作杜陵人。", "朝天路在驪山下，專望紅旗拜舊塵。"]'),
('27973e2a-78d5-4b23-9cbc-b7aefa810514','送唐大夫罷節歸山','王建','唐','唐诗','tang','','[]','年少平戎老學仙，表求骸骨乞生全。',64,'全唐诗/poet.tang.16000.json','["年少平戎老學仙，表求骸骨乞生全。", "不堪腰下懸金印，已向雲西寄玉田。", "旄節抱歸官路上，公卿送到國門前。", "人間雞犬同時去，遙聽笙歌隔水煙。"]'),
('af79842b-d31a-453d-bc9a-a3e2c124ba1a','送司空神童','王建','唐','唐诗','tang','','[]','杏花壇上授書時，不廢中庭趂蝶飛。',64,'全唐诗/poet.tang.16000.json','["杏花壇上授書時，不廢中庭趂蝶飛。", "暗寫五經收部秩，初年七歲著衫衣。", "秋堂白髮先生別，古巷青襟舊伴歸。", "獨向鳳城持薦表，萬人叢裏有光輝。"]'),
('593b85ac-836c-4dc5-9df9-80896aed57b1','送振武張尚書','王建','唐','唐诗','tang','','[]','回天轉地是將軍，扶助春宮上五雲。',64,'全唐诗/poet.tang.16000.json','["回天轉地是將軍，扶助春宮上五雲。", "撫背恩雖同骨肉，擁旄名未敵功勳。", "盡收壯勇填兵數，不向蕃渾奪馬羣。", "閑即單于臺下獵，威聲直到海西聞。"]'),
('f7550390-cba4-483d-bf2b-c004ba1a63c5','送吳諫議上饒州','王建','唐','唐诗','tang','','[]','鄱陽太守是真人，琴在牀頭籙在身。',64,'全唐诗/poet.tang.16000.json','["鄱陽太守是真人，琴在牀頭籙在身。", "曾向先皇邊諫事，還應上帝處稱臣。", "養生自有年支藥，稅戶應停月進銀。", "淨掃水堂無侍女，下街唯共鶴殷勤。"]'),
('04435e69-cfbe-4e0c-9907-e35330d414c6','贈閻少保','王建','唐','唐诗','tang','','[]','髭鬚雖白體輕健，九十三來却少年。',64,'全唐诗/poet.tang.16000.json','["髭鬚雖白體輕健，九十三來却少年。", "問事愛知天寶裏，識人皆是武皇前。", "玉裝劒珮身長帶，絹寫方書子不傳。", "侍女常時教合藥，亦聞私地學求仙。"]'),
('d5111a8b-8b91-486a-b966-db944fd58d56','送魏州李相公','王建','唐','唐诗','tang','','[]','百代功勳一日成，三年五度換雙旌。',64,'全唐诗/poet.tang.16000.json','["百代功勳一日成，三年五度換雙旌。", "閑來不對人論戰，難處長先自請行。", "旗下可聞誅敗將，陣頭多是用降兵。", "當朝面受新恩去，算料妖星不敢生。"]'),
('42668b3c-bf4c-495d-80c2-92cf24df6196','贈索暹將軍','王建','唐','唐诗','tang','','[]','渾身著箭瘢猶在，萬槊千刀總過來。',64,'全唐诗/poet.tang.16000.json','["渾身著箭瘢猶在，萬槊千刀總過來。", "輪劒直衝生馬隊，抽旗旋踏死人堆。", "聞休鬬戰心還癢，見說煙塵眼即開。", "泪滴先皇堦下土，南衙班裏趁朝回。"]'),
('63bccd5f-9e37-4f51-bc36-f0a48fa62203','贈王屋道士赴詔','王建','唐','唐诗','tang','','[]','玉皇符詔下天壇，玳瑁頭簪白角冠。',64,'全唐诗/poet.tang.16000.json','["玉皇符詔下天壇，玳瑁頭簪白角冠。", "鶴遣院中童子養，鹿憑山下老人看。", "法成不怕刀槍利，體實常欺石榻寒。", "能斷世間腥血昧，長生只要一丸丹。"]'),
('6d8dd62f-12f1-4d0f-9ebc-88645fe3a2e5','贈王處士','王建','唐','唐诗','tang','','[]','松樹當軒雪滿地，青山掩障碧紗幮。',64,'全唐诗/poet.tang.16000.json','["松樹當軒雪滿地，青山掩障碧紗幮。", "鼠來案上常偷水，鶴在牀前亦看碁。", "道士寫將行氣法，家童授與步虛詞。", "世間有似君應少，便乞從今作我師。"]'),
('f0891e43-57ed-4936-9681-06025f00aa9e','洛中張籍新居','王建','唐','唐诗','tang','','[]','最是城中閑靜處，更回門向寺前開。',64,'全唐诗/poet.tang.16000.json','["最是城中閑靜處，更回門向寺前開。", "雲山且喜重重見，親故應須得得來。", "借倩學生排藥合，留連處士乞松栽。", "自君移到無多日，牆上人名滿綠苔。"]'),
('e28175d3-b929-4a82-832b-4d2443c4c0c5','題裴處士碧虛溪居','王建','唐','唐诗','tang','','[]','鳥聲真似深山裏，平地人間自不同。',64,'全唐诗/poet.tang.16000.json','["鳥聲真似深山裏，平地人間自不同。", "春圃紫芹長卓卓，暖泉青草一叢叢。", "松臺前後花皆別，竹崦高低水盡通。", "細問來時從近遠，溪名載入縣圖中。"]'),
('6c0a586a-0e00-4330-988a-512a42903ffc','送阿史那將軍安西迎舊使靈櫬','王建','唐','唐诗','tang','','[]','漢家都護邊頭沒，舊將麻衣萬里迎。',64,'全唐诗/poet.tang.16000.json','["漢家都護邊頭沒，舊將麻衣萬里迎。", "陰地背行山下火，風天錯到磧西城。", "單于送葬還垂淚，部曲招魂亦道名。", "却入杜陵秋巷裏，路人來去讀銘旌。"]'),
('34fe5b48-7725-4c09-9b11-f27111088ec1','贈崔禮駙馬','王建','唐','唐诗','tang','','[]','鳳皇樓閣連宮樹，天子崔郎自愛貧。',64,'全唐诗/poet.tang.16000.json','["鳳皇樓閣連宮樹，天子崔郎自愛貧。", "金埒減添栽藥地，玉鞭平與賣書人。", "家中弦管聽常少，分外詩篇看即新。", "一月一回陪內宴，馬蹄猶壓踏香塵。"]'),
('90db08ad-b913-4456-a6a0-eebbfea52433','贈太清盧道士','王建','唐','唐诗','tang','','[]','上清道士未昇天，南岳中華作散仙。',64,'全唐诗/poet.tang.16000.json','["上清道士未昇天，南岳中華作散仙。", "書賣八分通字學，丹燒九轉定人年。", "修行近日形如鶴，導引多時骨似綿。", "想向諸山尋禮遍，却回還守老君前。"]'),
('301333cd-30ee-48f4-ba6f-9f4b2ad0d331','送宮人入道','王建','唐','唐诗','tang','','[]','休梳叢鬢洗紅妝，頭戴芙蓉出未央。',64,'全唐诗/poet.tang.16000.json','["休梳叢鬢洗紅妝，頭戴芙蓉出未央。", "弟子抄將歌遍疊，宮人分散舞衣裳。", "問師初得經中字，入靜猶燒內裏香。", "發願蓬萊見王母，却歸人世施仙方。"]'),
('c4d80d5b-1ad1-4044-9a68-8da672d9e7e6','上李吉甫相公','王建','唐','唐诗','tang','','[]','聖朝齊賀說逢殷，霄漢無雲日月真。',64,'全唐诗/poet.tang.16000.json','["聖朝齊賀說逢殷，霄漢無雲日月真。", "金鼎調和天膳美，瑤池沐浴賜衣新。", "兩河開地山川正，四海休兵造化仁。", "曾向山東爲散吏，當今竇憲是賢臣。"]'),
('9a1d3b38-037f-4cca-8a75-c42d52b330a0','上李益庶子','王建','唐','唐诗','tang','','[]','紫煙樓閣碧紗亭，上界詩仙獨自行。',64,'全唐诗/poet.tang.16000.json','["紫煙樓閣碧紗亭，上界詩仙獨自行。", "奇險驅回還寂寞，雲山經用始鮮明。", "藕綃紋縷裁來滑，鏡水波濤濾得清。", "昏思願因秋露洗，幸容堦下禮先生。"]'),
('65ac5eb3-ccf7-4e2e-987b-846db242acda','題元郎中新宅','王建','唐','唐诗','tang','','[]','近移松樹初栽藥，經帙書籤一切新。',64,'全唐诗/poet.tang.16000.json','["近移松樹初栽藥，經帙書籤一切新。", "鋪設暖房迎道士，支分閑院著醫人。", "買來高石雖然貴，入得朱門未免貧。", "惟有好詩名字出，倍教年少損心神。"]'),
('8f8238ba-3ceb-4235-b124-28cc24cae7f0','初授太府丞言懷','王建','唐','唐诗','tang','','[]','除書亦下屬微班，喚作官曹便不閑。',64,'全唐诗/poet.tang.16000.json','["除書亦下屬微班，喚作官曹便不閑。", "檢案事多關市井，聽人言志在雲山。", "病童喚著唯行慢，老馬鞭多轉放頑。", "此去仙宮無一里，遙看松樹衆家攀。"]'),
('3eee28e0-1517-42fd-9da8-e0f39ff5a8e5','贈李愬僕射','王建','唐','唐诗','tang','','[]','唐州將士死生同，盡逐雙旌舊鎮空。',64,'全唐诗/poet.tang.16000.json','["唐州將士死生同，盡逐雙旌舊鎮空。", "獨破淮西功業大，新除隴右世家雄。", "知時每笑論兵法，識勢還輕立戰功。", "次第各分茅土貴，殊勳併在一門中。"]'),
('6dfec9a2-b67b-4eeb-846c-aa2af2bd364e','書贈舊渾二曹長','王建','唐','唐诗','tang','','[]','二年同在華清下，入縣門中最近鄰。',64,'全唐诗/poet.tang.16000.json','["二年同在華清下，入縣門中最近鄰。", "替飲觥籌知戶小，助成書屋見家貧。", "夜碁臨散停分客，朝浴先回各送人。", "僮僕使來傳語熟，至今行酒校殷勤。"]'),
('238f693f-32b2-4c3b-9da1-a2e767c88184','上崔相公','王建','唐','唐诗','tang','','[]','枯桂衰蘭一遍春，唯將道德定君臣。',64,'全唐诗/poet.tang.16000.json','["枯桂衰蘭一遍春，唯將道德定君臣。", "施行聖澤山川潤，圖畫天文彩色新。", "開閣覆看祥瑞曆，封名直進薜蘿人。", "應憐老病無知己，自別溪中滿鬢塵。"]'),
('bc52516d-0dbb-4fba-9a23-359d1270a87f','寄楊十二秘書','王建','唐','唐诗','tang','','[]','初移古寺正南方，靜是浮山遠是莊。',64,'全唐诗/poet.tang.16000.json','["初移古寺正南方，靜是浮山遠是莊。", "人定猶行背街鼓，月高還去打僧房。", "新詩欲寫中朝滿，舊卷常抄外國將。", "閑出天門醉騎馬，可憐蓬閣秘書郎。"]'),
('da167e6b-f19a-452e-bdc7-0cacb1f20878','謝田贊善見寄','王建','唐','唐诗','tang','','[]','五侯三任未相稱，頭白如絲作縣丞。',64,'全唐诗/poet.tang.16000.json','["五侯三任未相稱，頭白如絲作縣丞。", "錯判符曹羣吏笑，亂書巖石一山憎。", "自知酒病衰腸怯，遙怕春殘百鳥凌。", "年少力生猶不敵，況加顦顇悶騰騰。"]'),
('8bb6dd3e-1109-4311-a0f6-e995231d60ef','晚秋病中','王建','唐','唐诗','tang','','[]','萬事風吹過耳輪，貧兒活計亦曾聞。',64,'全唐诗/poet.tang.16000.json','["萬事風吹過耳輪，貧兒活計亦曾聞。", "偶逢新語書紅葉，難得閑人話白雲。", "霜下野花渾著地，寒來溪鳥不成羣。", "病多體痛無心力，更被頭邊藥氣熏。"]'),
('70cab30e-4882-443a-b461-2d38bcae6891','薛二十池亭','王建','唐','唐诗','tang','','[]','每箇樹邊消一日，遶池行匝又須行。',64,'全唐诗/poet.tang.16000.json','["每箇樹邊消一日，遶池行匝又須行。", "異花多是非時有，好竹皆當要處生。", "斜豎小橋看島勢，遠移山石作泉聲。", "浮萍著岸風吹歇，水面無塵晚更清。"]'),
('bbbd8442-beb3-4660-a6eb-290f87b89b77','故梁國公主池亭','王建','唐','唐诗','tang','','[]','平陽池館枕秦川，門鎖南山一朵煙。',64,'全唐诗/poet.tang.16000.json','["平陽池館枕秦川，門鎖南山一朵煙。", "素柰花開西子面，綠榆枝散沈郎錢。", "裝簷玳瑁隨風落，傍岸鵁鶄逐暖眠。", "寂寞空餘歌舞地，玉簫聲絕鳳歸天。"]'),
('14232fe1-35c8-47d1-8ba5-80b31460d564','題柱國寺','王建','唐','唐诗','tang','','[]','皇帝施錢修此院，半居天上半人間。',64,'全唐诗/poet.tang.16000.json','["皇帝施錢修此院，半居天上半人間。", "丹梯暗出三重閣，古像斜開一面山。", "松柏自穿空地少，川原不稅小僧閑。", "行香天使長相續，早起離城日午還。"]'),
('a6911799-0c0f-4ab8-b55d-7d63deced9a2','昭應官舍書事','王建','唐','唐诗','tang','','[]','縣在華清宮北面，曉看樓殿正相當。',64,'全唐诗/poet.tang.16000.json','["縣在華清宮北面，曉看樓殿正相當。", "慶雲出處依時報，御果呈來每度嘗。", "臘月近湯泉不凍，夏天臨渭屋多涼。", "兩衙早被官拘束，登閣巡溪亦屬忙。"]'),
('609665e0-d947-403a-be76-1a7a24aef344','昭應李郎中見貽佳作次韻奉酬','王建','唐','唐诗','tang','','[]','窗戶風涼四面開，陶公愛晚上高臺。',64,'全唐诗/poet.tang.16000.json','["窗戶風涼四面開，陶公愛晚上高臺。", "中庭不熱青山入，野水初晴白鳥來。", "靜思道心緣境熟，麤疎文字見詩回。", "諸生圍遶新篇讀，玉闕仙宮少此才。"]'),
('8f6ae424-9a39-46f6-9d5a-795bcb600918','閑說','王建','唐','唐诗','tang','','[]','桃花百葉不成春，鶴壽千年也未神。',64,'全唐诗/poet.tang.16000.json','["桃花百葉不成春，鶴壽千年也未神。", "秦隴州緣鸚鵡貴，王侯家爲牡丹貧。", "歌頭舞遍回回別，鬢樣眉心日日新。", "鼓動六街騎馬出，相逢總是學狂人。"]'),
('78584a46-c8dc-4c1f-bd84-50e4aae19bf9','自傷','王建','唐','唐诗','tang','','[]','衰門海內幾多人，滿眼公卿總不親。',64,'全唐诗/poet.tang.16000.json','["衰門海內幾多人，滿眼公卿總不親。", "四授官資元七品，再經婚娶尚單身。", "圖書亦爲頻移盡，兄弟還因數散貧。", "獨自在家長似客，黃昏哭向野田春。"]'),
('8c64d89c-ddec-4f0a-8e10-37566af8890c','田侍中宴席','王建','唐','唐诗','tang','','[]','香熏羅幕暖成煙，火照中庭燭滿筵。',64,'全唐诗/poet.tang.16000.json','["香熏羅幕暖成煙，火照中庭燭滿筵。", "整頓舞衣呈玉腕，動搖歌扇露金鈿。", "青蛾側座調雙管，彩鳳斜飛入五弦。", "雖是沂公門下客，爭將肉眼看雲天。"]'),
('b62970f6-6aa5-4b49-8c2d-02a67210920d','寒食日看花','王建','唐','唐诗','tang','','[]','早入公門到夜歸，不因寒食少閑時。',64,'全唐诗/poet.tang.16000.json','["早入公門到夜歸，不因寒食少閑時。", "顛狂遶樹猿離鏁，跳躑緣岡馬斷羈。", "酒汙衣裳從客笑，醉饒言語覓花知。", "老來自喜身無事，仰面西園得詠詩。"]'),
('5c7a67db-d417-49f9-823d-d8e679a35d1a','和少府崔卿微雪早朝','王建','唐','唐诗','tang','','[]','蓬萊春雪曉猶殘，點地成花遶百官。',64,'全唐诗/poet.tang.16000.json','["蓬萊春雪曉猶殘，點地成花遶百官。", "已傍祥鸞迷殿角，還穿瑞草入袍襴。", "無多白玉階前濕，積漸青松葉上乾。", "粉畫南山稜郭出，初晴一半隔雲看。"]'),
('e2bcfcd7-bff1-4079-8ed9-636909088a11','和胡將軍寓直','王建','唐','唐诗','tang','','[]','宮鴉棲定禁槍攢，樓殿深嚴月色寒。',64,'全唐诗/poet.tang.16000.json','["宮鴉棲定禁槍攢，樓殿深嚴月色寒。", "進狀直穿金戟槊，探更先傍玉鉤欄。", "漏傳五點班初合，鼓動三聲仗已端。", "遙見正南宣不坐，新栽松樹喚人看。"]'),
('d8bb235a-83c5-4925-91a8-b7fc112a2197','春日五門西望','王建','唐','唐诗','tang','','[]','百官朝下五門西，塵起春風過玉堤。',63,'全唐诗/poet.tang.16000.json','["百官朝下五門西，塵起春風過玉堤。", "黃帕蓋鞍呈了馬，紅羅繫項鬬回雞館松枝重牆頭出，御柳條長水面齊。", "唯有教坊南草綠，古苔陰地冷淒淒。"]'),
('b75e8d1e-9f33-4203-8a87-518c2bba6875','長安早春','王建','唐','唐诗','tang','','[]','霏霏漠漠遶皇州，銷雪欺寒不自由。',64,'全唐诗/poet.tang.16000.json','["霏霏漠漠遶皇州，銷雪欺寒不自由。", "先向紅妝添曉夢，爭來白髮送新愁。", "暖催衣上縫羅勝，晴報窗中點綵毬。", "每度暗來還暗去，今年須遣蝶遲留。"]'),
('dbf8c05d-acf9-4c37-990c-f32200d9e1f3','早春病中','王建','唐','唐诗','tang','','[]','日日春風階下起，不吹光彩上寒株。',64,'全唐诗/poet.tang.16000.json','["日日春風階下起，不吹光彩上寒株。", "師教絳服禳衰月，妻許青衣侍病夫。", "健羨人家多力子，祈求道士有神符。", "世間方法從誰問，臥處還看藥草圖。"]'),
('d3f10208-8797-412a-a458-a0faaccb0ea5','上陽宮','王建','唐','唐诗','tang','','[]','上陽花木不曾秋，洛水穿宮處處流。',64,'全唐诗/poet.tang.16000.json','["上陽花木不曾秋，洛水穿宮處處流。", "畫閣紅樓宮女笑，玉簫金管路人愁。", "幔城入澗橙花發，玉輦登山桂葉稠。", "曾讀列仙王母傳，九天未勝此中遊。"]'),
('c0c02818-5805-43b0-aed3-02d64601f482','李處士故居','王建','唐','唐诗','tang','','[]','露濃煙重草萋萋，樹映闌干柳拂堤。',64,'全唐诗/poet.tang.16000.json','["露濃煙重草萋萋，樹映闌干柳拂堤。", "一院落花無客醉，半窗殘月有鶯啼。", "芳筵想像情難盡，故榭荒涼路欲迷。", "風景宛然人自改，却經門外馬頻嘶。"]'),
('0ebf2c0d-1270-4493-90af-b7d429ab78eb','寄賈島','王建','唐','唐诗','tang','','[]','盡日吟詩坐忍飢，萬人中覓似君稀。',64,'全唐诗/poet.tang.16000.json','["盡日吟詩坐忍飢，萬人中覓似君稀。", "僮眠冷榻朝猶臥，驢放秋田夜不歸。", "傍暖旋收紅落葉，覺寒猶著舊生衣。", "曲江池畔時時到，爲愛鸕鷀雨後飛。"]'),
('48b4fa8e-6535-4b54-a31d-853c3cc55431','村居即事','王建','唐','唐诗','tang','','[]','休看小字大書名，向日持經眼却明。',64,'全唐诗/poet.tang.16000.json','["休看小字大書名，向日持經眼却明。", "時過無心求富貴，身閑不夢見公卿。", "因尋寺裏薰辛斷，自別城中禮數生。", "斜月照房新睡覺，西峰半夜鶴來聲。"]'),
('52e70b94-0d86-4430-b51f-c3c6e9a1796d','維揚冬末寄幕中二從事','王建','唐','唐诗','tang','','["\u601d\u4e61", "\u51ac\u5929"]','江上數株桑棗樹，自從離亂更荒涼。',64,'全唐诗/poet.tang.16000.json','["江上數株桑棗樹，自從離亂更荒涼。", "那堪旅館經殘臘，秪把空書寄故鄉。", "典盡客衣三尺雪，鍊精詩句一頭霜。", "故人多在芙蓉幕，應笑孜孜道未光。"]'),
('9dc10910-5358-4c1e-ad03-4114fb8ff480','寄杜侍御','王建','唐','唐诗','tang','','[]','何須服藥覓昇天，粉閣爲郎即是仙。',128,'全唐诗/poet.tang.16000.json','["何須服藥覓昇天，粉閣爲郎即是仙。", "買宅但幽從索價，栽松取活不爭錢。", "退朝寺裏尋荒塔，經宿城南看野泉。", "道氣清凝分曉爽，詩情冷瘦滴秋鮮。", "學通儒釋三千卷，身擁旌旗二十年。", "春巷偶過同戶飲，暖窗時與對牀眠。", "破除心力緣書癖，傷瘦花枝爲酒顛。", "今日總來歸聖代，丈人先達幸相憐。"]'),
('85b298b8-e4bf-4cd7-b335-a5ed90169354','寄上韓愈侍郎','王建','唐','唐诗','tang','','[]','重登大學領儒流，學浪詞鋒壓九州。',128,'全唐诗/poet.tang.16000.json','["重登大學領儒流，學浪詞鋒壓九州。", "不以雄名疎野賤，唯將直氣折王侯。", "詠傷松桂青山瘦，取盡珠璣碧海愁。", "敍述異篇經總別，鞭驅險句最先投。", "碑文合遣貞魂謝，史筆應令諂骨羞。", "清俸探將還酒債，黃金旋得起書樓。", "參來擬設官人禮，朝退多逢月閣遊。", "見說雲泉求住處，若無知薦一生休。"]'),
('96799361-68ba-4585-99f9-cbfa8e2ba0d2','贈華州鄭大夫','王建','唐','唐诗','tang','','[]','此官出入鳳池頭，通化門前第一州。',96,'全唐诗/poet.tang.16000.json','["此官出入鳳池頭，通化門前第一州。", "少華山雲當驛起，小敷溪水入城流。", "空閑地內人初滿，詞訟牌前草漸稠。", "報狀拆開知足雨，赦書宣過喜無囚。", "自來不說雙旌貴，恐替長教百姓愁。", "公退晚涼無一事，步行攜客上南樓。"]'),
('a453a702-ad7f-4f2a-a620-b2471955c45d','寄賀田侍中東平功成','王建','唐','唐诗','tang','','[]','使回高品滿城傳，親見沂公在陣前。',160,'全唐诗/poet.tang.16000.json','["使回高品滿城傳，親見沂公在陣前。", "百里旗幡衝即斷，兩重衣甲射皆穿。", "探知點檢兵應怯，算得新移柵未堅。", "營被數驚乘勢破，將經頻敗遂生全。", "密招殘寇防人覺，遙斬元兇恐自專。", "首讓諸軍無敢近，功歸部曲不爭先。", "開通州縣斜連海，交割山河直到燕。", "戰馬散驅還逐草，肉牛齊散却耕田。", "府中獨拜將軍貴，門下兼分宰相權。", "唐史上頭功第一，春風雙節好朝天。"]'),
('aedeb3e6-3df2-4379-afc7-0b5f8719f597','送裴相公上太原','王建','唐','唐诗','tang','','[]','還攜堂印向幷州，將相兼權是武侯。',128,'全唐诗/poet.tang.16000.json','["還攜堂印向幷州，將相兼權是武侯。", "時難獨當天下事，功成却進手中籌。", "再三陳乞罏煙裏，前後封章玉案頭。", "朱架早朝立劒戟，綠槐殘雨看張油。", "遙知塞雁從今好，直得漁陽已北愁。", "邊鋪警巡旗盡換，山城候館壁重修。", "千羣白刃兵迎節，十對紅妝妓打毬。", "聖主分明交暫去，不須高起見京樓。"]'),
('96758abb-9c2f-4af2-984f-914592486897','題栢巖禪師影堂','王建','唐','唐诗','tang','','[]','山中磚塔閉，松下影堂新。',24,'全唐诗/poet.tang.16000.json','["山中磚塔閉，松下影堂新。", "恨不生前識，今朝禮畫身。"]'),
('fa7e882c-5c5c-40d9-971b-ccdd2d1df293','送人','王建','唐','唐诗','tang','','[]','河亭收酒器，語盡各西東。',24,'全唐诗/poet.tang.16000.json','["河亭收酒器，語盡各西東。", "回首不相見，行車秋雨中。"]'),
('a360ba0f-5145-481a-9398-2b0e6955501d','春意二首 一','王建','唐','唐诗','tang','','[]','去日丁寧別，情知寒食歸。',24,'全唐诗/poet.tang.16000.json','["去日丁寧別，情知寒食歸。", "緣逢好天氣，教熨看花衣。"]'),
('4a4191e9-46f3-4d0e-941e-556c957f9bb4','春意二首 二','王建','唐','唐诗','tang','','[]','誰是杏園主，一枝臨古岐。',24,'全唐诗/poet.tang.16000.json','["誰是杏園主，一枝臨古岐。", "從傷早春意，乞取欲開枝。"]'),
('793bba92-14b6-45e6-89aa-b12c71b47348','夜聞子規','王建','唐','唐诗','tang','','[]','子規啼不歇，到曉口應穿。',24,'全唐诗/poet.tang.16000.json','["子規啼不歇，到曉口應穿。", "況是不眠夜，聲聲在耳邊。"]'),
('f22731db-7c73-4122-b5ee-998b1c153c4b','四望驛松','王建','唐','唐诗','tang','','[]','當初北澗別，直至此庭中。',24,'全唐诗/poet.tang.16000.json','["當初北澗別，直至此庭中。", "何意聞鞞耳，聽君枝上風。"]'),
('d3b063dd-11e1-4f20-92e0-e5d475c8e77a','江館','王建','唐','唐诗','tang','','[]','水面細風生，菱歌慢慢聲。',24,'全唐诗/poet.tang.16000.json','["水面細風生，菱歌慢慢聲。", "客亭臨小市，燈火夜妝明。"]'),
('8fed83da-d1ee-45de-b792-0a4e404df0fd','題江臺驛','王建','唐','唐诗','tang','','[]','水北金臺路，年年行客稀。',24,'全唐诗/poet.tang.16000.json','["水北金臺路，年年行客稀。", "近聞天子使，多取雁門歸。"]'),
('342ad256-e8c4-4d7a-b3a9-ad6accd335e8','贈謫者','王建','唐','唐诗','tang','','[]','何罪過長沙，年年北望家。',24,'全唐诗/poet.tang.16000.json','["何罪過長沙，年年北望家。", "重封嶺頭信，一樹海邊花。"]'),
('3a0b0f07-a9fb-41ed-941c-63c7aa90b6b3','戲酬盧秘書','王建','唐','唐诗','tang','','[]','芸香閣裏人，採摘御園春。',24,'全唐诗/poet.tang.16000.json','["芸香閣裏人，採摘御園春。", "取此和仙藥，猶治老病身。"]'),
('8564e4ef-9502-4ddd-952d-7879f3790fa9','小松','王建','唐','唐诗','tang','','[]','小松初數尺，未有直生枝。',24,'全唐诗/poet.tang.16000.json','["小松初數尺，未有直生枝。", "閑即傍邊立，看多長却遲。"]'),
('64fdab52-e6d2-410e-8bde-aba1429c4b56','秋夜','王建','唐','唐诗','tang','','[]','夜久葉露滴，秋蟲入戶飛。',24,'全唐诗/poet.tang.16000.json','["夜久葉露滴，秋蟲入戶飛。", "臥多骨髓冷，起覆舊綿衣。"]'),
('e4a93bc9-1d69-4dfa-8525-c6d99b6c17c8','水精','王建','唐','唐诗','tang','','[]','映水色不別，向月光還度。',24,'全唐诗/poet.tang.16000.json','["映水色不別，向月光還度。", "傾在荷葉中，有時看是露。"]'),
('a9952526-56d6-4fe5-a44f-44f2d8cff826','香印','王建','唐','唐诗','tang','','[]','閑坐燒印香，滿戶松柏氣。',24,'全唐诗/poet.tang.16000.json','["閑坐燒印香，滿戶松柏氣。", "火盡轉分明，青苔碑上字。"]'),
('60cc0c7d-7a16-4474-9e97-710f3f5ba362','秋燈','王建','唐','唐诗','tang','','[]','向壁暖悠悠，羅幃寒寂寂。',24,'全唐诗/poet.tang.16000.json','["向壁暖悠悠，羅幃寒寂寂。", "斜照碧山圖，松間一片石。"]'),
('73b463e3-0634-4be4-8d69-935d41bb76ba','落葉','王建','唐','唐诗','tang','','[]','陳綠向參差，初紅已重疊。',24,'全唐诗/poet.tang.16000.json','["陳綠向參差，初紅已重疊。", "中庭初掃地，繞樹三兩葉。"]'),
('6fb272bc-5660-4a2f-8c56-cff401d964da','園果','王建','唐','唐诗','tang','','[]','雨中棃果病，每樹無數箇。',24,'全唐诗/poet.tang.16000.json','["雨中棃果病，每樹無數箇。", "小兒出入看，一半鳥啄破。"]'),
('6d1ee060-5750-4c9b-8c75-6080912cbe17','野菊','王建','唐','唐诗','tang','','["\u548f\u7269", "\u83ca\u82b1", "\u8d5e\u7f8e", "\u548f\u7269\u8bd7"]','晚豔出荒籬，冷香著秋水。',24,'全唐诗/poet.tang.16000.json','["晚豔出荒籬，冷香著秋水。", "憶向山中見，伴蛩石壁裏。"]'),
('69fb354c-b79e-49ff-b5af-3ebda8e78467','荒園','王建','唐','唐诗','tang','','[]','朝日滿園霜，牛衝籬落壞。',24,'全唐诗/poet.tang.16000.json','["朝日滿園霜，牛衝籬落壞。", "掃掠黃葉中，時時一窠薤。"]'),
('e60091b4-ed57-4889-93ef-7134cd4a235a','南澗','王建','唐','唐诗','tang','','[]','野桂香滿溪，石莎寒覆水。',24,'全唐诗/poet.tang.16000.json','["野桂香滿溪，石莎寒覆水。", "愛此南澗頭，終日潺湲裏。"]'),
('9ed75c18-bb15-43f6-8a59-694c872b9f2f','晚蝶','王建','唐','唐诗','tang','','[]','粉翅嫩如水，繞砌乍依風。',24,'全唐诗/poet.tang.16000.json','["粉翅嫩如水，繞砌乍依風。", "日高山露解，飛入菊花中。"]'),
('7546c4ad-9315-40c4-b334-8650fa5b17a5','田家','王建','唐','唐诗','tang','','[]','啾啾雀滿樹，靄靄東坡雨。',24,'全唐诗/poet.tang.16000.json','["啾啾雀滿樹，靄靄東坡雨。", "田家夜無食，水中摘禾黍。"]'),
('0fb88df8-f09c-42ef-86ef-5e022a5831b4','新嫁娘詞三首 一','王建','唐','唐诗','tang','','[]','鄰家人未識，牀上坐堆堆。',24,'全唐诗/poet.tang.16000.json','["鄰家人未識，牀上坐堆堆。", "郎來傍門戶，滿口索錢財。"]'),
('fd7bced0-9f84-409b-b035-38ae5a143842','新嫁娘詞三首 二','王建','唐','唐诗','tang','','[]','錦幛兩邊橫，遮掩侍娘行。',24,'全唐诗/poet.tang.16000.json','["錦幛兩邊橫，遮掩侍娘行。", "遣郎鋪簟席，相並拜親情。"]'),
('efaaa86e-5628-40d3-a137-1ae8fcbe41b8','新嫁娘詞三首 三','王建','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u65b0\u5a5a", "\u4e94\u8a00\u7edd\u53e5", "\u5973\u5b50", "\u751f\u6d3b"]','三日入廚下，洗手作羹湯。',24,'全唐诗/poet.tang.16000.json','["三日入廚下，洗手作羹湯。", "未諳姑食性，先遣小姑嘗。"]'),
('a6c85d29-ad02-4f54-a347-63800213a7b4','故行宮','王建','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u53e4", "\u5bab\u6028", "\u4e94\u8a00\u7edd\u53e5"]','寥落古行宮，宮花寂寞紅。',24,'全唐诗/poet.tang.16000.json','["寥落古行宮，宮花寂寞紅。", "白頭宮女在，閑坐說玄宗。"]'),
