('c0edb69f-e1e5-46bc-8481-577a118f8b4c','宮詞一百首 九十一','王建','唐','唐诗','tang','','[]','金殿當頭紫閤重，仙人掌上玉芙蓉。',32,'全唐诗/poet.tang.16000.json','["金殿當頭紫閤重，仙人掌上玉芙蓉。", "太平天子朝迎日，五色雲車駕六龍。"]'),
('599fb506-5684-4d62-b5fa-db3c51812f8e','宮詞一百首 九十二','王建','唐','唐诗','tang','','[]','鴛鴦瓦上瞥然聲，晝寢宮娥夢裏驚。',32,'全唐诗/poet.tang.16000.json','["鴛鴦瓦上瞥然聲，晝寢宮娥夢裏驚。", "元是我王金彈子，海棠花下打流鶯。"]'),
('2a572a9b-e559-4c0e-b203-f79f1aa8827d','宮詞一百首 九十三','王建','唐','唐诗','tang','','[]','忽地金輿向月陂，內人接著便相隨。',32,'全唐诗/poet.tang.16000.json','["忽地金輿向月陂，內人接著便相隨。", "却回龍武軍前過，當處敎開臥鴨池。"]'),
('2264ebda-c26d-44d0-ade0-b4e4f611f5cf','宮詞一百首 九十四','王建','唐','唐诗','tang','','[]','畫作天河刻作牛，玉梭金鑷采橋頭。',32,'全唐诗/poet.tang.16000.json','["畫作天河刻作牛，玉梭金鑷采橋頭。", "每年宮裏穿針夜，勑賜諸親乞巧樓。"]'),
('39a7273e-ae33-4de7-b20e-f0f7a6c0d78c','宮詞一百首 九十五','王建','唐','唐诗','tang','','[]','春來睡困不梳頭，懶逐君王苑北游。',32,'全唐诗/poet.tang.16000.json','["春來睡困不梳頭，懶逐君王苑北游。", "暫向玉花階上坐，簸錢贏得兩三籌。"]'),
('b633f346-d769-4271-bff8-64999918129e','宮詞一百首 九十六','王建','唐','唐诗','tang','','[]','步行送入長門裏，不許來辭舊院花。',32,'全唐诗/poet.tang.16000.json','["步行送入長門裏，不許來辭舊院花。", "只恐他時身到此，乞恩求赦放還家。"]'),
('19b439d1-831d-4205-a029-b960752b79d3','宮詞一百首 九十七','王建','唐','唐诗','tang','','[]','縑羅不著索輕容，對面敎人染退紅。',32,'全唐诗/poet.tang.16000.json','["縑羅不著索輕容，對面敎人染退紅。", "衫子成來一遍出，明朝半片在園中。"]'),
('1b000bd9-a7a3-4324-bbb4-1e7b753c88f2','宮詞一百首 九十八','王建','唐','唐诗','tang','','[]','彈棋玉指兩叁差，背局臨虛鬬著危。',32,'全唐诗/poet.tang.16000.json','["彈棋玉指兩叁差，背局臨虛鬬著危。", "先打角頭紅子落，上三金字半邊垂。"]'),
('d76aa321-8445-4830-9fa8-ec736fa8703f','宮詞一百首 九十九','王建','唐','唐诗','tang','','[]','後宮宮女無多少，盡向園中笑一團。',32,'全唐诗/poet.tang.16000.json','["後宮宮女無多少，盡向園中笑一團。", "舞蝶落花相覓著，春風共語亦應難。"]'),
('15d2463d-b5f0-4b81-83aa-408aa2cad3b8','宮詞一百首 一百','王建','唐','唐诗','tang','','[]','宛轉黃金白柄長，青荷葉子畫鴛鴦。',32,'全唐诗/poet.tang.16000.json','["宛轉黃金白柄長，青荷葉子畫鴛鴦。", "把來不是呈新樣，欲進微風到御牀。"]'),
('7577f4d7-8b15-4133-a741-84caefc06062','宮詞一百首 一百一','王建','唐','唐诗','tang','','[]','供御香方加減頻，水沈山麝每回新。',32,'全唐诗/poet.tang.16000.json','["供御香方加減頻，水沈山麝每回新。", "內中不許相傳出，已被醫家寫與人。"]'),
('798e071a-a38c-4e59-a2fd-aaa5c7a6e1b3','宮詞一百首 一百二','王建','唐','唐诗','tang','','[]','藥童食後送雲漿，高殿無風扇少涼。',32,'全唐诗/poet.tang.16000.json','["藥童食後送雲漿，高殿無風扇少涼。", "每到日中重掠鬢，衩衣騎馬繞宮廊。"]'),
('a7d155e3-e149-403e-ae76-538a64295657','句','王建','唐','唐诗','tang','','[]','單于不向南牧馬，席萁遍滿天山下卻公不易勝，莫著外家欺。',83,'全唐诗/poet.tang.16000.json','["單于不向南牧馬，席萁遍滿天山下卻公不易勝，莫著外家欺。", "錦江詩弟子，時寄五花牋。", "花燒落第眼，雨破到家程。", "一朝金鳳庭前下，當是虛皇詔沈曦。", "宣城四面水茫茫，草蓋江城竹夾牆。"]'),
('9a9d1c54-36be-433a-bf1c-35f0e839e226','銅雀妓','劉商','唐','唐诗','tang','','[]','魏主矜蛾眉，美人美於玉。',132,'全唐诗/poet.tang.16000.json','["魏主矜蛾眉，美人美於玉。", "高臺無晝夜，歌舞竟未足。", "盛色如轉圜，夕陽落深谷。", "仍令身歿後，尚縱平生慾。", "紅粉淚縱橫，調絃向空屋。", "舉頭君不在，惟見西陵木。", "玉輦豈再來，嬌鬟爲誰綠。", "那堪秋風裏，更舞陽春曲。", "曲罷情不勝，凭闌向西哭。", "臺邊生野草，來去罥羅縠。", "況復陵寢間，雙雙見麋鹿。"]'),
('bf2bbb81-fe8c-448a-b0de-d1d518314e90','哭韓淮端公兼上崔中丞','劉商','唐','唐诗','tang','','[]','堅貞與和璧，利用歸干將。',216,'全唐诗/poet.tang.16000.json','["堅貞與和璧，利用歸干將。", "金玉徒自寶，高賢無比方。", "挺生巖松姿，孤直凌雪霜。", "亭亭結清陰，不競桃李芳。", "讀書哂霸業，翊贊思皇王。", "千載有疑議，一言能否臧。", "儒風久淪弊，顏閔壽不長。", "邦國豈殄瘁，斯人今又亡。", "別離長春草，存沒隔楚鄉。", "聞問尚書慟，淚凝向日黃。", "奄忽薤露晞，杳冥泉夜長。", "賢愚自修短，天色空蒼蒼。", "銘旌歛歸魂，荆棘生路傍。", "門柳日蕭索，繐帷掩空堂。", "燈孤晦處明，高節歿後彰。", "芳蘭已灰燼，幕府留餘香。", "常愛獨坐尊，繡衣如雁行。", "至今虛左位，言發淚霑裳。"]'),
('0f9dd333-5f18-478b-8b18-53ed1bf06e91','秋夜聽嚴紳巴童唱竹枝歌','劉商','唐','唐诗','tang','','[]','巴人遠從荆山客，回首荆山楚雲隔。',144,'全唐诗/poet.tang.16000.json','["巴人遠從荆山客，回首荆山楚雲隔。", "思歸夜唱竹枝歌，庭槐葉落秋風多。", "曲中歷歷敘鄉土，鄉思綿綿楚詞古。", "身騎吳牛不畏虎，手提簑笠欺風雨。", "猨啼日暮江岸邊，綠蕪連山水連天。", "來時十三今十五，一成新衣已再補。", "鴻雁南飛報鄰伍，在家歡樂辭家苦。", "天晴露白鐘漏遲，淚痕滿面看竹枝。", "曲終寒竹風裊裊，西方落日東方曉。"]'),
('14824f68-98d7-433e-be7c-2eff3a9a891c','烏夜啼','劉商','唐','唐诗','tang','','[]','遶樹啞啞驚復栖，含烟碧樹高枝齊。',72,'全唐诗/poet.tang.16000.json','["遶樹啞啞驚復栖，含烟碧樹高枝齊。", "月明露濕枝亦滑，城上女牆西月低。", "愁人出戶聽烏啼，團團明月墮牆西。", "月中有桂樹，日中有伴侶。", "何不上天去？一聲啼到曙。"]'),
('6d2f8ac7-6cd0-4b7f-9dba-38a1b190f195','隨陽雁歌送兄南遊','劉商','唐','唐诗','tang','','[]','塞鴻聲聲飛不住，終日南征向何處。',96,'全唐诗/poet.tang.16000.json','["塞鴻聲聲飛不住，終日南征向何處。", "大漠窮陰多沍寒，分飛不得長懷安。", "春去秋來年歲疾，湖南薊北關山難。", "寒飛萬里胡天雪，夜度千門漢家月。", "去住應多兩地情，東西動作經年別。", "南州風土復何如，春雁歸時早寄書。"]'),
('1db712ea-73c1-4162-b031-24b137bcc622','賦得射雉歌送楊協律表弟赴婚期','劉商','唐','唐诗','tang','','[]','昔日才高容貌古，相敬如賓不相覩。',176,'全唐诗/poet.tang.16000.json','["昔日才高容貌古，相敬如賓不相覩。", "手奉蘋蘩喜盛門，心知禮義感君恩。", "三星照戶春空盡，一樹桃花竟不言。", "結束車輿強遊往，和風霽日東臯上。", "鸞鳳參差陌上行，麥苗縈隴雉初鳴。", "修容盡飾將何益，極慮呈材欲導情。", "六藝從師得機要，百發穿楊含絕妙。", "白羽風馳碎錦毛，青娥怨處嫣然笑。", "楊生詞賦比潘郎，不似前賢貌不揚。", "聽調琴弄能和室，更解彎弧足自防。", "秋深爲爾持圓扇，莫忘魯連飛一箭。"]'),
('53a21972-1845-42d9-9d17-e7d4987d496d','泛舒城南溪賦得沙鶴歌奉餞張侍御赴河南元博士赴揚州拜覲僕射','劉商','唐','唐诗','tang','','[]','終日閭閻逐羣雞，喜逢野鶴臨清溪。',144,'全唐诗/poet.tang.16000.json','["終日閭閻逐羣雞，喜逢野鶴臨清溪。", "綠苔春水水中影，夜月平沙沙上栖。", "驚謂汀洲白蘋發，又疑曲渚前年雪。", "紫頂昂藏肯狎人，一聲嘹亮沖天闕。", "素質翩翩帶落暉，湖南渭陽相背飛。", "東西分散別離促，宇宙蒼茫相見稀。", "皇華地仙如鶴馭，乘駕飄飄留不住。", "延望乘虛入紫霞，陌頭回首空烟樹。", "會使摶風羽翮輕，九霄雲路隨先鳴。"]'),
('a6e781fe-94d9-48fd-9d57-cc331970e10f','姑蘇懷古送秀才下第歸江南','劉商','唐','唐诗','tang','','[]','姑蘇臺枕吳江水，層級鱗差向天倚。',336,'全唐诗/poet.tang.16000.json','["姑蘇臺枕吳江水，層級鱗差向天倚。", "秋高露白萬林空，低望吳田三百里。", "當時雄盛如何比，千仞無根立平地。", "臺前夾月吹玉鸞，臺上迎涼撼金翠。", "銀河倒瀉君王醉，灩酒峩冠眄西子。", "宮娃酣態舞娉婷，香飆四颯青城墜。", "伍員結舌長噓嚱，忠諫無因到君耳。", "城烏啼盡海霞銷，深掩金屏日高睡。", "王道潛隳伍員死，可嘆斗間瞻王氣。", "會稽句踐擁長矛，萬馬鳴蹄掃空壘。", "瓦解冰銷真可恥，凝豔妖芳安足恃。", "可憐荒堞晚冥濛，麋鹿呦呦達遺址。", "君懷逸氣還東吳，吟狂日日遊姑蘇。", "興來下筆到奇景，瑤盤迸灑蛟人珠。", "大鵬矯翼翻雲衢，嵩峰霽後凌天孤。", "海潮秋打羅剎石，月魄夜當彭蠡湖。", "有時凝思家虛無，霓幢彷彿遊仙都。", "琳琅暗戛玉華殿，天香靜褭金芙蕖。", "君聲日下聞來久，清贍何人敢敵手。", "我逃名迹遁西林，不得灞陵傾別酒。", "莫便五湖爲隱淪，年年三十昇仙人。"]'),
('dc25343e-4e2d-46b0-a856-c2465581ef90','金井歌','劉商','唐','唐诗','tang','','[]','文明化洽天地清，和氣氤氳孕至靈。',144,'全唐诗/poet.tang.16000.json','["文明化洽天地清，和氣氤氳孕至靈。", "瑞雪不散抱層嶺，陽谷霞光射山頂。", "薙草披沙石竇開，生金曜日明金井。", "虞衡相賀爲禎祥，畏人採攫持殳戕。", "羊馳馬走塵滿道，郡邸封章開建章。", "君王儉德先簡易，贍國肥家在仁義。", "山澤藏金與萬人，宣言郡邑無專利。", "閭閻少長競奔凑，黃金滿袖家富有。", "驩心蹈舞歌皇風，願載謳歌青史中。"]'),
('1a0aeeef-7f97-44a4-969b-ce61c69043c3','柳條歌送客','劉商','唐','唐诗','tang','','[]','露井夭桃春未到，遲日猶寒柳開早。',80,'全唐诗/poet.tang.16000.json','["露井夭桃春未到，遲日猶寒柳開早。", "高枝低枝飛鸝黃，千條萬條覆宮牆。", "幾回離別折欲盡，一夜東風吹又長。", "毿毿拂人行不進，依依送君無遠近。", "青春去住隨柳條，却寄來人以爲信。"]'),
('c752cff2-b969-4ada-b562-bc5cc58caaa3','胡笳十八拍 第一拍','劉商','唐','唐诗','tang','','[]','漢室將衰兮四夷不賓，動干戈兮征戰頻。',82,'全唐诗/poet.tang.16000.json','["漢室將衰兮四夷不賓，動干戈兮征戰頻。", "哀哀父母生育我，見離亂兮當此辰。", "紗窗對鏡未經事，將謂珠簾能蔽身。", "一朝胡騎入中國，蒼黃處處逢胡人。", "忽將薄命委鋒鏑，可惜紅顏隨虜塵。"]'),
('c8aa9275-c55a-4d12-aff9-fffb282530b4','胡笳十八拍 第二拍','劉商','唐','唐诗','tang','','[]','馬上將余向絕域，厭生求死死不得。',64,'全唐诗/poet.tang.16000.json','["馬上將余向絕域，厭生求死死不得。", "戎羯腥膻豈是人，豺狼喜怒難姑息。", "行盡天山足霜霰，風土蕭條近胡國。", "萬里重陰鳥不飛，寒沙莽莽無南北。"]'),
('3e600dd7-b922-4ec2-b694-0d4eaeaa86bb','胡笳十八拍 第三拍','劉商','唐','唐诗','tang','','[]','如羇囚兮在縲絏，憂慮萬端無處說。',64,'全唐诗/poet.tang.16000.json','["如羇囚兮在縲絏，憂慮萬端無處說。", "使余刀兮剪余髮，食余肉兮飲余血。", "誠知殺身願如此，以余爲妻不如死。", "早被蛾眉累此身，空悲弱質柔如水。"]'),
('39d1e936-b9ac-465b-8f25-c2e4df0e6658','胡笳十八拍 第四拍','劉商','唐','唐诗','tang','','[]','山川路長誰記得，何處天涯是鄉國。',64,'全唐诗/poet.tang.16000.json','["山川路長誰記得，何處天涯是鄉國。", "自從驚怖少精神，不覺風霜損顏色。", "夜中歸夢來又去，朦朧豈解傳消息。", "漫漫胡天叫不聞，明明漢月應相識。"]'),
('f3b34c23-9d12-4503-b7c8-057c815ed34f','胡笳十八拍 第五拍','劉商','唐','唐诗','tang','','[]','水頭宿兮草頭坐，風吹漢地衣裳破。',64,'全唐诗/poet.tang.16000.json','["水頭宿兮草頭坐，風吹漢地衣裳破。", "羊脂沐髮長不梳，羔子皮裘領仍左。", "狐襟貉袖腥復膻，晝披行兮夜披臥。", "氈帳時移無定居，日月長兮不可過。"]'),
('59ce2ebb-5660-4c5a-b360-e8352c651df6','胡笳十八拍 第六拍','劉商','唐','唐诗','tang','','[]','怪得春光不來久，胡中風土無花柳。',64,'全唐诗/poet.tang.16000.json','["怪得春光不來久，胡中風土無花柳。", "天翻地覆誰得知，如今正南看北斗。", "姓名音信兩不通，終日經年常閉口。", "是非取與在指撝，言語傳情不如手。"]'),
('58d2dfe8-40c2-42ec-9dee-72a1480571de','胡笳十八拍 第七拍','劉商','唐','唐诗','tang','','[]','男兒婦人帶弓箭，塞馬蕃羊臥霜霰。',64,'全唐诗/poet.tang.16000.json','["男兒婦人帶弓箭，塞馬蕃羊臥霜霰。", "寸步東西豈自由，偷生乞死非情願。", "龜茲觱篥愁中聽，碎葉琵琶夜深怨。", "竟夕無雲月上天，故鄉應得重相見。"]'),
('6d98fe1d-74b2-4b61-8112-1d2e9beaf6d8','胡笳十八拍 第八拍','劉商','唐','唐诗','tang','','[]','憶昔私家恣嬌小，遠取珍禽學馴擾。',64,'全唐诗/poet.tang.16000.json','["憶昔私家恣嬌小，遠取珍禽學馴擾。", "如今淪棄念故鄉，悔不當初放林表。", "朔風蕭蕭寒日暮，星河寥落胡天曉。", "旦夕思歸不得歸，愁心想似籠中鳥。"]'),
('aa098574-5f7e-4be3-b8d1-5a1e7bc8040d','胡笳十八拍 第九拍','劉商','唐','唐诗','tang','','[]','當日蘇武單于問，道是賓鴻解傳信。',64,'全唐诗/poet.tang.16000.json','["當日蘇武單于問，道是賓鴻解傳信。", "學他刺血寫得書，書上千重萬重恨。", "髯胡少年能走馬，彎弓射飛無遠近。", "遂令邊雁轉怕人，絕域何由達方寸。"]'),
('3128f181-3841-403b-bb63-75cff2210e7b','胡笳十八拍 第十拍','劉商','唐','唐诗','tang','','[]','恨凌辱兮惡腥膻，憎胡地兮怨胡天。',64,'全唐诗/poet.tang.16000.json','["恨凌辱兮惡腥膻，憎胡地兮怨胡天。", "生得胡兒欲棄捐，及生母子情宛然。", "貌殊語異憎還愛，心中不覺常相牽。", "朝朝暮暮在眼前，腹生手養寧不憐。"]'),
('9c5c1f94-f4af-464d-a9c7-feee2cdddd51','胡笳十八拍 第十一拍','劉商','唐','唐诗','tang','','[]','日來月往相催遷，迢迢星歲欲周天。',64,'全唐诗/poet.tang.16000.json','["日來月往相催遷，迢迢星歲欲周天。", "無冬無夏臥霜霰，水凍草枯爲一年。", "漢家甲子有正朔，絕域三光空自懸。", "幾回鴻雁來又去，腸斷蟾蜍虧復圓。"]'),
('855f3a4e-d57b-455d-91a2-8680575a592c','胡笳十八拍 第十二拍','劉商','唐','唐诗','tang','','[]','破瓶落井空永沈，故鄉望斷無歸心。',64,'全唐诗/poet.tang.16000.json','["破瓶落井空永沈，故鄉望斷無歸心。", "寧知遠使問姓名，漢語泠泠傳好音。", "夢魂幾度到鄉國，覺後翻成哀怨深。", "如今果是夢中事，喜過悲來情不任。"]'),
('97b4f82e-7435-463a-bd8c-c4556930e757','胡笳十八拍 第十三拍','劉商','唐','唐诗','tang','','[]','童稚牽衣雙在側，將來不可留又憶。',64,'全唐诗/poet.tang.16000.json','["童稚牽衣雙在側，將來不可留又憶。", "還鄉惜別兩難分，寧棄胡兒歸舊國。", "山川萬里復邊戍，背面無由得消息。", "淚痕滿面對殘陽，終日依依向南北。"]'),
('57e95e45-fd2e-45e6-ac84-770e801192ef','胡笳十八拍 第十四拍','劉商','唐','唐诗','tang','','[]','莫以胡兒可羞耻，恩情亦各言其子。',64,'全唐诗/poet.tang.16000.json','["莫以胡兒可羞耻，恩情亦各言其子。", "手中十指有長短，截之痛惜皆相似。", "還鄉豈不見親族，念此飄零隔生死。", "南風萬里吹我心，心亦隨風度遼水。"]'),
('fc3f33f8-4a8a-4f6c-bbb2-1d911272a2d4','胡笳十八拍 第十五拍','劉商','唐','唐诗','tang','','[]','歎息襟懷無定分，當時怨來歸又恨。',64,'全唐诗/poet.tang.16000.json','["歎息襟懷無定分，當時怨來歸又恨。", "不知愁怨情若何，似有鋒鋩擾方寸。", "悲歡竝行情未快，心意相尤自相問。", "不緣生得天屬親，豈向仇讐結恩信。"]'),
('52d879f5-cf71-4fc0-b691-48b4800e4610','胡笳十八拍 第十六拍','劉商','唐','唐诗','tang','','[]','去時只覺天蒼蒼，歸日始知胡地長。',64,'全唐诗/poet.tang.16000.json','["去時只覺天蒼蒼，歸日始知胡地長。", "重陰白日落何處，秋雁所向應南方。", "平沙四顧自迷惑，遠近悠悠隨雁行。", "征途未盡馬蹄盡，不見行人邊草黃。"]'),
('5bac9387-46ad-4204-aa27-0b802d854d99','胡笳十八拍 第十七拍','劉商','唐','唐诗','tang','','[]','行盡胡天千萬里，唯見黃沙白雲起。',64,'全唐诗/poet.tang.16000.json','["行盡胡天千萬里，唯見黃沙白雲起。", "馬飢跑雪銜草根，人渴敲冰飲流水。", "燕山髣髴辨烽戍，鼙鼓如聞漢家壘。", "努力前程是帝鄉，生前免向胡中死。"]'),
('77a5ef08-2dcc-407a-8435-8a675d8cd159','胡笳十八拍 第十八拍','劉商','唐','唐诗','tang','','[]','歸來故鄉見親族，田園半蕪春草綠。',64,'全唐诗/poet.tang.16000.json','["歸來故鄉見親族，田園半蕪春草綠。", "明燭重燃煨燼灰，寒泉更洗沈泥玉。", "載持巾櫛禮儀好，一弄絲桐生死足。", "出入關山十二年，哀情盡在胡笳曲。"]'),
('8175d362-c8b9-466d-a738-fc95652ee00c','雜言同豆盧郎中郭南七里橋哀悼姚倉曹','劉商','唐','唐诗','tang','','[]','橋邊足離別，終日爲悲辛。',76,'全唐诗/poet.tang.16000.json','["橋邊足離別，終日爲悲辛。", "登橋因歎逝，却羨別離人。", "橋下東流水，芳樹櫻桃蘂。", "流水與潮迴，花落明年開。", "可憐三語掾，長作九泉灰。", "宿昔歡遊在何處，花前飲足求仙去。"]'),
('19e3c503-b936-42f7-a20b-aa67fb63bd42','春日臥病','劉商','唐','唐诗','tang','','[]','楚客經年病，孤舟人事稀。',48,'全唐诗/poet.tang.16000.json','["楚客經年病，孤舟人事稀。", "晚晴江柳變，春暮塞鴻歸。", "今日方知命，前身自覺非。", "不能憂歲計，無限故山薇。"]'),
('33f57929-32fc-4b75-a67c-5c8a205b6633','題禪居廢寺','劉商','唐','唐诗','tang','','[]','凋殘精舍在，連步訪緇衣。',48,'全唐诗/poet.tang.16000.json','["凋殘精舍在，連步訪緇衣。", "古殿門空掩，楊花雪亂飛。", "鶴巢松影薄，僧少磬聲稀。", "青眼能留客，疎鐘逼夜歸。"]'),
('750681cd-241e-47e4-ae58-75a805741d79','題山寺','劉商','唐','唐诗','tang','','[]','扁舟水淼淼，曲岸復長塘。',48,'全唐诗/poet.tang.16000.json','["扁舟水淼淼，曲岸復長塘。", "古寺春山上，登樓憶故鄉。", "雲烟橫極浦，花木擁迴廊。", "更有思歸意，晴明陟上方。"]'),
('f28d3b72-4f74-44fd-bf93-47cc98b943a3','題楊侍郎新亭','劉商','唐','唐诗','tang','','[]','毘陵過柱史，簡易在茅茨。',48,'全唐诗/poet.tang.16000.json','["毘陵過柱史，簡易在茅茨。", "芳草如花種，修篁帶笋移。", "徑幽人未賞，簷靜燕初窺。", "野客憐霜壁，青松畫一枝。"]'),
('f1f52d4d-4255-4974-847a-0511d42332a5','同徐城季明府遊重光寺題晃師壁','劉商','唐','唐诗','tang','','[]','野寺僧房遠，陶潛引客來。',48,'全唐诗/poet.tang.16000.json','["野寺僧房遠，陶潛引客來。", "鳥喧殘果落，蘭敗幾花開。", "真性知無住，微言欲望迴。", "竹風清磬晚，歸策步蒼苔。"]'),
('54057edc-c57e-48c5-9aab-9e6a78dfc58b','送林袞侍御東陽秩滿赴上都','劉商','唐','唐诗','tang','','[]','幾年烏府內，何處逐鳧歸。',48,'全唐诗/poet.tang.16000.json','["幾年烏府內，何處逐鳧歸。", "關吏迷驄馬，銅章累繡衣。", "野亭山草綠，客路柳花飛。", "況復長安遠，音書從此稀。"]'),
('ed324ccb-055a-4da7-9807-8464a8eb46d1','送人之江東','劉商','唐','唐诗','tang','','[]','含香仍佩玉，宜入鏡中行。',48,'全唐诗/poet.tang.16000.json','["含香仍佩玉，宜入鏡中行。", "盡室隨乘興，扁舟不計程。", "渡江霖雨霽，對月夜潮生。", "莫慮當炎暑，稽山水木清。"]'),
('256d9d34-901b-4586-bd9c-bfddbdf025db','送李元規昆季赴舉','劉商','唐','唐诗','tang','','[]','見誦甘泉賦，心期折桂歸。',48,'全唐诗/poet.tang.16000.json','["見誦甘泉賦，心期折桂歸。", "鳳雛皆五色，鴻漸又雙飛。", "別思看衰柳，秋風動客衣。", "明朝問禮處，蹔覺雁行稀。"]'),
('c04bee0c-2dd1-4ce8-8363-3be2f06db71b','送楊閑侍御拜命赴上都','劉商','唐','唐诗','tang','','[]','賀客移星使，絲綸出紫微。',48,'全唐诗/poet.tang.16000.json','["賀客移星使，絲綸出紫微。", "手中霜作簡，身上繡爲衣。", "驄馬朝天疾，臺烏向日飛。", "親朋皆避路，不是送人稀。"]'),
('86d693be-a8d4-4ad2-a205-cf0d30255e90','賦得月下聞蛩送別','劉商','唐','唐诗','tang','','[]','物候改秋節，炎涼此夕分。',48,'全唐诗/poet.tang.16000.json','["物候改秋節，炎涼此夕分。", "暗蟲聲徧草，明月夜無雲。", "清逈簷外見，淒其籬下聞。", "感時兼惜別，羇思自紛紛。"]'),
('3fba7ff9-acd9-4dce-bfbc-2e071547103d','重陽日寄上饒李明府','劉商','唐','唐诗','tang','','[]','重陽秋雁未啣蘆，始覺他鄉節候殊。',64,'全唐诗/poet.tang.16000.json','["重陽秋雁未啣蘆，始覺他鄉節候殊。", "旅館但知聞蟋蟀，郵童不解獻茱萸。", "陶潛何處登高醉，倦客停橈一事無。", "來歲公田多種黍，莫敎黃菊笑楊朱。"]'),
('dd5f08ab-e872-48df-978b-369433e46e7d','同諸子哭張元易','劉商','唐','唐诗','tang','','[]','盛德高名總是空，神明福善大朦朧。',64,'全唐诗/poet.tang.16000.json','["盛德高名總是空，神明福善大朦朧。", "遊魂永永無歸日，流水年年自向東。", "素帷旅櫬鄉關遠，丹旐孤燈客舍中。", "伯道共悲無後嗣，孀妻老母斷根蓬。"]'),
('35922d1a-9bd6-4c05-aa45-274cf51ded24','合肥至日愁中寄鄭明府','劉商','唐','唐诗','tang','','[]','失計爲卑吏，三年滯楚鄉。',120,'全唐诗/poet.tang.16000.json','["失計爲卑吏，三年滯楚鄉。", "不能隨世俗，應是昧行藏。", "白璧空無玷，黃沙只自傷。", "暮天鄉思亂，曉鏡鬢毛蒼。", "灰管移新律，窮陰變一陽。", "歲時人共換，幽憤日先長。", "拙宦慚知己，無媒悔自強。", "迍邅羞薄命，恩惠費餘光。", "衆口誠難稱，長川却易防。", "魚竿今尚在，行此掉滄浪。"]'),
('a0bfd0f1-c4ef-46fe-a535-5effc4ca87b6','送廬州賈使君拜命','劉商','唐','唐诗','tang','','[]','考績朝稱貴，時清武用文。',96,'全唐诗/poet.tang.16000.json','["考績朝稱貴，時清武用文。", "二天移外府，三命佐元勳。", "佩玉兼高位，摐金閱上軍。", "威容冠是鐵，圖畫閣名芸。", "人詠甘棠茂，童謠竹馬羣。", "懸旌風肅肅，臥轍淚紛紛。", "特達恩難報，升沈路易分。", "侯嬴不得從，心逐信陵君。"]'),
('356e693d-f163-4cfb-ba12-54c808e63828','怨婦','劉商','唐','唐诗','tang','','[]','淨掃黃金階，飛霜皎如雪。',24,'全唐诗/poet.tang.16000.json','["淨掃黃金階，飛霜皎如雪。", "下簾彈箜篌，不忍見秋月。"]'),
('1af41365-8613-43b1-b7e7-ec4bc29016a2','綠珠怨','劉商','唐','唐诗','tang','','[]','從來上臺榭，不敢倚闌干。',24,'全唐诗/poet.tang.16000.json','["從來上臺榭，不敢倚闌干。", "零落知成血，高樓直下看。"]'),
('8d40eb55-efed-44ae-a45d-994044bd05e7','古意','劉商','唐','唐诗','tang','','[]','達曉寢衣冷，開帷霜露凝。',24,'全唐诗/poet.tang.16000.json','["達曉寢衣冷，開帷霜露凝。", "風吹昨夜淚，一片枕前冰。"]'),
('8f6704ae-d21f-4be6-ab2c-b2627696130a','哭蕭掄','劉商','唐','唐诗','tang','','[]','何處哭故人，青門水如箭。',24,'全唐诗/poet.tang.16000.json','["何處哭故人，青門水如箭。", "當時水頭別，從此不相見。"]'),
('62c07bf8-fca7-4c72-91d2-f7043d2c972a','送從弟赴上都','劉商','唐','唐诗','tang','','[]','車騎秦城遠，囊裝楚客貧。',24,'全唐诗/poet.tang.16000.json','["車騎秦城遠，囊裝楚客貧。", "月明思遠道，詩罷訴何人。"]'),
('72f97955-cff6-4990-879b-acd33c85c53d','登相國寺閣','劉商','唐','唐诗','tang','','[]','晴日登臨好，春風各望家。',24,'全唐诗/poet.tang.16000.json','["晴日登臨好，春風各望家。", "垂楊夾城路，客思逐楊花。"]'),
('465abfc8-fe1f-4cc3-a9f3-5479f87cbfc0','酬濬上人采藥見寄','劉商','唐','唐诗','tang','','[]','玉英期共采，雲嶺獨先過。',24,'全唐诗/poet.tang.16000.json','["玉英期共采，雲嶺獨先過。", "應得靈芝也，詩情一倍多。"]'),
('65d6b275-c8b1-4bd6-9670-8a50b5be44d1','曲水寺枳實','劉商','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','枳實遶僧房，攀枝置藥囊。',24,'全唐诗/poet.tang.16000.json','["枳實遶僧房，攀枝置藥囊。", "洞庭山上橘，霜落也應黃。"]'),
('29cf1bbc-2b05-497a-89d2-961b2f7235d6','酬問師','劉商','唐','唐诗','tang','','[]','虛空無處所，髣髴似琉璃。',24,'全唐诗/poet.tang.16000.json','["虛空無處所，髣髴似琉璃。", "詩境何人到，禪心又過詩。"]'),
('1d70ecfb-07ba-41c3-81ed-d4f8fbc8e1e4','殷秀才求詩','劉商','唐','唐诗','tang','','[]','傾蓋見芳姿，晴天瓊樹枝。',24,'全唐诗/poet.tang.16000.json','["傾蓋見芳姿，晴天瓊樹枝。", "連城猶隱石，唯有卞和知。"]'),
('2f7723ef-bcde-4e91-8d32-dd66a03dadbe','行營即事','劉商','唐','唐诗','tang','','[]','萬姓厭干戈，三邊尚未和。',24,'全唐诗/poet.tang.16000.json','["萬姓厭干戈，三邊尚未和。", "將軍誇寶劒，功在殺人多。"]'),
('02efac18-657f-49cc-aec7-bb821b0fa2d4','送劉寰北歸','劉商','唐','唐诗','tang','','[]','南巢登望縣城孤，半是青山半是湖。',32,'全唐诗/poet.tang.16000.json','["南巢登望縣城孤，半是青山半是湖。", "知爾素多山水興，此回歸去更來無。"]'),
