('7c7c5f83-8f11-4174-ac35-fb3acdf4ba7a','代人村中悼亡二首 一','劉商','唐','唐诗','tang','','[]','花落茅簷轉寂寥，魂隨暮雨此中銷。',32,'全唐诗/poet.tang.16000.json','["花落茅簷轉寂寥，魂隨暮雨此中銷。", "邇來庭柳無人折，長得垂枝一萬條。"]'),
('5c11e69f-a174-486b-967e-4b8c1717b997','代人村中悼亡二首 二','劉商','唐','唐诗','tang','','[]','虛室無人乳燕飛，蒼苔滿地履痕稀。',32,'全唐诗/poet.tang.16000.json','["虛室無人乳燕飛，蒼苔滿地履痕稀。", "庭前唯有薔薇在，花似殘妝葉似衣。"]'),
('7070a110-e4f7-4db0-a389-aaa8303665a6','觀獵三首 一','劉商','唐','唐诗','tang','','[]','夢非熊虎數年間，驅盡豺狼宇宙閑。',32,'全唐诗/poet.tang.16000.json','["夢非熊虎數年間，驅盡豺狼宇宙閑。", "傳道單于聞校獵，相期不敢過陰山。"]'),
('61b6f683-2b9e-41c0-88cb-46df7a1cc9af','觀獵三首 二','劉商','唐','唐诗','tang','','[]','日隱寒山獵未歸，鳴絃落羽雪霏霏。',32,'全唐诗/poet.tang.16000.json','["日隱寒山獵未歸，鳴絃落羽雪霏霏。", "梁園射盡南飛鴈，淮楚人驚陽鳥啼。"]'),
('dece4ca9-85a1-49fb-aa4a-85d004bb7574','觀獵三首 三','劉商','唐','唐诗','tang','','[]','松月東軒許獨遊，深恩未報復淹留。',32,'全唐诗/poet.tang.16000.json','["松月東軒許獨遊，深恩未報復淹留。", "梁園日暮從公獵，每過青山不舉頭。"]'),
('fd933711-1b4d-4fec-aa26-c87d4484c886','畫石','劉商','唐','唐诗','tang','','[]','蒼蘚千年粉繪傳，堅貞一片色猶全。',32,'全唐诗/poet.tang.16000.json','["蒼蘚千年粉繪傳，堅貞一片色猶全。", "那知忽遇非常用，不把分銖補上天。"]'),
('d2782132-3d54-4bf4-8d68-d2b9c2803bda','詠雙開蓮花','劉商','唐','唐诗','tang','','[]','菡萏新花曉竝開，濃妝美笑面相隈。',32,'全唐诗/poet.tang.16000.json','["菡萏新花曉竝開，濃妝美笑面相隈。", "西方采畫迦陵鳥，早晚雙飛池上來。"]'),
('265957da-73d9-4c7c-be73-7768cbfb58a3','夜聞鄰管','劉商','唐','唐诗','tang','','[]','何事霜天月滿空，鸝雛百囀向春風。',32,'全唐诗/poet.tang.16000.json','["何事霜天月滿空，鸝雛百囀向春風。", "鄰家思婦更長短，楊柳如絲在管中。"]'),
('73a6d10e-ee40-4b4c-9b2a-284b12b70e71','山中寄元二侍御二首 一','劉商','唐','唐诗','tang','','[]','心期汗漫臥雲扃，家計漂零水上萍。',32,'全唐诗/poet.tang.16000.json','["心期汗漫臥雲扃，家計漂零水上萍。", "桃李向秋彫落盡，一枝松色獨青青。"]'),
('61e43314-6f9b-4881-ab52-ecd073db4d74','山中寄元二侍御二首 二','劉商','唐','唐诗','tang','','[]','拖紫鏘金濟世才，知君倚玉望三台。',32,'全唐诗/poet.tang.16000.json','["拖紫鏘金濟世才，知君倚玉望三台。", "深山窮谷無人到，唯有狂愚獨自來。"]'),
('02073a29-4c9c-4d60-b2fa-c92796cb24f2','上崔十五老丈','劉商','唐','唐诗','tang','','[]','天漢乘槎可問津，寂寥深景到無因。',32,'全唐诗/poet.tang.16000.json','["天漢乘槎可問津，寂寥深景到無因。", "看花獨往尋詩客，不爲經時謁丈人。"]'),
('60a2019f-2e72-472b-8b8f-03150f7b986a','袁德師求畫松','劉商','唐','唐诗','tang','','[]','柏偃松𢼮勢自分，森梢古意出浮雲。',32,'全唐诗/poet.tang.16000.json','["柏偃松𢼮勢自分，森梢古意出浮雲。", "如今眼暗畫不得，舊有三株持贈君。"]'),
('9bb54aba-3845-4717-9dec-1ed03b254f79','早夏月夜問王開','劉商','唐','唐诗','tang','','[]','清風首夏夜猶寒，嫩笋侵階竹數竿。',32,'全唐诗/poet.tang.16000.json','["清風首夏夜猶寒，嫩笋侵階竹數竿。", "君向蘇臺長見月，不知何事此中看。"]'),
('cc075307-65e8-4814-90fa-3bf93d48608f','裴十六廳即事','劉商','唐','唐诗','tang','','[]','主人能政訟庭閑，帆影雲峰戶牖間。',32,'全唐诗/poet.tang.16000.json','["主人能政訟庭閑，帆影雲峰戶牖間。", "每到夕陽嵐翠近，只言籬障倚前山。"]'),
('d82bf4d8-ee33-41ad-a008-d4dbfcabd803','春日行營即事','劉商','唐','唐诗','tang','','[]','風引雙旌馬首齊，曹南戰勝日平西。',32,'全唐诗/poet.tang.16000.json','["風引雙旌馬首齊，曹南戰勝日平西。", "爲儒不解從戎事，花落春深聞鼓鼙。"]'),
('f2ac2ab6-d983-4f81-a059-b6fdea86d9aa','畫樹後呈濬師','劉商','唐','唐诗','tang','','[]','翔鳳邊風十月寒，蒼山古木更摧殘。',32,'全唐诗/poet.tang.16000.json','["翔鳳邊風十月寒，蒼山古木更摧殘。", "爲君壁上畫松柏，勁雪嚴霜君試看。"]'),
('de848ea1-22cb-4dd5-94e3-9000a8cd754e','弔從甥','劉商','唐','唐诗','tang','','[]','日晚河邊訪惸獨，衰柳寒蕪遶茅屋。',32,'全唐诗/poet.tang.16000.json','["日晚河邊訪惸獨，衰柳寒蕪遶茅屋。", "兒童驚走報人來，孀婦開門一聲哭。"]'),
('c50e5462-3ccc-4aa7-b24b-d8f96f823aa2','句','劉商','唐','唐诗','tang','','[]','郵筒不解獻茱萸。',24,'全唐诗/poet.tang.16000.json','["郵筒不解獻茱萸。", "趙侯首帶鹿耳巾，規模出自陶弘景。"]'),
('c58d0fc5-6167-4f0b-b55c-7fd132aeec8e','登城樓作','陳翊','唐','唐诗','tang','','[]','井邑白雲間，嚴城遠帶山。',48,'全唐诗/poet.tang.16000.json','["井邑白雲間，嚴城遠帶山。", "沙墟陰欲暮，郊色淡方閑。", "孤徑迴榕岸，層巒破枳關。", "寥寥分遠望，暫得一開顏。"]'),
('a94630e9-8d05-4f23-b942-1844901f030d','宴柏臺','陳翊','唐','唐诗','tang','','[]','華臺陳桂席，密榭宴清真。',48,'全唐诗/poet.tang.16000.json','["華臺陳桂席，密榭宴清真。", "柏葉猶霜氣，桃花似漢津。", "青尊照深夕，綠綺映芳春。", "欲憶相逢後，無言嶺海人。"]'),
('301cc127-a514-4c46-af4f-5ccecaa32d2a','過馬侍中亭','陳翊','唐','唐诗','tang','','[]','草色照雙扉，軒車到客稀。',48,'全唐诗/poet.tang.16000.json','["草色照雙扉，軒車到客稀。", "苔衣香屐迹，花綬少塵飛。", "薄望憐池淨，開畦愛雨肥。", "相過忘日昃，坐待白雲歸。"]'),
('0e3b3e00-9cd5-410e-af4f-7465e0d0d273','寄邵校書楚萇','陳翊','唐','唐诗','tang','','[]','愛酒時稱僻，高情自不凡。',48,'全唐诗/poet.tang.16000.json','["愛酒時稱僻，高情自不凡。", "向人方白眼，違俗有青巖。", "雲際開三徑，煙中挂一帆。", "相期同歲晚，閑興與松杉。"]'),
('7206fb5e-9794-4926-a77c-d49a48b66235','龍池春草','陳翊','唐','唐诗','tang','','[]','青春光鳳苑，細草徧龍池。',72,'全唐诗/poet.tang.16000.json','["青春光鳳苑，細草徧龍池。", "曲渚交蘋葉，迴塘惹柳枝。", "因風初苒苒，覆岸欲離離。", "色帶金堤靜，陰連玉樹移。", "日光浮靃靡，波影動參差。", "豈比生幽遠，芳馨衆不知。"]'),
('3b986600-ebf4-4bfe-b2c9-0d625e290cd5','郊行示友人','陳翊','唐','唐诗','tang','','[]','水開長鏡引諸巒，春洞花深落翠寒。',32,'全唐诗/poet.tang.16000.json','["水開長鏡引諸巒，春洞花深落翠寒。", "醉向絲蘿驚自醒，與君清耳聽松湍。"]'),
('2759a051-c5c9-4b72-bcf6-fcbefe90ad40','送別蕭二','陳翊','唐','唐诗','tang','','[]','橘花香覆白蘋洲，江引輕帆入遠遊。',32,'全唐诗/poet.tang.16000.json','["橘花香覆白蘋洲，江引輕帆入遠遊。", "千里雲天風雨夕，憶君不敢再登樓。"]'),
('201ebc09-9beb-4a5d-a962-92dc6afff5d4','遊仙','劉復','唐','唐诗','tang','','[]','稅駕倚扶桑，逍遙望九州。',120,'全唐诗/poet.tang.16000.json','["稅駕倚扶桑，逍遙望九州。", "二老佐軒轅，移戈戮蚩尤。", "功成棄之去，乘龍上天遊。", "天上見玉皇，壽與天地休。", "俯視崑崙宮，五城十二樓。", "王母何窈眇，玉質清且柔。", "揚袂折瓊枝，寄我天東頭。", "相思千萬歲，大運浩悠悠。", "安用知吾道，日月不能周。", "寄音青鳥翼，謝爾碧海流。"]'),
('45f5c07c-6fd7-4884-9107-e86be9cefe2d','寺居清晨','劉復','唐','唐诗','tang','','[]','高枕對曉月，衣巾清且涼。',72,'全唐诗/poet.tang.16000.json','["高枕對曉月，衣巾清且涼。", "露華朝未晞，滴瀝含虛光。", "隔竹聞汲井，開扉見焚香。", "幽心感衰病，結念依法王。", "青冥早雲飛，杳靄空鳥翔。", "此情皆有釋，悠然知所忘。"]'),
('db1c8f32-7a4a-432e-9e8c-c16945988fca','出東城','劉復','唐','唐诗','tang','','[]','步出東城門，獨行已徬徨。',96,'全唐诗/poet.tang.16000.json','["步出東城門，獨行已徬徨。", "伊洛汎清流，密林含朝陽。", "芳景雖可矚，憂懷在中腸。", "人生幾何時，苒苒隨流光。", "願得心所親，尊酒坐高堂。", "一爲浮沈隔，會合殊未央。", "雙戲水中鳧，和鳴自翱翔。", "我無此羽翼，安可以比方。"]'),
('3f8eb0b3-d997-49f6-90bf-74a3400e9a73','經禁城','劉復','唐','唐诗','tang','','[]','日沒路且長，遊子欲涕零。',108,'全唐诗/poet.tang.16000.json','["日沒路且長，遊子欲涕零。", "荒城無人路，秋草飛寒螢。", "東南古丘墟，莽蒼馳郊坰。", "黃雲晦斷岸，枯井臨崩亭。", "昔人竟何之，窮泉獨冥冥。", "蒼苔沒碑版，朽骨無精靈。", "俛仰寄世間，忽如流波萍。", "金石非汝壽，浮生等臊腥。", "不如學神仙，服食求丹經。"]'),
('054b8e52-9a8f-49b2-8341-801a5bff34be','出三城留別幕中三判官','劉復','唐','唐诗','tang','','[]','翔禽託高柯，倦客念主人。',120,'全唐诗/poet.tang.16000.json','["翔禽託高柯，倦客念主人。", "恩義有所知，四海同一身。", "況皆曠大姿，翰音見良辰。", "陳規佐武略，高視據要津。", "常願投素誠，今果得所申。", "金罍列四座，廣廈無氛塵。", "留連徂暑中，觀望歷數旬。", "河山險以固，士卒勇且仁。", "飭裝去未歸，相追越城闉。", "愧無青玉案，緘佩永不泯。"]'),
('6f000ab0-251b-480a-abfe-28d565c08797','送劉秀才南歸','劉復','唐','唐诗','tang','','[]','鳥啼楊柳垂，此別千萬里。',48,'全唐诗/poet.tang.16000.json','["鳥啼楊柳垂，此別千萬里。", "古路入商山，春風生灞水。", "停車落日在，罷酒離人起。", "蓬戶寄龍沙，送歸情詎已。"]'),
('fe915623-7e9c-4ad3-8f87-8947fa3d6934','送王倫','劉復','唐','唐诗','tang','','[]','春江日未曛，楚客酣送君。',72,'全唐诗/poet.tang.16000.json','["春江日未曛，楚客酣送君。", "翩翩孤黃鶴，萬里滄洲雲。", "四方各有志，豈得常顧羣。", "山連巴湘遠，水與荆吳分。", "清光日修阻，尺素安可論。", "相思寄夢寐，瑤草空氛氳。"]'),
('0a988f56-b22d-48cb-94f1-fc75e2532eab','長相思','劉復','唐','唐诗','tang','','[]','長相思，在桂林，蒼梧山遠瀟湘深。',96,'全唐诗/poet.tang.16000.json','["長相思，在桂林，蒼梧山遠瀟湘深。", "秋堂零淚倚金瑟，朱顏搖落隨光陰。", "長宵嘹唳鴻命侶，河漢蒼蒼隔牛女。", "寧知一水不可渡，況復萬山修且阻。", "綵絲織綺文雙鴛，昔時贈君君可憐。", "何言一去瓶落井，流塵歇滅金爐前。"]'),
('7cd26645-b9bd-4b2c-bbbd-7af03d8bc1b0','長歌行','劉復','唐','唐诗','tang','','[]','淮南木落秋雲飛，楚宮商歌今正悲。',131,'全唐诗/poet.tang.16000.json','["淮南木落秋雲飛，楚宮商歌今正悲。", "青春白日不與我，當壚舉酒勸君持。", "出門驅馳四方事，徒用辛勤不得意。", "三山海底無見期，百齡世間莫虛棄。", "君不見金城帝業漢家有，東制諸侯欲長久。", "姦雄竊命風塵昏，函谷重關不能守。", "龍蛇出沒經兩朝，胡虜憑陵大道銷。", "河水東流宮闕盡，五陵松柏自蕭蕭。"]'),
('57d4ff2e-1617-4bbc-a647-be4beb69097a','春遊曲','劉復','唐','唐诗','tang','','[]','春風戲狹斜，相見莫愁家。',48,'全唐诗/poet.tang.16000.json','["春風戲狹斜，相見莫愁家。", "細酌蒲桃酒，嬌歌玉樹花。", "裁衫催白紵，迎客走朱車。", "不覺重城暮，爭栖柳上鵶。"]'),
('d0892fc2-dffd-4c1c-bb5d-7e1191d6b3d6','雜曲','劉復','唐','唐诗','tang','','[]','寶劒飾文犀，當風似切泥。',48,'全唐诗/poet.tang.16000.json','["寶劒飾文犀，當風似切泥。", "逢君感意氣，貰酒杜陵西。", "趙女顏雖少，宛駒齒正齊。", "嬌多不肯別，更待夜烏啼。"]'),
('664fbadd-e1f7-4f7e-b8b4-919f553258fd','春雨','劉復','唐','唐诗','tang','','[]','細雨度深閨，鶯愁欲嬾啼。',48,'全唐诗/poet.tang.16000.json','["細雨度深閨，鶯愁欲嬾啼。", "如煙飛漠漠，似露濕淒淒。", "草色行看靡，花枝暮欲低。", "曉聽鐘鼓動，早送錦障泥。"]'),
('0db8ad0c-911f-4fe2-88de-4cb245fcfd0d','夕次襄邑','劉復','唐','唐诗','tang','','[]','何處成吾道，經年遠路中。',48,'全唐诗/poet.tang.16000.json','["何處成吾道，經年遠路中。", "客心猶向北，河水自歸東。", "古戍飄殘角，疎林振夕風。", "輕舟難載月，那與故人同。"]'),
('8b45440d-9cf5-4912-97b6-ed2dbf4b28e5','夏日','劉復','唐','唐诗','tang','','[]','暎日紗窗深且閑，含桃紅日石榴殷。',64,'全唐诗/poet.tang.16000.json','["暎日紗窗深且閑，含桃紅日石榴殷。", "銀瓶綆轉桐花井，沈水煙銷金博山。", "文簟象牀嬌倚瑟，綵匳銅鏡嬾拈環。", "明朝戲去誰相伴，年少相逢狹路間。"]'),
('14ed8f09-9c84-4e1e-b814-6c6c21aacf63','送黃曄明府岳州湘陰赴任','劉復','唐','唐诗','tang','','[]','擬占名塲第一科，龍門十上困風波。',64,'全唐诗/poet.tang.16000.json','["擬占名塲第一科，龍門十上困風波。", "三年護塞從戎遠，萬里投荒失意多。", "花縣到時銅墨貴，葉舟行處水雲和。", "遙知布惠蘇民後，應向祠堂弔汨羅。"]'),
('83ae6d70-db9c-47ec-856d-283076615700','禪門寺暮鐘','劉復','唐','唐诗','tang','','[]','簨簴高懸于闐鐘，黃昏發地殷龍宮。',32,'全唐诗/poet.tang.16000.json','["簨簴高懸于闐鐘，黃昏發地殷龍宮。", "遊人憶到嵩山夜，疊閣連樓滿太空。"]'),
('a369c730-c93d-4fb1-a235-ce7a1ec8f40c','同張深秀才遊華嚴寺','冷朝陽','唐','唐诗','tang','','[]','同遊雲外寺，渡水入禪關。',48,'全唐诗/poet.tang.16000.json','["同遊雲外寺，渡水入禪關。", "立埽窗前石，坐看池上山。", "有僧飛錫到，留客話松間。", "不是緣名利，好來長伴閑。"]'),
('a0bee52e-3b61-475b-9f5b-120e056e24da','中秋與空上人同宿華嚴寺','冷朝陽','唐','唐诗','tang','','[]','埽榻相逢宿，論詩舊梵宮。',48,'全唐诗/poet.tang.16000.json','["埽榻相逢宿，論詩舊梵宮。", "磬聲迎鼓盡，月色過山窮。", "庭簇安禪草，窗飛帶火蟲。", "一宵何惜別，回首隔秋風。"]'),
('e8a97318-e6dd-4bbf-a599-3ef79b4d6f13','宿柏巖寺','冷朝陽','唐','唐诗','tang','','[]','幽寺在巖中，行唯一徑通。',48,'全唐诗/poet.tang.16000.json','["幽寺在巖中，行唯一徑通。", "客吟孤嶠月，蟬噪數枝風。", "秋色生苔砌，泉聲入梵宮。", "吾師修道處，不與世間同。"]'),
('7aef47bc-c87f-4bf7-934d-bbc59b8da971','登靈善寺塔','冷朝陽','唐','唐诗','tang','','["\u9ec4\u6cb3"]','飛閣青霞裏，先秋獨早涼。',48,'全唐诗/poet.tang.16000.json','["飛閣青霞裏，先秋獨早涼。", "天花映窗近，月桂拂簷香。", "華岳三峰小，黃河一帶長。", "空聞指歸路，煙處有垂楊。"]'),
('0a5c5d0f-c729-4ca6-8655-68557df89721','瀑布泉','冷朝陽','唐','唐诗','tang','','[]','潺湲半空裏，霖落石房邊。',48,'全唐诗/poet.tang.16000.json','["潺湲半空裏，霖落石房邊。", "風激珠光碎，山欹練影偏。", "急流難起浪，迸沫祗如煙。", "自古惟今日，淒涼一片泉。"]'),
('05bfc235-c784-4456-b6b2-9b0829433f28','冬日逢馮法曹話懷','冷朝陽','唐','唐诗','tang','','[]','分襟二年內，多少事相干。',48,'全唐诗/poet.tang.16000.json','["分襟二年內，多少事相干。", "禮樂風全變，塵埃路漸難。", "秋林新葉落，霜月滿庭寒。", "雖喜逢知己，他鄉歲又闌。"]'),
('a7d09cc0-8468-4c8a-b340-67c15159da19','送唐六赴舉','冷朝陽','唐','唐诗','tang','','[]','秋色生邊思，送君西入關。',48,'全唐诗/poet.tang.16000.json','["秋色生邊思，送君西入關。", "草衰空大野，葉落露青山。", "故國煙霞外，新安道路間。", "碧霄知己在，香桂月中攀。"]'),
('c6ce38df-fe11-4c4c-b584-b1df4b7bd580','送遠上人歸京','冷朝陽','唐','唐诗','tang','','[]','夏臘歲方深，思歸徹曙吟。',48,'全唐诗/poet.tang.16000.json','["夏臘歲方深，思歸徹曙吟。", "未離銷雪院，已有過雲心。", "寒磬清函谷，孤鐘宿華陰。", "別京遊舊寺，月色似雙林。"]'),
('f42d7731-d87a-4b1f-b9cb-c84c5fac675b','別郎上人','冷朝陽','唐','唐诗','tang','','[]','過雲尋釋子，話別更依依。',48,'全唐诗/poet.tang.16000.json','["過雲尋釋子，話別更依依。", "靜室開來久，遊人到自稀。", "觸風香氣盡，隔水磬聲微。", "獨傍孤松立，塵中多是非。"]'),
('8e9e1d1d-9862-47d8-bf68-23cf477c1744','立春','冷朝陽','唐','唐诗','tang','','[]','玉律傳佳節，青陽應此辰。',72,'全唐诗/poet.tang.16000.json','["玉律傳佳節，青陽應此辰。", "土牛呈歲稔，綵燕表年春。", "臘盡星迴次，寒餘月建寅。", "風光行處好，雲物望中新。", "流水初銷凍，潛魚欲振鱗。", "梅花將柳色，偏思越鄉人。"]'),
('b5ee91d2-3649-4ef3-9310-953468fc9eea','送紅線','冷朝陽','唐','唐诗','tang','','[]','採菱歌怨木蘭舟，送客魂銷百尺樓。',32,'全唐诗/poet.tang.16000.json','["採菱歌怨木蘭舟，送客魂銷百尺樓。", "還似洛妃乘霧去，碧天無際水空流。"]'),
('52a41a91-414f-46df-97d5-e9aad9e036bf','南至日太史登臺書雲物','于尹躬','唐','唐诗','tang','','[]','至日行時令，登臺約禮文。',72,'全唐诗/poet.tang.16000.json','["至日行時令，登臺約禮文。", "官稱伯趙氏，色辨五方雲。", "晝漏聽初發，陽光望漸分。", "司天爲歲備，持簡出人羣。", "惠愛周微物，生靈荷聖君。", "長當有嘉瑞，郁郁復紛紛。"]'),
('a3a0e085-4365-4f29-bcf1-0b3b2ad336ab','贈別二首 一','柳郴','唐','唐诗','tang','','[]','江浦程千里，離尊淚數行。',24,'全唐诗/poet.tang.16000.json','["江浦程千里，離尊淚數行。", "無論吳與楚，俱是客他鄉。"]'),
('85bed92d-9dd4-4dbe-bda5-71b947320d5c','贈別二首 二','柳郴','唐','唐诗','tang','','[]','何處最悲辛，長亭臨古津。',24,'全唐诗/poet.tang.16000.json','["何處最悲辛，長亭臨古津。", "往來舟檝路，前後別離人。"]'),
('ac33036a-7a0b-44cb-bbc6-1362e9b53b62','句','柳郴','唐','唐诗','tang','','[]','他鄉生白髮，舊國有青山。',12,'全唐诗/poet.tang.16000.json','["他鄉生白髮，舊國有青山。"]'),
('63b9ffb4-4993-4fec-ab57-9276187a6e91','望終南春雪','李子卿','唐','唐诗','tang','','[]','山勢抱西秦，初年瑞雪頻。',72,'全唐诗/poet.tang.16000.json','["山勢抱西秦，初年瑞雪頻。", "色搖鶉野霽，影落鳳城春。", "輝燿銀峰逼，晶明玉樹親。", "尚寒由氣勁，不夜爲光新。", "荆岫全疑近，崑丘宛合鄰。", "餘輝儻可借，迴照讀書人。"]'),
('fb93e8b8-19cd-4586-a6d0-875ec3506a1d','九日登青山','朱灣','唐','唐诗','tang','','[]','昔人惆悵處，繫馬又登臨。',48,'全唐诗/poet.tang.16000.json','["昔人惆悵處，繫馬又登臨。", "舊地煙霞在，多時草木深。", "水將空合色，雲與我無心。", "想見龍山會，良辰亦似今。"]'),
('621d6001-ea93-4bce-adb6-7e085437f15f','秋夜宴王郎中宅賦得露中菊','朱灣','唐','唐诗','tang','','[]','衆芳春競發，寒菊露偏滋。',48,'全唐诗/poet.tang.16000.json','["衆芳春競發，寒菊露偏滋。", "受氣何曾異，開花獨自遲。", "晚成猶待賞，欲採未過時。", "忍棄東籬下，看隨秋草衰。"]'),
('dc9d8acc-dd78-45a2-a5dd-5e62eb3ca8ff','奉使設宴戲擲籠籌','朱灣','唐','唐诗','tang','','[]','今日陪樽俎，良籌復在茲。',48,'全唐诗/poet.tang.16000.json','["今日陪樽俎，良籌復在茲。", "獻酬君有禮，賞罰我無私。", "莫怪斜相向，還將正自持。", "一朝權入手，看取令行時。"]'),
('b6d41ea6-82ca-4be2-9c3a-844e62d5b573','詠雙陸骰子','朱灣','唐','唐诗','tang','','[]','采采應緣白，鑽心不爲名。',48,'全唐诗/poet.tang.16000.json','["采采應緣白，鑽心不爲名。", "掌中猶可重，手下莫言輕。", "有對唯求敵，無私直任爭。", "君看一擲後，當取擅場聲。"]'),
('3eb22f0f-865f-45e9-9c97-95715d6a495a','詠壁上酒瓢呈蕭明府','朱灣','唐','唐诗','tang','','[]','不是難提挈，行藏固有期。',48,'全唐诗/poet.tang.16000.json','["不是難提挈，行藏固有期。", "安身未得所，開口欲從誰。", "應物心無倦，當壚柄會持。", "莫將成廢器，還有對樽時。"]'),
('d8f97067-cf54-4f31-9b18-8aa489c9b4b3','詠玉','朱灣','唐','唐诗','tang','','[]','歌玉屢招疑，終朝省復思。',48,'全唐诗/poet.tang.16000.json','["歌玉屢招疑，終朝省復思。", "既哀黃鳥興，還復白圭詩。", "請益先求友，將行必擇師。", "誰知不鳴者，獨下董生帷。"]'),
('0af3c45d-ce51-428d-b68a-d1273339e102','送陳偃賦得白鳥翔翠微','朱灣','唐','唐诗','tang','','[]','不知鷗與鶴，天畔弄晴暉。',48,'全唐诗/poet.tang.16000.json','["不知鷗與鶴，天畔弄晴暉。", "背日分明見，臨川相暎微。", "淨中雲一點，回處雪孤飛。", "正好南枝住，翩翩何所歸。"]'),
('065ec7f4-bdf5-4012-bf73-d38328e1001b','題段上人院壁畫古松','朱灣','唐','唐诗','tang','','[]','石上盤古根，謂言天生有。',116,'全唐诗/poet.tang.16000.json','["石上盤古根，謂言天生有。", "安知草木性，變在畫師手。", "陰深方丈間，直趣幽且閑。", "木紋離披勢搓捽，中裂空心火燒出。", "掃成三寸五寸枝，便是千年萬年物。", "莓苔濃淡色不同，一面死皮生蠹蟲。", "風霜未必來到此，氣色杳在寒山中。", "孤標可玩不可取，能使支公道場古。"]'),
('4f4067b1-b822-4ef2-84d4-24f473b14178','逼寒節寄崔七','朱灣','唐','唐诗','tang','','[]','閑庭只是長莓苔，三徑曾無車馬來。',64,'全唐诗/poet.tang.16000.json','["閑庭只是長莓苔，三徑曾無車馬來。", "旅館尚愁寒食火，羈心嬾向不然灰。", "門前下客雖彈鋏，溪畔窮魚且曝腮。", "他日趨庭應問禮，須言陋巷有顏回。"]'),
('9c6325fe-fafd-4ed0-ba14-562b7e7ff760','長安喜雪','朱灣','唐','唐诗','tang','','[]','千門萬戶雪花浮，點點無聲落瓦溝。',64,'全唐诗/poet.tang.16000.json','["千門萬戶雪花浮，點點無聲落瓦溝。", "全似玉塵消更積，半成冰片結還流。", "光含曉色清天苑，輕逐微風遶御樓。", "平地已霑盈尺潤，年豐須荷富人侯。"]'),
('c77bab05-cc71-4bdd-ae62-d41d35d0792e','宴楊駙馬山亭','朱灣','唐','唐诗','tang','','[]','垂楊拂岸草茸茸，繡戶窗前花影重。',64,'全唐诗/poet.tang.16000.json','["垂楊拂岸草茸茸，繡戶窗前花影重。", "鱠下玉盤紅縷細，酒開金甕綠醅濃。", "中朝駙馬何平叔，南國詞人陸士龍。", "落日泛舟同醉處，回潭百丈映千峰。"]'),
('0ee73c58-cce4-4852-b95b-73ce2d12618e','過宣上人湖上蘭若','朱灣','唐','唐诗','tang','','[]','十年湖上結幽期，偏向東林遇遠師。',64,'全唐诗/poet.tang.16000.json','["十年湖上結幽期，偏向東林遇遠師。", "未道姓名童子識，不酬言語上人知。", "閑花落日滋苔徑，細雨和煙著柳枝。", "問我別來何所得，解將無事當無爲。"]'),
('38a81bbb-f8b7-41a8-a456-a5c1cd4ba4ea','同達奚宰遊竇子明仙壇','朱灣','唐','唐诗','tang','','[]','松檜陰深一徑微，中峰石室到人稀。',64,'全唐诗/poet.tang.16000.json','["松檜陰深一徑微，中峰石室到人稀。", "仙官不住青山在，故老相傳白日飛。", "華表問栽何歲木，片雲留著去時衣。", "今朝茂宰尋真處，暫駐雙鳧且莫歸。"]'),
('ecad5c4e-aaeb-4f85-bf79-036e6fe92b66','平陵寓居再逢寒食','朱灣','唐','唐诗','tang','','[]','幾迴江上泣途窮，每遇良辰歎轉蓬。',64,'全唐诗/poet.tang.16000.json','["幾迴江上泣途窮，每遇良辰歎轉蓬。", "火燧知從新節變，灰心還與故人同。", "莫聽黃鳥愁啼處，自有花開久客中。", "貧病固應無撓事，但將懷抱醉春風。"]'),
('24349e0b-7e0e-4ce2-9173-1550c7f8be81','尋隱者韋九山人於東溪草堂','朱灣','唐','唐诗','tang','','[]','尋得仙源訪隱淪，漸來深處漸無塵。',64,'全唐诗/poet.tang.16000.json','["尋得仙源訪隱淪，漸來深處漸無塵。", "初行竹裹唯通馬，直到花間始見人。", "四面雲山誰作主，數家煙火自爲鄰。", "路傍樵客何須問，朝市如今不是秦。"]'),
('78a5efb6-04b4-46ba-b030-8deb41e810d3','假攝池州留別東溪隱居','朱灣','唐','唐诗','tang','','[]','一官仍是假，豈願數離羣。',48,'全唐诗/poet.tang.16000.json','["一官仍是假，豈願數離羣。", "愁鬢看如雪，浮名認是雲。", "暫辭南國隱，莫勒北山文。", "今後松溪月，還應夢見君。"]'),
('152fef94-01eb-445c-b918-434d41891ab8','詠柏板','朱灣','唐','唐诗','tang','','[]','赴節心長在，從繩道可觀。',48,'全唐诗/poet.tang.16000.json','["赴節心長在，從繩道可觀。", "須知片木用，莫向散材看。", "空爲歌偏苦，仍愁和即難。", "既能親掌握，願得接同歡。"]'),
('c1315df6-abd2-433d-a297-763163959091','箏柱子','朱灣','唐','唐诗','tang','','[]','散木今何幸，良工不棄捐。',48,'全唐诗/poet.tang.16000.json','["散木今何幸，良工不棄捐。", "力微慙一柱，材薄仰羣弦。", "且喜聲相應，寧辭跡屢遷。", "知音如見賞，雅調爲君傳。"]'),
('b82ca5fb-1edb-4931-8c43-975a2a9ca0de','送李司直歸浙東幕兼寄鮑行軍持節大夫初拜東平郡王','朱灣','唐','唐诗','tang','','[]','翩翩書記早曾聞，二十年來願見君。',64,'全唐诗/poet.tang.16000.json','["翩翩書記早曾聞，二十年來願見君。", "今日相逢悲白髮，同時幾許在青雲。", "人從北固山邊去，水到西陵渡口分。", "會作王門曳裙客，爲余前謝鮑參軍。"]'),
('6197387a-f00c-48df-8812-d27213d7d543','七賢廟','朱灣','唐','唐诗','tang','','[]','常慕晉高士，放心日沈冥。',72,'全唐诗/poet.tang.16000.json','["常慕晉高士，放心日沈冥。", "湛然對一壺，土木爲我形。", "下馬訪陳迹，披榛詣荒庭。", "相看兩不言，猶謂醉未醒。", "長嘯或可擬，幽琴難再聽。", "同心不共世，空見蘚門青。"]'),
('6400a6ba-98f1-4bd0-8f53-402727624022','同清江師月夜聽堅正二上人爲懷州轉法華經歌','朱灣','唐','唐诗','tang','','[]','若耶谿畔雲門僧，夜閑燕坐聽真乘。',144,'全唐诗/poet.tang.16000.json','["若耶谿畔雲門僧，夜閑燕坐聽真乘。", "蓮花祕偈藥草喻，二師身住口不住。", "鑿井求泉會到源，閉門避火終迷路。", "前心後心皆此心，梵音妙音柔軟音。", "清泠霜磬有時動，寂歷空堂宜夜深。", "向來不寐何所事，一念纔生百慮息。", "風翻亂葉林有聲，雪映閑庭月無色。", "玄關密跡難可思，醒人悟兮醉人疑。", "衣中繫寶覺者誰，臨川內史字得之。"]'),
('8493b95e-28d1-475c-8db3-756f2e662cf1','寒城晚角','朱灣','唐','唐诗','tang','','[]','高臺高高畫角雄，五更初發寒城中。',188,'全唐诗/poet.tang.16000.json','["高臺高高畫角雄，五更初發寒城中。", "寒城北臨大河水，淇門賊烽隔岸是。", "長風送過黎陽川，我軍氣雄賊心死。", "羇人此夜寐不成，萬里邊情枕上生。", "乍似隴頭戍，寒泉幽咽流不住。", "又如巴江頭，啼猨帶雨斷續愁。", "忽憶嫖姚北征伐，空山宿兵寒對月。", "一聲老將起，三奏行人發。", "冀馬爲之嘶，朔雲爲之結。", "二十年來天下兵，到處不曾無此聲。", "洛陽陌，長安路。", "角聲朝朝兼暮暮，平居聞之尚難度。", "何況天山征戍兒，雲中下營雪裏吹。"]'),
('0693d540-58d0-4345-b184-4e42c4360903','重陽日陪韋卿讌','朱灣','唐','唐诗','tang','','[]','何必龍山好，南亭賞不暌。',48,'全唐诗/poet.tang.16000.json','["何必龍山好，南亭賞不暌。", "清規陳侯事，雅興謝公題。", "入座青峰近，當軒遠樹齊。", "仙家自有月，莫歎夕陽西。"]'),
('1b1b0bdf-4b31-4849-8637-382b1f3f0350','憶長安 四月','丘丹','唐','唐诗','tang','','[]','憶長安，四月時，南郊萬乘旌旗。',43,'全唐诗/poet.tang.16000.json','["憶長安，四月時，南郊萬乘旌旗。", "嘗酎玉巵更獻，含桃絲籠交馳。", "芳草落花無限，金張許史相隨。"]'),
('28970cea-caf4-4698-bc13-0560500b8235','狀江南 季冬','丘丹','唐','唐诗','tang','','[]','江南季冬月，紅蟹大如𤬊。',24,'全唐诗/poet.tang.16000.json','["江南季冬月，紅蟹大如𤬊。", "湖水龍爲鏡，爐峰氣作煙。"]'),
('9409e3c8-2fa4-4b6c-97c0-8de5e4d3cfec','和韋使君秋夜見寄','丘丹','唐','唐诗','tang','','[]','露滴梧葉鳴，秋風桂花發。',24,'全唐诗/poet.tang.16000.json','["露滴梧葉鳴，秋風桂花發。", "中有學仙侶，吹簫弄山月。"]'),
('f8d776d7-fdd3-4bb6-8a39-8806e79fa02f','奉酬韋蘇州使君','丘丹','唐','唐诗','tang','','[]','久作煙霞侶，蹔將簪組親。',24,'全唐诗/poet.tang.16000.json','["久作煙霞侶，蹔將簪組親。", "還同褚伯玉，入館忝州人。"]'),
('24d17590-1447-476d-9736-8f9f14c567f7','和韋使君聽江笛送陳侍御','丘丹','唐','唐诗','tang','','[]','離樽聞夜笛，寥亮入寒城。',24,'全唐诗/poet.tang.16000.json','["離樽聞夜笛，寥亮入寒城。", "月落車馬散，悽惻主人情。"]'),
('34e1ae2f-fc4d-4f48-aff3-3a4902f4e44b','奉酬韋使君送歸山之作','丘丹','唐','唐诗','tang','','[]','側聞郡守至，偶乘黃犢出。',84,'全唐诗/poet.tang.16000.json','["側聞郡守至，偶乘黃犢出。", "不別桃源人，一見經累日。", "蟬鳴念秋稼，蘭酌動離瑟。", "臨水降麾幢，野艇纔容膝。", "參差碧山路，目送江帆疾。", "涉海得驪珠，棲梧慚鳳質。", "媿非鄭公里，歸掃蒙籠室。"]'),
('80f04f2b-da28-4c7b-8015-f9e6c11d3400','奉酬重送歸山','丘丹','唐','唐诗','tang','','[]','賣藥有時至，自知來往疎。',48,'全唐诗/poet.tang.16000.json','["賣藥有時至，自知來往疎。", "遽辭池上酌，新得山中書。", "步出芙蓉府，歸乘觳𧥆車。", "猥蒙招隱作，豈愧班生廬。"]'),
('7317a3f9-118f-401d-bc47-70f328d6341f','經湛長史草堂','丘丹','唐','唐诗','tang','','[]','身退謝名累，道存嘉止足。',72,'全唐诗/poet.tang.16000.json','["身退謝名累，道存嘉止足。", "設醴降華幡，挂冠守空谷。", "偶尋野外寺，仰慕賢者躅。", "不見昔簪裾，猶有舊松竹。", "煙霞雖異世，風韻如在矚。", "余即江海上，歸轍青山曲。"]'),
('de8e8337-42e1-40c9-9cb6-0f846b1fb014','蕭山祗園寺','丘丹','唐','唐诗','tang','','[]','東晉許徴君，西方彥上人。',72,'全唐诗/poet.tang.16000.json','["東晉許徴君，西方彥上人。", "生時猶定見，悟後了前因。", "靈塔多年古，高僧苦行頻。", "碑存纔記日，藤老豈知春。", "車騎歸蕭詧，雲林識許詢。", "千秋不相見，悟定是吾身。"]'),
('b08883e7-d43b-45fd-9c1d-b770b8e8bbdf','奉使過石門觀瀑','丘丹','唐','唐诗','tang','','[]','溪上望懸泉，耿耿雲中見。',132,'全唐诗/poet.tang.16000.json','["溪上望懸泉，耿耿雲中見。", "披榛上巖岫，峭壁正東面。", "千仞瀉聯珠，一潭噴飛霰。", "嵯𤄓滿山響，坐覺炎氛變。", "照日類虹霓，從風似綃練。", "靈奇既天造，惜處窮海甸。", "吾祖昔登臨，謝公亦遊衍。", "王程懼淹泊，下磴空延眷。", "千里雷尚聞，巒迴樹葱蒨。", "此來共賤役，探討愧前彥。", "永欲洗塵纓，終當愜此願。"]'),
('c67ab0b3-dea9-4b02-ab62-cae441b1d4a9','秋夕宿石門館','丘丹','唐','唐诗','tang','','[]','暝從石門宿，搖落四巖空。',48,'全唐诗/poet.tang.16000.json','["暝從石門宿，搖落四巖空。", "潭月漾山足，天河瀉澗中。", "杉松寒似雨，猨鳥夕驚風。", "獨臥不成寢，蒼然想謝公。"]'),
('cc6dd58f-c26e-4f48-8b0c-cb5d5eb49f7f','狀江南 孟夏','賈弇','唐','唐诗','tang','','[]','江南孟夏天，慈竹笋如編。',24,'全唐诗/poet.tang.16000.json','["江南孟夏天，慈竹笋如編。", "蜃氣爲樓閣，蛙聲作管弦。"]'),
('1cc46db5-4610-4109-b1b4-ff6e2c70ee06','狀江南 仲秋','沈仲昌','唐','唐诗','tang','','[]','江南仲秋天，鱏鼻大如船。',24,'全唐诗/poet.tang.16000.json','["江南仲秋天，鱏鼻大如船。", "雷是樟亭浪，苔爲界石錢。"]'),
('51c14574-7598-43a3-a8de-e7f95678f9d9','憶長安 正月','謝良輔','唐','唐诗','tang','','[]','憶長安，正月時，和風喜氣相隨。',43,'全唐诗/poet.tang.16000.json','["憶長安，正月時，和風喜氣相隨。", "獻壽彤庭萬國，燒燈青玉五枝。", "終南往往殘雪，渭水處處流澌。"]'),
('63ea4166-22f6-4640-b23d-06dc648c56f4','憶長安 十二月','謝良輔','唐','唐诗','tang','','[]','憶長安，臘月時，溫泉彩仗新移。',43,'全唐诗/poet.tang.16000.json','["憶長安，臘月時，溫泉彩仗新移。", "瑞氣遙迎鳳輦，日光先暖龍池。", "取酒蝦蟇陵下，家家守歲傳巵。"]'),
('3a073cbe-3531-40a9-97f6-4a0d5ffddb84','狀江南 仲春','謝良輔','唐','唐诗','tang','','[]','江南仲春天，細雨色如煙。',24,'全唐诗/poet.tang.16000.json','["江南仲春天，細雨色如煙。", "絲爲武昌柳，布作石門泉。"]'),
('31cf12a5-51a2-4d42-9673-e110a4824fd8','狀江南 孟冬','謝良輔','唐','唐诗','tang','','[]','江南孟冬天，荻穗軟如綿。',24,'全唐诗/poet.tang.16000.json','["江南孟冬天，荻穗軟如綿。", "綠絹芭蕉裂，黃金橘柚懸。"]'),
('e4bc93c8-417d-4670-8fc0-ca28d3fa3bf8','憶長安 二月','鮑防','唐','唐诗','tang','','[]','憶長安，二月時，玄鳥初至禖祠。',43,'全唐诗/poet.tang.16000.json','["憶長安，二月時，玄鳥初至禖祠。", "百囀宮鶯繡羽，千條御柳黃絲。", "更有曲江勝地，此來寒食佳期。"]'),
('de1862c8-278a-40c6-90b8-9106cdb379bc','狀江南 孟春','鮑防','唐','唐诗','tang','','[]','江南孟春天，荇葉大如錢。',26,'全唐诗/poet.tang.16000.json','["江南孟春天，荇葉大如錢。", "白[雪]裝梅樹，青袍似葑田。"]'),
('c4a21fba-29eb-4fe6-a426-05ef19f72c13','雜感','鮑防','唐','唐诗','tang','','[]','漢家海內承平久，萬國戎王皆稽首。',96,'全唐诗/poet.tang.16000.json','["漢家海內承平久，萬國戎王皆稽首。", "天馬常銜苜蓿花，胡人歲獻葡萄酒。", "五月荔枝初破顏，朝離象郡夕函關。", "鴈飛不到桂陽嶺，馬走先過林邑山。", "甘泉御果垂仙閣，日暮無人香自落。", "遠物皆重近皆輕，雞雖有德不如鶴。"]'),
('3951b5a2-207b-4dfe-a5d8-1dee23c1ffde','送薛補闕入朝','鮑防','唐','唐诗','tang','','[]','平原門下十餘人，獨受恩多未殺身。',64,'全唐诗/poet.tang.16000.json','["平原門下十餘人，獨受恩多未殺身。", "每歎陸家兄弟少，更憐楊氏子孫貧。", "柴門豈斷施行馬，魯酒那堪醉近臣。", "賴有軍中遺令在，猶將談笑對風塵。"]'),
('6507a20e-2fa3-47d6-ad95-9fc4bde194d6','人日陪宣州范中丞傳正與范侍御傳真宴東峰亭','鮑防','唐','唐诗','tang','','[]','人日春風綻早梅，謝家兄弟看花來。',64,'全唐诗/poet.tang.16000.json','["人日春風綻早梅，謝家兄弟看花來。", "吳姬對酒歌千曲，秦女留人酒百杯。", "絲柳向空輕婉轉，玉山看日漸裴回。", "流光易去懽難得，莫厭頻頻上此臺。"]'),
('76cc99b7-c628-4f69-9855-4ebfc338b15c','上巳寄孟中丞','鮑防','唐','唐诗','tang','','[]','世間禊事風流處，鏡裏雲山若畫屏。',32,'全唐诗/poet.tang.16000.json','["世間禊事風流處，鏡裏雲山若畫屏。", "今日會稽王內史，好將賓客醉蘭亭。"]'),
('4e409fd6-6f44-40e3-82b0-3c0fb1f146ef','秋暮憶中秋夜與王璠侍御賞月因愴遠離聊以奉寄','鮑防','唐','唐诗','tang','','[]','前月月明夜，美人同遠光。',36,'全唐诗/poet.tang.16000.json','["前月月明夜，美人同遠光。", "清塵一以間，今夕坐相忘。", "風落芙蓉露，疑餘繡被香。"]'),
('8bf33f8b-b4a5-4cf1-8140-ddbb47cd1fed','元日早朝行','鮑防','唐','唐诗','tang','','[]','乾元發生春爲宗，盛德在木斗建東。',144,'全唐诗/poet.tang.16000.json','["乾元發生春爲宗，盛德在木斗建東。", "東方歲星大明宮，南山喜氣搖晴空。", "望雲五等舞萬玉，獻壽一聲出千峰。", "文昌隨彩禮樂正，太平下直旌旗紅。", "師曠應律調黃鍾，王良運策調時龍。", "玄冥無事歸朔土，青帝放身入朱宮。", "九韶九變五聲裏，四方四友一身中。", "天何言哉樂無窮，廣成彭祖爲三公。", "野臣潛隨擊壤老，日下鼓腹歌可封。"]'),
('2fff3942-620d-4197-a5aa-6693fc7a573d','憶長安 三月','杜奕','唐','唐诗','tang','','[]','憶長安，三月時，上苑遍是花枝。',43,'全唐诗/poet.tang.16000.json','["憶長安，三月時，上苑遍是花枝。", "青門幾場送客，曲水竟日題詩。", "駿馬金鞭無數，良辰美景追隨。"]'),
('5d3374bc-daa8-4ca0-a0f0-38137a7ea593','憶長安 六月','鄭概','唐','唐诗','tang','','[]','憶長安，六月時，風臺水榭逶迤。',43,'全唐诗/poet.tang.16000.json','["憶長安，六月時，風臺水榭逶迤。", "朱果雕籠香透，分明紫禁寒隨。", "塵驚九衢客散，赭珂滴瀝青驪。"]'),
('9c0f48ee-13f1-4e4a-a763-effe08e90998','狀江南 孟秋','鄭概','唐','唐诗','tang','','[]','江南孟秋天，稻花白如氈。',24,'全唐诗/poet.tang.16000.json','["江南孟秋天，稻花白如氈。", "素腕慙新藕，殘妝妒晚蓮。"]'),
('c51ebd5d-f16d-4042-963f-b1ff984d8689','憶長安 七月','陳元初','唐','唐诗','tang','','[]','憶長安，七月時，槐花點散罘罳。',43,'全唐诗/poet.tang.16000.json','["憶長安，七月時，槐花點散罘罳。", "七夕針樓競出，中元香供初移。", "繡轂金鞍無限，遊人處處歸遲。"]'),
('8504f827-22c0-467b-9a22-a8650192fa63','憶長安 八月','呂渭','唐','唐诗','tang','','[]','憶長安，八月時，闕下天高舊儀。',43,'全唐诗/poet.tang.16000.json','["憶長安，八月時，闕下天高舊儀。", "衣冠共頒金鏡，犀象對舞丹墀。", "更愛終南灞上，可憐秋草碧滋。"]'),
('0031a2e1-8915-43dc-9dfc-eb641d55443d','狀江南 仲冬','呂渭','唐','唐诗','tang','','[]','江南仲冬天，紫蔗節如鞭。',24,'全唐诗/poet.tang.16000.json','["江南仲冬天，紫蔗節如鞭。", "海將鹽作雪，山用火耕田。"]'),
('3723cad1-60e6-4700-a4fa-a147346c7bd9','貞元十一年知貢舉撓閣不能定去留寄詩前主司','呂渭','唐','唐诗','tang','','[]','獨坐貢闈裏，愁多芳草生。',24,'全唐诗/poet.tang.16000.json','["獨坐貢闈裏，愁多芳草生。", "仙翁昨日事，應見此時情。"]'),
('e3c9d99b-f48a-44fa-9e0d-4034c3c4c0f6','皇帝移晦日爲中和節','呂渭','唐','唐诗','tang','','[]','皇心不向晦，改節號中和。',72,'全唐诗/poet.tang.16000.json','["皇心不向晦，改節號中和。", "淑氣同風景，嘉名別詠歌。", "湔裙移舊俗，賜尺下新科。", "曆象千年正，酺醵四海多。", "花隨春令發，鴻度歲陽過。", "天地齊休慶，歡聲欲盪波。"]'),
('6417fb43-b5ae-40c9-8ab4-e743e85a7ea1','經湛長史草堂','呂渭','唐','唐诗','tang','','[]','巖居舊風景，人世今成昔。',72,'全唐诗/poet.tang.16000.json','["巖居舊風景，人世今成昔。", "木落古山空，猨啼秋月白。", "誰同西府僚，幾謝南平客。", "摧殘松桂老，蕭散煙雲夕。", "跡留異代遠，境入空門寂。", "惟有草堂僧，陳詩在石壁。"]'),
('eef69c91-a8a9-47fb-9bb6-d6f2aba3c387','憶長安 九月','范燈','唐','唐诗','tang','','[]','憶長安，九月時，登高望見昆池。',45,'全唐诗/poet.tang.16000.json','["憶長安，九月時，登高望見昆池。", "上苑初開露菊，芳林正獻霜梨。", "更想千門萬戶，[月]明砧杵參差。"]'),
('40e4f634-6e6b-4df8-a9d4-f3a52233b7a0','狀江南 季夏','范燈','唐','唐诗','tang','','[]','江南季夏天，身熱汗如泉。',24,'全唐诗/poet.tang.16000.json','["江南季夏天，身熱汗如泉。", "蚊蚋成雷澤，袈裟作水田。"]'),
('9a38ce26-2b37-4151-888b-3b7f78acafcb','憶長安 十月','樊珣','唐','唐诗','tang','','[]','憶長安，十月時，華清士馬相馳。',43,'全唐诗/poet.tang.16000.json','["憶長安，十月時，華清士馬相馳。", "萬國來朝漢闕，五陵共獵秦祠。", "晝夜歌鐘不歇，山河四塞京師。"]'),
('86660317-2190-484f-86b1-c8b429cadbdb','狀江南 仲夏','樊珣','唐','唐诗','tang','','[]','江南仲夏天，時雨下如川。',24,'全唐诗/poet.tang.16000.json','["江南仲夏天，時雨下如川。", "盧橘垂金彈，甘蕉吐白蓮。"]'),
('ac63c877-c425-4d01-93f7-a718859a403f','憶長安 十一月','劉蕃','唐','唐诗','tang','','[]','憶長安，子月時，千官賀至丹墀。',43,'全唐诗/poet.tang.16000.json','["憶長安，子月時，千官賀至丹墀。", "御苑雪開瓊樹，龍堂冰作瑤池。", "獸炭氈爐正好，貂裘狐白相宜。"]'),
('962103e4-47c6-462a-801b-cd981024217b','狀江南 季秋','劉蕃','唐','唐诗','tang','','[]','江南季秋天，栗熟大如拳。',24,'全唐诗/poet.tang.16000.json','["江南季秋天，栗熟大如拳。", "楓葉紅霞舉，蒼蘆白浪川。"]'),
('541a9811-acd4-41b2-95b9-cf9a63e9e4e9','太寥歌','張志和','唐','唐诗','tang','','[]','化元靈哉，碧虛清哉。',28,'全唐诗/poet.tang.16000.json','["化元靈哉，碧虛清哉。", "紅霞明哉，冥哉茫哉，惟化之工無彊哉。"]'),
('705adb8f-f174-4221-8bdb-a2efd0e16b68','空洞歌','張志和','唐','唐诗','tang','','[]','無自而然，自然之元。',44,'全唐诗/poet.tang.16000.json','["無自而然，自然之元。", "無造而化，造化之端。", "廓然慤然，其形團圞。", "反爾之視，絕爾之思，可以觀。"]'),
('0c7f80dd-29e4-4c72-b4b5-f967aa52b51a','漁父歌 一','張志和','唐','唐诗','tang','','["\u5c71\u6c34", "\u5199\u666f", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u56db\u5e74\u7ea7\u4e0b\u518c", "\u5199\u4eba", "\u6292\u6000"]','西塞山前白鷺飛，桃花流水鱖魚肥。',32,'全唐诗/poet.tang.16000.json','["西塞山前白鷺飛，桃花流水鱖魚肥。", "青篛笠，綠簑衣，斜風細雨不須歸。"]'),
('e8f030b1-9e72-4243-92b3-3c4ec8028354','漁父歌 二','張志和','唐','唐诗','tang','','["\u957f\u6c5f"]','釣臺漁父褐爲裘，兩兩三三舴艋舟。',32,'全唐诗/poet.tang.16000.json','["釣臺漁父褐爲裘，兩兩三三舴艋舟。", "能縱櫂，慣乘流，長江白浪不曾憂。"]'),
('2e99fd87-77f9-42d7-af47-1a845e2e865d','漁父歌 三','張志和','唐','唐诗','tang','','[]','霅谿灣裏釣漁翁，舴艋爲家西復東。',32,'全唐诗/poet.tang.16000.json','["霅谿灣裏釣漁翁，舴艋爲家西復東。", "江上雪，浦邊風，笑著荷衣不歎窮。"]'),
('29005e2b-3311-40df-a3b8-5ff8455bc4af','漁父歌 四','張志和','唐','唐诗','tang','','[]','松江蟹舍主人歡，菰飯蓴羹亦共餐。',32,'全唐诗/poet.tang.16000.json','["松江蟹舍主人歡，菰飯蓴羹亦共餐。", "楓葉落，荻花乾，醉宿漁舟不覺寒。"]'),
('bdb3235d-6261-4b85-b5f5-53fc016942c3','漁父歌 五','張志和','唐','唐诗','tang','','[]','青草湖中月正圓，巴陵漁父櫂歌連。',32,'全唐诗/poet.tang.16000.json','["青草湖中月正圓，巴陵漁父櫂歌連。", "釣車子，橛頭船，樂在風波不用仙。"]'),
('58ed2f11-d26c-47bf-8daa-02eb522da5f1','上巳日憶江南禊事','張志和','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河西繞郡城流，上巳應無祓禊遊。',32,'全唐诗/poet.tang.16000.json','["黃河西繞郡城流，上巳應無祓禊遊。", "爲憶淥江春水色，更隨宵夢向吳洲。"]'),
('0d6eed96-a408-4c95-9d9a-fc1ba93675fc','漁父','張志和','唐','唐诗','tang','','[]','八月九月蘆花飛，南谿老人垂釣歸。',64,'全唐诗/poet.tang.16000.json','["八月九月蘆花飛，南谿老人垂釣歸。", "秋山入簾翠滴滴，野艇倚檻雲依依。", "却把漁竿尋小徑，閑梳鶴髮對斜暉。", "翻嫌四皓曾多事，出爲儲皇定是非。"]'),
('6bb1ee39-265a-4c53-a5b4-311b2e65429c','和荅弟志和漁父歌','張松齡','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','樂是風波釣是閑，草堂松徑已勝攀。',32,'全唐诗/poet.tang.16000.json','["樂是風波釣是閑，草堂松徑已勝攀。", "太湖水，洞庭山，狂風浪起且須還。"]'),
('392696d5-0270-4db7-9f78-a7a6dfc442fb','歌','陸羽','唐','唐诗','tang','','["\u957f\u6c5f"]','不羨黃金罍，不羨白玉杯。',38,'全唐诗/poet.tang.16000.json','["不羨黃金罍，不羨白玉杯。", "不羨朝入省，不羨暮入臺。", "惟羨西江水，曾向金陵城下來。"]'),
('a7055ca5-213d-41d4-81f9-dba64d953e44','會稽東小山','陸羽','唐','唐诗','tang','','[]','月色寒潮入剡溪，青猨叫斷綠林西。',32,'全唐诗/poet.tang.16000.json','["月色寒潮入剡溪，青猨叫斷綠林西。", "昔人已逐東流去，空見年年江草齊。"]'),
('19812eab-6755-48b9-8c14-f44ce2d3ee14','句','陸羽','唐','唐诗','tang','','[]','辟彊舊林間，怪石紛相向。',36,'全唐诗/poet.tang.16000.json','["辟彊舊林間，怪石紛相向。", "絕澗方險尋，亂巖亦危造。", "瀉從千仞石，寄逐九江船。"]'),
('fadd4ab1-6b70-4a7b-b9b5-4190edae96e0','寒食寄李補闕','郭鄖','唐','唐诗','tang','','[]','蘭陵士女滿晴川，郊外紛紛拜古埏。',64,'全唐诗/poet.tang.16000.json','["蘭陵士女滿晴川，郊外紛紛拜古埏。", "萬井閭閻皆禁火，九原松柏自生煙。", "人間後事悲前事，鏡裏今年老去年。", "介子終知祿不及，王孫誰肯一相憐。"]'),
('12cdc618-7a5f-4cb3-9607-46025a48c467','仲月賞花','韋同則','唐','唐诗','tang','','[]','梅花似雪柳含煙，南地風光臘月前。',32,'全唐诗/poet.tang.16000.json','["梅花似雪柳含煙，南地風光臘月前。", "把酒且須拼却醉，風流何必待歌筵。"]'),
('ff30dedd-92e7-47eb-8241-751240f036fc','西亭暇日書懷十二韻獻上相公','李夷簡','唐','唐诗','tang','','[]','勝賞不在遠，憮然念玄搜。',144,'全唐诗/poet.tang.16000.json','["勝賞不在遠，憮然念玄搜。", "茲亭有殊致，經始富人侯。", "澄澹分沼沚，縈迴間林丘。", "荷香奪芳麝，石溜當鳴球。", "撫俗來康濟，經邦去咨謀。", "寬明洽時論，惠愛聞甿謳。", "代斵豈容易，守成獲優游。", "文翁舊學校，子產昔田疇。", "琬琰富佳什，池臺想舊遊。", "誰言矜改作，曾是日增修。", "憲省忝陪屬，岷峨嗣徽猷。", "提攜當有路，勿使滯刀州。"]'),
('43c2e197-20d6-4ed6-bef0-972b05d1dd41','城南訪裴氏昆季','李約','唐','唐诗','tang','','[]','相思起中夜，夙駕訪柴荆。',120,'全唐诗/poet.tang.16000.json','["相思起中夜，夙駕訪柴荆。", "早霧桑柘隱，曉光溪澗明。", "村蹊嵩棘間，往往斷新耕。", "貧野煙火微，晝無烏鳶聲。", "田頭逢餉人，道君南山行。", "南山千里峰，盡是相思情。", "野老無拜揖，村童多躶形。", "相呼看車馬，顏色喜相驚。", "荒圃雞豚樂，雨牆禾莠生。", "欲君知我來，壁上空書名。"]'),
('64a346ea-e5ce-4b81-bd99-06ad50239f5b','歲日感懷','李約','唐','唐诗','tang','','[]','曙氣變東風，蟾壺夜漏窮。',48,'全唐诗/poet.tang.16000.json','["曙氣變東風，蟾壺夜漏窮。", "新春幾人老，舊曆四時空。", "身賤悲添歲，家貧喜過冬。", "稱觴惟有感，歡慶在兒童。"]'),
('eec52107-44eb-48eb-a47d-7f34277bea28','從軍行三首 一','李約','唐','唐诗','tang','','[]','看圖閑敎陣，畫地靜論邊。',48,'全唐诗/poet.tang.16000.json','["看圖閑敎陣，畫地靜論邊。", "烏壘天西戍，鷹姿塞上川。", "路長唯算月，書遠每題年。", "無復生還望，翻思未別前。"]'),
('d400b97d-e36d-48a5-98c2-33db274c5ddd','從軍行三首 二','李約','唐','唐诗','tang','','[]','柵壕三面鬬，箭盡舉烽頻。',48,'全唐诗/poet.tang.16000.json','["柵壕三面鬬，箭盡舉烽頻。", "營柳和煙暮，關榆帶雪春。", "邊城多老將，磧路少歸人。", "殺盡金河卒，年年添塞塵。"]'),
('4557894f-a024-44af-936c-f758cac66b46','從軍行三首 三','李約','唐','唐诗','tang','','[]','候火起雕城，塵沙擁戰聲。',48,'全唐诗/poet.tang.16000.json','["候火起雕城，塵沙擁戰聲。", "遊軍藏漢幟，降騎說蕃情。", "霜落滹沱淺，秋深太白明。", "嫖姚方虎視，不覺說添兵。"]'),
('bbc4bedf-3a8a-4405-a241-2f4257a1cc08','贈韋況','李約','唐','唐诗','tang','','[]','我有心中事，不與韋三說。',24,'全唐诗/poet.tang.16000.json','["我有心中事，不與韋三說。", "秋夜洛陽城，明月照張八。"]'),
('16e63d97-a2df-4388-ae70-66e0deb0ab91','觀祈雨','李約','唐','唐诗','tang','','[]','桑條無葉土生煙，簫管迎龍水廟前。',32,'全唐诗/poet.tang.16000.json','["桑條無葉土生煙，簫管迎龍水廟前。", "朱門幾處看歌舞，猶恐春陰咽管弦。"]'),
('68e248c2-7de3-4f95-8f78-aef6c5e3d5a5','江南春','李約','唐','唐诗','tang','','[]','池塘春暖水紋開，堤柳垂絲間野梅。',32,'全唐诗/poet.tang.16000.json','["池塘春暖水紋開，堤柳垂絲間野梅。", "江上年年芳意早，蓬瀛春色逐潮來。"]'),
('d90c99e0-b50a-48e1-8331-e1539d86ceab','過華清宮','李約','唐','唐诗','tang','','[]','君王遊樂萬機輕，一曲霓裳四海兵。',32,'全唐诗/poet.tang.16000.json','["君王遊樂萬機輕，一曲霓裳四海兵。", "玉輦升天人已盡，故宮猶有樹長生。"]'),
('ac059717-856b-4e9c-8ab8-af17dbcf47a3','病中宿宜陽館聞雨','李約','唐','唐诗','tang','','[]','難眠夏夜抵秋賒，簾幔深垂窗燭斜。',32,'全唐诗/poet.tang.16000.json','["難眠夏夜抵秋賒，簾幔深垂窗燭斜。", "風吹桐竹更無雨，白髮病人心到家。"]'),
('97546486-e401-4b60-9983-154f784155d3','江南曲','于鵠','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50", "\u90ca\u6e38"]','偶向江邊採白蘋，還隨女伴賽江神。',32,'全唐诗/poet.tang.16000.json','["偶向江邊採白蘋，還隨女伴賽江神。", "衆中不敢分明語，暗擲金錢卜遠人。"]'),
('9c0a394a-59fb-4008-9f92-bf6d247be4c6','山中寄樊僕射','于鵠','唐','唐诗','tang','','[]','却憶東溪日，同年事魯儒。',48,'全唐诗/poet.tang.16000.json','["却憶東溪日，同年事魯儒。", "僧房閑共宿，酒肆醉相扶。", "天畔雙旌貴，山中病客孤。", "無謀還有計，春谷種桑榆。"]'),
('6f485ea0-1ba6-4f56-9962-7ca4c3054745','題宇文𧚞山寺讀書院','于鵠','唐','唐诗','tang','','[]','讀書林下寺，不出動經年。',48,'全唐诗/poet.tang.16000.json','["讀書林下寺，不出動經年。", "草閣連僧院，山廚共石泉。", "雲庭無履跡，龕壁有燈煙。", "年少今頭白，刪詩到幾篇。"]'),
('eac82df3-36cd-412c-8144-337ce181f63b','贈蘭若僧','于鵠','唐','唐诗','tang','','[]','一身禪誦苦，灑掃古花宮。',48,'全唐诗/poet.tang.16000.json','["一身禪誦苦，灑掃古花宮。", "靜室門常閉，深蘿月不通。", "懸燈喬木上，鳴磬亂幡中。", "附入高僧傳，長稱二遠公。"]'),
('c09e987d-f376-467e-a435-326368f3eb13','題鄰居','于鵠','唐','唐诗','tang','','["\u751f\u6d3b", "\u53cb\u60c5"]','僻巷鄰家少，茅簷喜竝居。',48,'全唐诗/poet.tang.16000.json','["僻巷鄰家少，茅簷喜竝居。", "蒸梨常共竈，澆薤亦同渠。", "傳屐朝尋藥，分燈夜讀書。", "雖然在城市，還得似樵漁。"]'),
('ec973ae2-f409-4701-8ae2-7cc2abb850b2','山中自述','于鵠','唐','唐诗','tang','','[]','三十無名客，空山獨臥秋。',48,'全唐诗/poet.tang.16000.json','["三十無名客，空山獨臥秋。", "病多知藥性，年長信人愁。", "螢影竹窗下，松聲茅屋頭。", "近來心更靜，不夢世間遊。"]'),
('2e0a488f-bbd7-4558-852e-55314a431d5a','山中寄韋鉦','于鵠','唐','唐诗','tang','','[]','嬾成身病日，因醉臥多時。',48,'全唐诗/poet.tang.16000.json','["嬾成身病日，因醉臥多時。", "送客出谿少，讀書終卷遲。", "幽窗聞墜葉，晴景見遊絲。", "早晚來收藥，門前有紫芝。"]'),
('4582417a-dd1a-46fd-aada-337888556a06','南谿書齋','于鵠','唐','唐诗','tang','','[]','茅屋往來久，山深不置門。',48,'全唐诗/poet.tang.16000.json','["茅屋往來久，山深不置門。", "草生垂井口，花落擁籬根。", "入院將雛鳥，尋蘿抱子猿。", "曾逢異人說，風景似桃源。"]'),
('1a9a0a42-3109-4d0a-bd07-d8557137e0a7','夜會李太守宅','于鵠','唐','唐诗','tang','','[]','郡齋常夜埽，不臥獨吟詩。',48,'全唐诗/poet.tang.16000.json','["郡齋常夜埽，不臥獨吟詩。", "把燭近幽客，升堂戴接䍦。", "微風吹凍葉，餘雪落寒枝。", "明日逢山伴，須令隱者知。"]'),
('d76b40cc-adeb-46a5-a7a9-174ef98e6af5','題柏臺山僧','于鵠','唐','唐诗','tang','','[]','上方唯一室，禪定對山容。',48,'全唐诗/poet.tang.16000.json','["上方唯一室，禪定對山容。", "行道臨孤壁，持齋聽遠鐘。", "枯藤離舊樹，朽石落高峰。", "不向雲間見，還應夢裏逢。"]'),
('c9747409-7db3-4600-8a85-90465a503b29','寄續尊師','于鵠','唐','唐诗','tang','','[]','得道任髮白，亦逢城市遊。',48,'全唐诗/poet.tang.16000.json','["得道任髮白，亦逢城市遊。", "新經天上取，稀藥洞中收。", "春木帶枯葉，新蒲生漫流。", "年年望靈鶴，常在此山頭。"]'),
('20a02018-3e6e-41df-bb28-6b901e047213','題南峰褚道士','于鵠','唐','唐诗','tang','','[]','得道南山久，曾敎四皓碁。',48,'全唐诗/poet.tang.16000.json','["得道南山久，曾敎四皓碁。", "閉門醫病鶴，倒篋養神龜。", "松際風長在，泉中草不衰。", "誰知茅屋裏，有路向峨嵋。"]'),
('2e31b486-7ec0-4af4-b137-4df1262b2b57','贈不食姑','于鵠','唐','唐诗','tang','','[]','不食非關藥，天生是女仙。',48,'全唐诗/poet.tang.16000.json','["不食非關藥，天生是女仙。", "見人還起拜，留伴亦開田。", "無窟尋溪宿，兼衣掃葉眠。", "不知何代女，猶帶剪刀錢。"]'),
('f8bc9e50-ee3c-4874-8081-f27d69cf217d','送李明府歸別業','于鵠','唐','唐诗','tang','','[]','寄家丹水邊，歸去種春田。',48,'全唐诗/poet.tang.16000.json','["寄家丹水邊，歸去種春田。", "白髮無知己，空山又一年。", "鹿裘長酒氣，茅屋有茶煙。", "亦擬辭人世，何溪有瀑泉。"]'),
('821b3cad-6a18-4404-b54a-b105e4d89faa','題樹下禪師','于鵠','唐','唐诗','tang','','[]','久行多不定，樹下是禪牀。',48,'全唐诗/poet.tang.16000.json','["久行多不定，樹下是禪牀。", "寂寂心無住，年年日自長。", "蟲虵同宿磵，草木共經霜。", "已見南人說，天台有舊房。"]'),
('ed50304d-9bf0-4f49-bde3-05efe0c27752','宿王尊師隱居','于鵠','唐','唐诗','tang','','[]','夜愛雲林好，寒天月裏行。',48,'全唐诗/poet.tang.16000.json','["夜愛雲林好，寒天月裏行。", "青牛眠樹影，白犬吠猨聲。", "一磬山院靜，千燈谿路明。", "從來此峰客，幾箇得長生。"]'),
('58156c74-4d4c-4371-9ad5-381c3fb80bc8','題服柏先生','于鵠','唐','唐诗','tang','','[]','服柏不飛鍊，閑眠閉草堂。',48,'全唐诗/poet.tang.16000.json','["服柏不飛鍊，閑眠閉草堂。", "有泉唯盥漱，留火爲焚香。", "新雨閑門靜，孤松滿院涼。", "仍聞枕中術，曾授漢淮王。"]'),
('47454354-f2b9-4e03-8a7b-d649ec119bf1','哭凌霄山光上人','于鵠','唐','唐诗','tang','','[]','身沒碧峰裏，門人改葬期。',48,'全唐诗/poet.tang.16000.json','["身沒碧峰裏，門人改葬期。", "買山尋主遠，壘塔化人遲。", "鬼火穿空院，秋螢入素帷。", "黃昏溪路上，聞哭竺乾師。"]'),
('51af5465-00b8-4607-ae23-330377379608','途中寄楊涉','于鵠','唐','唐诗','tang','','[]','蕭蕭蘆荻晚，一逕入荒陂。',48,'全唐诗/poet.tang.16000.json','["蕭蕭蘆荻晚，一逕入荒陂。", "日色雲收處，蛙聲雨歇時。", "前村見來久，羸馬自行遲。", "聞作王門客，應閑白接䍦。"]'),
('1efbe2fa-7b61-4bb7-b74c-180e2dc76acb','送韋判官歸薊門','于鵠','唐','唐诗','tang','','[]','桑乾歸路遠，聞說亦愁人。',48,'全唐诗/poet.tang.16000.json','["桑乾歸路遠，聞說亦愁人。", "有雪常經夏，無花空到春。", "下營雲外火，收馬月中塵。", "白首從戎客，青衫未離身。"]'),
('b23be228-4d1f-4ef9-aef5-c069a1d5b803','出塞 一','于鵠','唐','唐诗','tang','','[]','葱嶺秋塵起，全軍取月支。',48,'全唐诗/poet.tang.16000.json','["葱嶺秋塵起，全軍取月支。", "山川引行陣，蕃漢列旌旗。", "轉戰疲兵少，孤城外救遲。", "邊人逢聖代，不見偃戈時。"]'),
('1ee270d5-6ce9-4e1c-8ede-f71467d88dc9','出塞 二','于鵠','唐','唐诗','tang','','[]','微雪軍將出，吹笳天未明。',48,'全唐诗/poet.tang.16000.json','["微雪軍將出，吹笳天未明。", "觀兵登古戍，斬將對雙旌。", "分陣瞻山勢，潛兵制馬鳴。", "如今青史上，已有滅胡名。"]'),
('ffb4a57d-fbd9-4210-82e9-070e0dfd80a4','出塞 三','于鵠','唐','唐诗','tang','','[]','單于驕愛獵，放火到軍城。',48,'全唐诗/poet.tang.16000.json','["單于驕愛獵，放火到軍城。", "乘月調新馬，防秋置遠營。", "空山朱戟影，寒磧鐵衣聲。", "度水逢胡說，沙陰有伏兵。"]'),
('8e658815-27ab-41bd-aa91-6d649f3f5486','贈李太守','于鵠','唐','唐诗','tang','','[]','幾年爲郡守，家似布衣貧。',48,'全唐诗/poet.tang.16000.json','["幾年爲郡守，家似布衣貧。", "沽酒迎幽客，無金與近臣。", "擣茶書院靜，講易藥堂春。", "歸闕功成後，隨車有野人。"]'),
('9f752d65-2fcf-4e77-88da-a63babf06e09','送張司直入單于','于鵠','唐','唐诗','tang','','[]','若過幷州北，誰人不憶家。',48,'全唐诗/poet.tang.16000.json','["若過幷州北，誰人不憶家。", "塞深無伴侶，路盡有平沙。", "磧冷唯逢鴈，天春不見花。", "莫隨征將意，垂老事輕車。"]'),
('3470ab57-356f-40ef-9733-762144efa971','惜花','于鵠','唐','唐诗','tang','','[]','夜來花欲盡，始惜兩三枝。',48,'全唐诗/poet.tang.16000.json','["夜來花欲盡，始惜兩三枝。", "早起尋稀處，閑眠記落時。", "蘂焦蜂自散，蔕折蝶還移。", "攀著殷勤別，明年更有期。"]'),
('2cc0d574-4d92-4b42-a70a-63f0f151d7cc','春山居','于鵠','唐','唐诗','tang','','[]','獨來多任性，唯與白雲期。',48,'全唐诗/poet.tang.16000.json','["獨來多任性，唯與白雲期。", "深處花開盡，遲眠人不知。", "水流山暗處，風起月明時。", "望見南峰近，年年嬾更移。"]'),
('5737ad7a-143d-4e8e-8e15-f1b7c4a7edd3','遊瀑泉寺','于鵠','唐','唐诗','tang','','[]','日夕尋未遍，古木寺高低。',48,'全唐诗/poet.tang.16000.json','["日夕尋未遍，古木寺高低。", "粉壁猶遮嶺，朱樓尚隔溪。", "廚窗通澗鼠，殿跡立山雞。", "更有無人處，明朝獨向西。"]'),
('07fbdc14-3490-43de-a1b3-4491731dbf3f','送宮人入道歸山','于鵠','唐','唐诗','tang','','[]','十歲吹蕭入漢宮，看修水殿種芙蓉。',64,'全唐诗/poet.tang.16000.json','["十歲吹蕭入漢宮，看修水殿種芙蓉。", "自傷白髮辭金屋，許著黃衣向玉峰。", "解語老猨開曉戶，學飛雛鶴落高松。", "定知別後宮中伴，應聽緱山半夜鐘。"]'),
('5258bf0f-f67e-46ce-a99b-29526dcf4838','巴女謠','于鵠','唐','唐诗','tang','','["\u4e61\u6751", "\u513f\u7ae5", "\u6c11\u8c23", "\u751f\u6d3b"]','巴女騎牛唱竹枝，藕絲菱葉傍江時。',32,'全唐诗/poet.tang.16000.json','["巴女騎牛唱竹枝，藕絲菱葉傍江時。", "不愁日暮還家錯，記得芭蕉出槿籬。"]'),
('c32d6c2c-b8d6-437d-89da-13d726e2f515','公子行','于鵠','唐','唐诗','tang','','[]','少年初拜大長秋，半醉垂鞭見列侯。',64,'全唐诗/poet.tang.16000.json','["少年初拜大長秋，半醉垂鞭見列侯。", "馬上抱雞三市鬬，袖中攜劒五陵遊。", "玉簫金管迎歸院，錦袖紅妝擁上樓。", "更向院西新買宅，月波春水入門流。"]'),
('0d1c6fe2-f28e-4774-87ee-6c3cd7e3b663','長安遊','于鵠','唐','唐诗','tang','','[]','久臥長安春復秋，五侯長樂客長愁。',64,'全唐诗/poet.tang.16000.json','["久臥長安春復秋，五侯長樂客長愁。", "繡簾朱轂逢花住，錦幨銀珂觸雨遊。", "何處少年吹玉笛，誰家鸚鵡語紅樓。", "年年只是看他貴，不及南山任白頭。"]'),
('5be46944-35d5-4ca6-8e69-e5eeee29c452','別齊太守','于鵠','唐','唐诗','tang','','[]','花裏南樓春夜寒，還如王屋上天壇。',32,'全唐诗/poet.tang.16000.json','["花裏南樓春夜寒，還如王屋上天壇。", "歸山不道無明月，誰共相從到曉看。"]'),
('774f87d0-bbf3-41cf-a07e-98bea4945cd7','登古城','于鵠','唐','唐诗','tang','','[]','獨上閑城却下遲，秋山慘慘塚纍纍。',32,'全唐诗/poet.tang.16000.json','["獨上閑城却下遲，秋山慘慘塚纍纍。", "當時還有登城者，荒草如今知是誰。"]'),
('6d8b0386-c539-45d8-8d63-f7d90c74f21c','哭劉夫子','于鵠','唐','唐诗','tang','','[]','近問南州客，云亡已數春。',48,'全唐诗/poet.tang.16000.json','["近問南州客，云亡已數春。", "痛心曾受業，追服恨無親。", "孀婦歸鄉里，書齋屬四鄰。", "不知經亂後，奠祭有何人。"]'),
('958ab75b-c1ae-4606-b911-9e5cd490b03f','醉後寄山中友人','于鵠','唐','唐诗','tang','','[]','昨日山家春酒濃，野人相勸久從容。',64,'全唐诗/poet.tang.16000.json','["昨日山家春酒濃，野人相勸久從容。", "獨憶卸冠眠細草，不知誰送出深松。", "都忘醉後逢廉度，不省歸時見魯恭。", "知己尚嫌身酩酊，路人應恐笑龍鍾。"]'),
('d934ecd5-00ef-4665-bfd6-d3f5a9d9b933','溫泉僧房','于鵠','唐','唐诗','tang','','[]','雲裏前朝寺，修行獨幾年。',48,'全唐诗/poet.tang.16000.json','["雲裏前朝寺，修行獨幾年。", "山村無施食，盥漱亦安禪。", "古塔巢溪鳥，深房閉谷泉。", "自言曾入室，知處梵王天。"]'),
('c67b136a-b391-4fcd-97d7-c27910856d79','題美人','于鵠','唐','唐诗','tang','','[]','秦女窺人不解羞，攀花趁蝶出牆頭。',32,'全唐诗/poet.tang.16000.json','["秦女窺人不解羞，攀花趁蝶出牆頭。", "胸前空帶宜男草，嫁得蕭郎愛遠遊。"]'),
('1f556f19-fc2b-435a-82fd-183f9c6c0915','尋李暹','于鵠','唐','唐诗','tang','','[]','任性常多出，人來得見稀。',48,'全唐诗/poet.tang.16000.json','["任性常多出，人來得見稀。", "市樓逢酒住，野寺送僧歸。", "簷下懸秋葉，籬頭曬褐衣。", "門前南北路，誰肯入柴扉。"]'),
('f5d5e816-974b-4ae6-8240-5392678b7781','尋李逸人舊居','于鵠','唐','唐诗','tang','','[]','舊隱松林下，衝泉入兩涯。',48,'全唐诗/poet.tang.16000.json','["舊隱松林下，衝泉入兩涯。", "琴書隨弟子，雞犬在鄰家。", "茅屋長黃菌，槿籬生白花。", "幽墳無處訪，恐是入煙霞。"]'),
('73786f95-e483-46bf-9f63-ca78bb9e5204','贈碧玉','于鵠','唐','唐诗','tang','','[]','新繡籠裙荳蔲花，路人笑上返金車。',32,'全唐诗/poet.tang.16000.json','["新繡籠裙荳蔲花，路人笑上返金車。", "霓裳禁曲無人解，暗問梨園弟子家。"]'),
('70858ddb-decc-4fc1-a372-a41879131d4d','舟中月明夜聞笛','于鵠','唐','唐诗','tang','','[]','浦裏移舟候信風，蘆花漠漠夜江空。',32,'全唐诗/poet.tang.16000.json','["浦裏移舟候信風，蘆花漠漠夜江空。", "更深何處人吹笛，疑是孤吟寒水中。"]'),
('a715dbe1-8a5c-4249-ab03-b27132d62c26','送遷客二首 一','于鵠','唐','唐诗','tang','','[]','得罪誰人送，來時不到家。',48,'全唐诗/poet.tang.16000.json','["得罪誰人送，來時不到家。", "白頭無侍子，多病向天涯。", "莽蒼凌江水，黃昏見塞花。", "如今賈誼賦，不漫說長沙。"]'),
('b443cd1f-e94c-43e6-95ae-b9351215fc8f','送遷客二首 二','于鵠','唐','唐诗','tang','','[]','流人何處去，萬里向江州。',48,'全唐诗/poet.tang.16000.json','["流人何處去，萬里向江州。", "孤驛瘴煙重，行人巴草秋。", "上帆南去遠，送鴈北看愁。", "遍問炎方客，無人得白頭。"]'),
('f26cc1ff-5b47-44f7-b827-68077bbf1bb5','贈王道者','于鵠','唐','唐诗','tang','','[]','去尋長不出，門似絕人行。',48,'全唐诗/poet.tang.16000.json','["去尋長不出，門似絕人行。", "牀下石苔滿，屋頭秋草生。", "學琴寒月短，寫易晚窗明。", "唯到黃昏後，溪中聞磬聲。"]'),
('ebebbb5c-e0bc-46d5-9392-61411c2e3ea2','題合溪乾洞','于鵠','唐','唐诗','tang','','[]','渡水傍山尋絕壁，白雲飛處洞天開。',32,'全唐诗/poet.tang.16000.json','["渡水傍山尋絕壁，白雲飛處洞天開。", "仙人來往行無跡，石徑春風長綠苔。"]'),
('afea0c4a-9144-4c79-b212-a68c13b53d9b','過張老園林','于鵠','唐','唐诗','tang','','[]','身老無修飾，頭巾用白紗。',48,'全唐诗/poet.tang.16000.json','["身老無修飾，頭巾用白紗。", "開門朝掃徑，輦水夜澆花。", "藥氣聞深巷，桐陰到數家。", "不愁還酒債，腰下有丹砂。"]'),
('8aaf6380-d813-4330-9195-f4385b33fe1f','寓意','于鵠','唐','唐诗','tang','','[]','自小看花長不足，江邊尋得數株紅。',32,'全唐诗/poet.tang.16000.json','["自小看花長不足，江邊尋得數株紅。", "黃昏人散東風起，吹落誰家明月中。"]'),
('5dff667d-cef0-4f71-95bd-8151dd957335','哭王都護','于鵠','唐','唐诗','tang','','[]','老將明王識，臨終拜上公。',48,'全唐诗/poet.tang.16000.json','["老將明王識，臨終拜上公。", "告哀鄉路遠，助葬戍城空。", "素幔朱門裏，銘旌秋巷中。", "史官如不濫，獨傳說英雄。"]'),
('1cfb1ac1-3199-4d6c-a379-9977348129c6','餞司農宋卿立太尉碑了還江東','于鵠','唐','唐诗','tang','','[]','追立新碑日，憐君苦一身。',48,'全唐诗/poet.tang.16000.json','["追立新碑日，憐君苦一身。", "遠移深澗石，助立故鄉人。", "草色荒墳綠，松陰古殿春。", "平生心已遂，歸去得垂綸。"]'),
('8c96bdbb-c8f8-495d-ac25-52632f73c42c','送唐大夫讓節歸山','于鵠','唐','唐诗','tang','','[]','年老功成乞罷兵，玉階匍匐進雙旌。',64,'全唐诗/poet.tang.16000.json','["年老功成乞罷兵，玉階匍匐進雙旌。", "朱門鴛瓦爲仙觀，白領狐裘出帝城。", "侍女休梳官樣髻，蕃童新改道家名。", "到時浸髮春泉裏，猶夢紅樓簫管聲。"]'),
('0bbbc1e5-e32c-4fe8-9de1-19525e452291','買山吟','于鵠','唐','唐诗','tang','','[]','買得幽山屬漢陽，槿籬疎處種桄榔。',32,'全唐诗/poet.tang.16000.json','["買得幽山屬漢陽，槿籬疎處種桄榔。", "唯有獼猴來往熟，弄人拋果滿書堂。"]'),
('09aa8be6-8a6a-4693-9066-9853aa83ec7b','古詞三首 一','于鵠','唐','唐诗','tang','','[]','素絲帶金地，窗間掬飛塵。',24,'全唐诗/poet.tang.16000.json','["素絲帶金地，窗間掬飛塵。", "偷得鳳凰釵，門前乞行人。"]'),
('bc19d3db-9474-433c-93e1-a6c59ea495f6','古詞三首 二','于鵠','唐','唐诗','tang','','[]','新長青絲髮，啞啞言語黠。',24,'全唐诗/poet.tang.16000.json','["新長青絲髮，啞啞言語黠。", "隨人敲銅鏡，街頭救明月。"]'),
('bab3d928-cfb6-4c38-a339-281b2a324188','古詞三首 三','于鵠','唐','唐诗','tang','','[]','東家新長兒，與妾同時生。',24,'全唐诗/poet.tang.16000.json','["東家新長兒，與妾同時生。", "竝長兩心熟，到大相呼名。"]'),
('0c947585-a808-48d2-869d-e549515cbbf6','秦越人洞中詠','于鵠','唐','唐诗','tang','','[]','扁鵲得仙處，傳是西南峰。',120,'全唐诗/poet.tang.16000.json','["扁鵲得仙處，傳是西南峰。", "年年山下人，長見騎白龍。", "洞門黑無底，日夜唯雷風。", "清齋將入時，戴星兼抱松。", "石徑陰且寒，地響知遠鐘。", "似行山林外，聞葉履聲重。", "低礙更俯身，漸遠晝夜同。", "時時白蝙蝠，飛入茅衣中。", "行久路轉窄，靜聞水淙淙。", "但願逢一人，自得朝天宮。"]'),
('3fd0fbcb-0230-4804-850e-686283bbecbb','宿西山修下元齋詠','于鵠','唐','唐诗','tang','','[]','幽人在何處，松檜深冥冥。',144,'全唐诗/poet.tang.16000.json','["幽人在何處，松檜深冥冥。", "西峰望紫雲，知處安期生。", "沐浴溪水暖，新衣禮仙名。", "脫屐入靜堂，遶像隨禮行。", "碧紗籠寒燈，長幡綴金鈴。", "林下聽法人，起坐枯葉聲。", "啓奏修律儀，天曙山鳥鳴。", "分行布菅茅，列坐滿中庭。", "持齋候撞鐘，玉函散寶經。", "焚香開卷時，照耀金室明。", "投簡石洞深，稱過上帝靈。", "學道能苦心，自古無不成。"]'),
('90259ac4-473c-4451-97f9-7307c1ab0a61','過凌霄洞天謁張先生祠','于鵠','唐','唐诗','tang','','[]','戢戢亂峰裏，一峰獨凌天。',180,'全唐诗/poet.tang.16000.json','["戢戢亂峰裏，一峰獨凌天。", "下看如尖高，上有十里泉。", "志人愛幽深，一住五十年。", "懸牘到其上，乘牛耕藥田。", "衣食不下求，乃是雲中仙。", "山僧獨知處，相引衝碧煙。", "斷崖晝昏黑，槎臬橫隻椽。", "面壁攀石稜，養力方敢前。", "累歇日已沒，始到茅堂邊。", "見客不問誰，禮質無周旋。", "醉臥枕欹樹，寒坐展青氈。", "折松掃藜牀，秋菓顏色鮮。", "鍊蜜敲石炭，洗澡乘瀑泉。", "白犬舐客衣，驚走聞腥膻。", "乃知軒冕徒，寧比雲壑眠。"]'),
('6988ee0e-7257-4539-8f2f-2518806b13e2','早上凌霄第六峰入紫谿禮白鶴觀祠','于鵠','唐','唐诗','tang','','[]','路轉第六峰，傳是十里程。',156,'全唐诗/poet.tang.16000.json','["路轉第六峰，傳是十里程。", "放石試淺深，䃂壁虵鳥驚。", "欲下先襞衣，路底避枯莖。", "迴途歇嵌窟，整帶重冠纓。", "及到紫石溪，晻晻已天明。", "漸近神仙居，桂花濕溟溟。", "陰苔無人蹤，時得白鶴翎。", "忽然見朱樓，象牌題玉京。", "沈沈五雲影，香風散縈縈。", "清齋上玉堂，窗戶懸水精。", "青童撞金屑，杵臼聲丁丁。", "膻腥遙問誰，稽首稱姓名。", "若容在溪口，願乞殘雲英。"]'),
('1e9464f4-6c2f-4bf4-ae66-3ed16d66064e','山中訪道者','于鵠','唐','唐诗','tang','','[]','觸煙入溪口，岸岸唯檉櫟。',156,'全唐诗/poet.tang.16000.json','["觸煙入溪口，岸岸唯檉櫟。", "其中盡碧流，十里不通屐。", "出林山始轉，絕徑緣峭壁。", "把藤借行勢，側足憑石脈。", "㰹牙斷行處，光滑猿猱跡。", "忽然風景異，乃到神仙宅。", "天晴茅屋頭，殘雲蒸氣白。", "隔窗梳髮聲，久立聞吹笛。", "抱琴出門來，不顧人間客。", "山院不灑掃，四時自虛寂。", "落葉埋長松，出地纔數尺。", "曾讀上清經，知注長生籍。", "願示不死方，何山有瓊液。"]'),
('01a40659-28cc-455d-a83a-73ec5a81d982','寄盧儼員外秋衣詞','于鵠','唐','唐诗','tang','','[]','寄遠空以心，心誠亦難知。',120,'全唐诗/poet.tang.16000.json','["寄遠空以心，心誠亦難知。", "篋中有秋帛，裁作遠客衣。", "縫製雖女功，尺度手自持。", "容貌常目中，長短不復疑。", "斜縫密且堅，遊客多塵緇。", "意欲都無言，澣濯耐歲時。", "殷勤託行人，傳語慎勿遺。", "別來年已老，亦聞鬢成絲。", "縱然更相逢，握手唯是悲。", "所寄莫復棄，願見長相思。"]'),
('7ae81318-1141-4de0-9455-7789fea59317','種樹','于鵠','唐','唐诗','tang','','[]','一樹新栽益四鄰，野夫如到舊山春。',32,'全唐诗/poet.tang.16000.json','["一樹新栽益四鄰，野夫如到舊山春。", "樹成多是人先老，垂白看他攀折人。"]'),
('b2a9dfc9-7164-4841-8b44-1ab9d101437c','哭李暹','于鵠','唐','唐诗','tang','','[]','驅馬街中哭送君，靈車碾雪隔城聞。',32,'全唐诗/poet.tang.16000.json','["驅馬街中哭送君，靈車碾雪隔城聞。", "唯有山僧與樵客，共舁孤櫬入幽墳。"]'),
('aea52322-33bf-4e83-9b77-3a47bd6f2ad0','古挽歌 一','于鵠','唐','唐诗','tang','','[]','雙轍出郭門，綿綿東西道。',72,'全唐诗/poet.tang.16000.json','["雙轍出郭門，綿綿東西道。", "送死多於生，幾人得終老。", "見此切肺肝，不如歸山好。", "不聞哀哭聲，默默安懷抱。", "時盡從物化，又免生憂擾。", "世間壽者稀，盡爲悲傷惱。"]'),
('3ef0bbc2-1e0c-4890-82ac-45905f097232','古挽歌 二','于鵠','唐','唐诗','tang','','[]','送哭誰家車，靈旛紫帶長。',48,'全唐诗/poet.tang.16000.json','["送哭誰家車，靈旛紫帶長。", "青童抱何物，明月與香囊。", "可惜羅衣色，看舁入水泉。", "莫愁埏道暗，燒漆得千年。"]'),
('c47e788d-50a6-4c66-b5bb-1a121e179494','古挽歌 三','于鵠','唐','唐诗','tang','','[]','陰風吹黃蒿，挽歌度秋水。',24,'全唐诗/poet.tang.16000.json','["陰風吹黃蒿，挽歌度秋水。", "車馬却歸城，孤墳月明裏。"]'),
('5e4751bd-5f14-487c-ae97-2a7706f3ed9d','悼孩子','于鵠','唐','唐诗','tang','','[]','年長始一男，心亦頗自娛。',96,'全唐诗/poet.tang.16000.json','["年長始一男，心亦頗自娛。", "生來歲未周，奄然却歸無。", "裸送不以衣，瘞埋於中衢。", "乳母抱出門，所生亦隨呼。", "嬰孩無哭儀，禮經不可踰。", "親戚相問時，抑悲空歎吁。", "襁褓在舊牀，每見立踟躕。", "靜思益傷情，畏老爲獨夫。"]'),
('aef32801-f25a-4a9f-8db8-3704e6005953','別舊山','于鵠','唐','唐诗','tang','','[]','舊伴同遊盡却回，雲中獨宿守花開。',32,'全唐诗/poet.tang.16000.json','["舊伴同遊盡却回，雲中獨宿守花開。", "自是去人身漸老，暮山流水任東來。"]'),
('03addfec-c24f-40b8-8f49-99ba51f39704','寄周惲','于鵠','唐','唐诗','tang','','[]','家在荒陂長似秋，蓼花芹葉水蟲幽。',32,'全唐诗/poet.tang.16000.json','["家在荒陂長似秋，蓼花芹葉水蟲幽。", "去年相伴尋山客，明月今宵何處遊。"]'),
('70098333-7c28-4a3a-96d2-40d5e2e38b77','野田行','于鵠','唐','唐诗','tang','','[]','日暮出古城，野田何茫茫。',40,'全唐诗/poet.tang.16000.json','["日暮出古城，野田何茫茫。", "寒狐上孤冢，鬼火燒白楊。", "昔人未爲泉下客，若到此中還斷腸。"]'),
('e3dbe1cd-bf0b-40f6-9367-63ea2fea908d','塞上曲','于鵠','唐','唐诗','tang','','["\u8fb9\u585e"]','行人朝走馬，直走薊城傍。',72,'全唐诗/poet.tang.16000.json','["行人朝走馬，直走薊城傍。", "薊城通漢北，萬里別吳鄉。", "海上一烽火，沙中百戰場。", "軍書發上郡，春色度河陽。", "嫋嫋漢宮柳，青青胡地桑。", "琵琶出塞曲，橫笛斷君腸。"]'),
('dd39b6f4-de96-4d5a-aa5e-5169a43bae7b','襄陽寒食','于鵠','唐','唐诗','tang','','["\u601d\u5ff5", "\u6625\u5929", "\u5199\u666f", "\u5bd2\u98df\u8282"]','煙水初銷見萬家，東風吹柳萬條斜。',32,'全唐诗/poet.tang.16000.json','["煙水初銷見萬家，東風吹柳萬條斜。", "大堤欲上誰相伴，馬踏春泥半是花。"]'),
('9b2a90e2-562a-440c-a447-b38de75a6152','汎舟入後谿','于鵠','唐','唐诗','tang','','[]','雨餘芳草淨沙塵，水綠沙平一帶春。',32,'全唐诗/poet.tang.16000.json','["雨餘芳草淨沙塵，水綠沙平一帶春。", "唯有啼鵑似留客，桃花深處更無人。"]'),
('1b7c46b7-e451-418a-bb12-5219040905bc','寶劒篇','劉長川','唐','唐诗','tang','','[]','寶劒不可得，相逢幾許難。',48,'全唐诗/poet.tang.16000.json','["寶劒不可得，相逢幾許難。", "今朝一度見，赤色照人寒。", "匣裏星文動，環邊月影殘。", "自然神鬼伏，無事莫空彈。"]'),
('655944c8-1dff-4de3-9774-28d561b466d2','將赴東都上李相公','劉長川','唐','唐诗','tang','','[]','四海兵初偃，平津閣正開。',24,'全唐诗/poet.tang.16000.json','["四海兵初偃，平津閣正開。", "誰知大爐下，還有不然灰。"]'),
('ba081551-ed70-4be3-8a89-2414dd6b312a','寄邢逸人','鄭常','唐','唐诗','tang','','[]','羨君無外事，日與世情違。',48,'全唐诗/poet.tang.16000.json','["羨君無外事，日與世情違。", "地僻人難到，溪深鳥自飛。", "儒衣荷葉老，野飯藥苗肥。", "疇昔江湖意，而今憶共歸。"]'),
('aeb28c6b-8831-4018-a16a-7434ecf48df2','送頭陀上人赴廬山寺','鄭常','唐','唐诗','tang','','["\u5e90\u5c71"]','僧家無住著，早晚出東林。',48,'全唐诗/poet.tang.16000.json','["僧家無住著，早晚出東林。", "得道非真相，頭陀是苦心。", "持齋山果熟，倚錫野雲深。", "溪寺誰相待，香花與梵音。"]'),
('c0ef3f5a-9c30-4f6f-b1c7-2d986ba31425','謫居漢陽白沙口阻雨因題驛亭','鄭常','唐','唐诗','tang','','[]','漢陽無遠近，見說過湓城。',48,'全唐诗/poet.tang.16000.json','["漢陽無遠近，見說過湓城。", "雲雨經春客，江山幾日程。", "終隨鷗鳥去，秖待海潮生。", "前路逢漁父，多慚問姓名。"]'),
('90612ff9-2970-4c39-b5a9-df622a7405de','穆陵路','陳存','唐','唐诗','tang','','[]','西遊匣長劒，日暮湘楚間。',48,'全唐诗/poet.tang.16000.json','["西遊匣長劒，日暮湘楚間。", "歇馬上秋草，逢人問故關。", "孤村綠塘水，曠野白雲山。", "方念此中去，何時此路還。"]'),
('af2430da-f902-4987-a23c-094d81cc5b4c','清溪館作','陳存','唐','唐诗','tang','','[]','指途清溪裏，左右唯深林。',48,'全唐诗/poet.tang.16000.json','["指途清溪裏，左右唯深林。", "雲蔽望鄉處，雨愁爲客心。", "遇人多物役，聽鳥時幽音。", "何必滄浪水，庶茲浣塵襟。"]'),
('7fff6dff-900e-4e48-8966-eb1b8632b54f','寓居武丁館','陳存','唐','唐诗','tang','','[]','暑雨飄已過，涼飆觸幽衿。',48,'全唐诗/poet.tang.16000.json','["暑雨飄已過，涼飆觸幽衿。", "虛館無喧塵，綠槐多晝陰。", "俯視古苔積，仰聆早蟬吟。", "放卷一長想，閉門千里心。"]'),
('d51cce8e-37b1-4dca-b5e3-9aba68f3a90b','楚州贈別周愿侍御','陳存','唐','唐诗','tang','','[]','漂泊楚水來，捨舟坐高館。',48,'全唐诗/poet.tang.16000.json','["漂泊楚水來，捨舟坐高館。", "途窮在中路，孤征慕前伴。", "風雨一留宿，關山去欲嬾。", "淮南木葉飛，夜聞廣陵散。"]'),
('4d8d5a4d-2cbd-4f13-b159-9cd635051d57','送劉秀才南歸','陳存','唐','唐诗','tang','','[]','鳥啼楊柳垂，此別千萬里。',48,'全唐诗/poet.tang.16000.json','["鳥啼楊柳垂，此別千萬里。", "古路入商山，春風去灞水。", "停車落日在，罷酒離人起。", "蓬戶寄龍沙，送歸情詎已。"]'),
('77c46717-ab73-49ec-ad4b-10e918a6d924','丹陽作','陳存','唐','唐诗','tang','','[]','暫入新豐市，猶聞舊酒香。',24,'全唐诗/poet.tang.16000.json','["暫入新豐市，猶聞舊酒香。", "抱琴沽一醉，盡日臥垂楊。"]'),
('420f8947-b9d9-4645-8770-5cad877d0c58','早行','王觀','唐','唐诗','tang','','[]','雞唱催人起，又生前去愁。',48,'全唐诗/poet.tang.16000.json','["雞唱催人起，又生前去愁。", "路明殘月在，山露宿雲收。", "村店煙火動，漁家燈燭幽。", "趨名與趨利，行役幾時休。"]'),
('11966f61-b40f-4f30-95d3-4a3cbc72fa91','贈營妓','崔瓘','唐','唐诗','tang','','[]','寒簷寂寂雨霏霏，候館蕭條燭燼微。',32,'全唐诗/poet.tang.16000.json','["寒簷寂寂雨霏霏，候館蕭條燭燼微。", "只有今宵同此宴，翠娥佯醉欲先歸。"]'),
('a15c066c-4002-40a3-84b9-fdd360e8c34f','酒席賦得匏瓢','鄭審','唐','唐诗','tang','','[]','華閣與賢開。',48,'全唐诗/poet.tang.16000.json','["華閣與賢開。", "仙瓢自遠來，幽林嘗伴許。", "陋巷亦隨回，挂影憐紅壁。", "傾心向綠杯，何曾斟酌處。", "不使玉山頹。"]'),
('b653bb96-6980-4140-9fc5-a458611966b0','奉使巡檢兩京路種果樹事畢入秦因詠','鄭審','唐','唐诗','tang','','[]','聖德周天壤，韶華滿帝畿。',96,'全唐诗/poet.tang.16000.json','["聖德周天壤，韶華滿帝畿。", "九重承渙汗，千里樹芳菲。", "陜塞餘陰薄，關河舊色微。", "發生和氣動，封植衆心歸。", "春露條應弱，秋霜果定肥。", "影移行子蓋，香撲使臣衣。", "入逕迷馳道，分行接禁闈。", "何當扈仙蹕，攀折奉恩輝。"]'),
('f410eb46-155b-4693-9a4a-403d65198f00','丹陽作','朱彬','唐','唐诗','tang','','[]','暫入新豐市，猶聞舊酒香。',24,'全唐诗/poet.tang.16000.json','["暫入新豐市，猶聞舊酒香。", "抱琴沽一醉，盡日臥垂楊。"]'),
('4d1d454d-2443-49fe-a691-781179374678','採桑','李彥遠','唐','唐诗','tang','','[]','採桑畏日高，不待春眠足。',48,'全唐诗/poet.tang.16000.json','["採桑畏日高，不待春眠足。", "攀條有餘態，那矜貌如玉。", "千金豈不贈，五馬空躑躅。", "何以變真性，幽篁雪中綠。"]'),
('2be7c1ab-63e2-49b3-899d-45c762b2e904','章仇公席上詠真珠姬','范元凱','唐','唐诗','tang','','[]','神女初離碧玉階，彤雲猶擁牡丹鞋。',32,'全唐诗/poet.tang.16000.json','["神女初離碧玉階，彤雲猶擁牡丹鞋。", "應知子建憐羅襪，顧步裴回拾翠釵。"]'),
('160a79e1-a9ec-4eb5-87d5-3c8c206198d7','爛柯山四首 一','劉迥','唐','唐诗','tang','','[]','白雲引策仗，苔徑誰往還。',36,'全唐诗/poet.tang.16000.json','["白雲引策仗，苔徑誰往還。", "漸見松樹偃，時聞鳥聲閑。", "豁然喧氛盡，獨對萬重山。"]'),
('92544841-0b65-452e-be50-81059808d5b8','爛柯山四首 二','劉迥','唐','唐诗','tang','','[]','石橋架絕壑，蒼翠橫鳥道。',36,'全唐诗/poet.tang.16000.json','["石橋架絕壑，蒼翠橫鳥道。", "憑檻雲脚下，頹陽日猶蚤。", "霓裳倘一遇，千載長不老。"]'),
('b78402fe-fd8f-4a03-a2c2-fad16d474c14','爛柯山四首 三','劉迥','唐','唐诗','tang','','[]','靈境偶一尋，洞天碧雲上。',36,'全唐诗/poet.tang.16000.json','["靈境偶一尋，洞天碧雲上。", "爛柯有遺跡，羽客何由訪。", "日暮悵欲還，晴煙滿千嶂。"]'),
('1ffb8cde-44c1-4a31-ae1a-e60a3eda2897','爛柯山四首 四','劉迥','唐','唐诗','tang','','[]','繩牀宴坐久，石窟絕行跡。',36,'全唐诗/poet.tang.16000.json','["繩牀宴坐久，石窟絕行跡。", "能在人代中，遂將人代隔。", "白雲風颺飛，非欲待歸客。"]'),
('896cdf9b-805f-450f-87a7-fd266cf979f7','前年春與獨孤常州兄花時爲別倏已三年矣今鶯花又爾覩物增懷因之抒情聊以奉寄','李幼卿','唐','唐诗','tang','','[]','近日霜毛一番新，別時芳草兩迴春。',64,'全唐诗/poet.tang.16000.json','["近日霜毛一番新，別時芳草兩迴春。", "不堪花落花開處，況是江南江北人。", "薄宦龍鍾心懶慢，故山寥落水奫淪。", "緣君愛我疵瑕少，願竊仁風寄老身。"]'),
('730fb60d-f059-48cc-9be4-d166ee44757f','遊爛柯山四首 一','李幼卿','唐','唐诗','tang','','[]','拂霧理孤策，薄霄眺層岑。',36,'全唐诗/poet.tang.16000.json','["拂霧理孤策，薄霄眺層岑。", "迥升煙霧外，豁見天地心。", "物象不可及，遲回空詠吟。"]'),
('17c5283a-e49e-45e5-afa6-49c2084d50ee','遊爛柯山四首 二','李幼卿','唐','唐诗','tang','','[]','巨石何崔嵬，橫橋架山頂。',36,'全唐诗/poet.tang.16000.json','["巨石何崔嵬，橫橋架山頂。", "傍通日月過，仰望虹霓迥。", "聖者開津梁，誰能度茲嶺。"]'),
('a9ba2957-e87a-4b50-b77f-98e0b79a44ea','遊爛柯山四首 三','李幼卿','唐','唐诗','tang','','[]','二仙自圍棊，偶與樵夫會。',36,'全唐诗/poet.tang.16000.json','["二仙自圍棊，偶與樵夫會。", "仙家異人代，俄頃千年外。", "笙鶴何時還，儀形尚相對。"]'),
('1487df1d-eef7-404d-8416-148190c359d3','遊爛柯山四首 四','李幼卿','唐','唐诗','tang','','[]','石室過雲外，二僧儼禪寂。',36,'全唐诗/poet.tang.16000.json','["石室過雲外，二僧儼禪寂。", "不語對空山，無心向來客。", "作禮未及終，忘循舊形跡。"]'),
('e8d5935c-b41a-41da-b326-0e188ac37b01','遊爛柯山四首 一','李深','唐','唐诗','tang','','[]','尋源路不迷，絕頂與雲齊。',36,'全唐诗/poet.tang.16000.json','["尋源路不迷，絕頂與雲齊。", "坐引羣峰小，平看萬木低。", "雙林春色上，正有子規啼。"]'),
('5d4a3e3d-e679-4352-8074-42bc387feaf1','遊爛柯山四首 二','李深','唐','唐诗','tang','','[]','嵌空橫洞天，磅礴倚崖巘。',36,'全唐诗/poet.tang.16000.json','["嵌空橫洞天，磅礴倚崖巘。", "宛如虹勢出，可賞不可轉。", "真興得津粱，抽簪永游衍。"]'),
('10793ae1-9b22-421d-a339-01df3c73435e','遊爛柯山四首 三','李深','唐','唐诗','tang','','[]','羽客無姓名，仙棊但聞見。',36,'全唐诗/poet.tang.16000.json','["羽客無姓名，仙棊但聞見。", "行看負薪客，坐使桑田變。", "懷古正怡然，前山早鶯囀。"]'),
('9497caa8-d6ad-48d4-96a7-e6ace892699b','遊爛柯山四首 四','李深','唐','唐诗','tang','','[]','稽首期發蒙，吾師豈無說。',36,'全唐诗/poet.tang.16000.json','["稽首期發蒙，吾師豈無說。", "安禪即方丈，演法皆寂滅。", "鳴磬雨花香，齋堂飯松屑。"]'),
('63c51e96-384a-4e36-bbfb-e607e53b002b','遊爛柯山 一','羊滔','唐','唐诗','tang','','[]','步登春巖裏，更上最遠山。',36,'全唐诗/poet.tang.16000.json','["步登春巖裏，更上最遠山。", "聊見宇宙闊，遂令身世閑。", "清輝賞不盡，高駕何時還。"]'),
('30af2636-10b1-4767-a465-16576c09536d','遊爛柯山 二','羊滔','唐','唐诗','tang','','[]','石梁聳千尺，高盼出林囗。',36,'全唐诗/poet.tang.16000.json','["石梁聳千尺，高盼出林囗。", "亙壑躡丹虹，排雲弄清影。", "路期訪道客，遊衍空井井。"]'),
('643f73f3-6946-46a0-9e3f-5dcd6670b186','遊爛柯山 三','羊滔','唐','唐诗','tang','','[]','採薪窮冥搜，深路轉清暎。',36,'全唐诗/poet.tang.16000.json','["採薪窮冥搜，深路轉清暎。", "安知洞天裏，偶坐得棋聖。", "至今追靈跡，可用陶靜性。"]'),
('6f5bc09a-374e-4fdc-845e-a2facaa7a8fc','遊爛柯山 四','羊滔','唐','唐诗','tang','','[]','沙門何處人，攜手俱滅跡。',36,'全唐诗/poet.tang.16000.json','["沙門何處人，攜手俱滅跡。", "深入不動境，乃知真圓寂。", "有時歸羅浮，白日見飛錫。"]'),
('7feaa005-b044-4d99-94ad-21734d0d48d1','遊爛柯山 一','薛戎','唐','唐诗','tang','','[]','登巖已寂歷，絕頂更岧嶤。',36,'全唐诗/poet.tang.16000.json','["登巖已寂歷，絕頂更岧嶤。", "響像如天近，窺臨與世遙。", "悠然暢心目，萬慮一時銷。"]'),
('fc32fedf-ed94-41b2-a621-c9c6f8587895','遊爛柯山 二','薛戎','唐','唐诗','tang','','[]','聖遊本無跡，留此示津粱。',36,'全唐诗/poet.tang.16000.json','["聖遊本無跡，留此示津粱。", "架險知何適，遺名但不亡。", "只今成佛宇，化度果難量。"]'),
('27c8ddbe-a5e3-45a8-845a-2037dd47a15b','遊爛柯山 三','薛戎','唐','唐诗','tang','','[]','二仙行自適，日月徒遷徙。',36,'全唐诗/poet.tang.16000.json','["二仙行自適，日月徒遷徙。", "不語寄手談，無心引樵子。", "蒙分一丸藥，相偶窮年祀。"]'),
('ad28684c-b58f-4480-9f1c-57e451d79fa6','遊爛柯山 四','薛戎','唐','唐诗','tang','','[]','仙山習禪處，了知通李釋。',36,'全唐诗/poet.tang.16000.json','["仙山習禪處，了知通李釋。", "昔作異時人，今成相對寂。", "便是不二門，自生瞻仰意。"]'),
('cb53777c-911e-4aa2-a921-5d12707d82c3','遊爛柯山 一','謝勮','唐','唐诗','tang','','[]','獨凌清景出，下視衆山中。',36,'全唐诗/poet.tang.16000.json','["獨凌清景出，下視衆山中。", "雲日遙相對，川原無不通。", "自致高標末，何心待馭風。"]'),
('674e19cf-209a-4170-8dbc-04f1704f6ce0','遊爛柯山 二','謝勮','唐','唐诗','tang','','[]','宛演橫半規，穹崇翠微上。',36,'全唐诗/poet.tang.16000.json','["宛演橫半規，穹崇翠微上。", "雲扃掩苔石，千古無人賞。", "寧知後賢心，登此共來往。"]'),
('2cf4d796-09e7-44bc-b6a0-6b98d6ac872c','遊爛柯山 三','謝勮','唐','唐诗','tang','','[]','仙弈示樵夫，能言忘歸路。',36,'全唐诗/poet.tang.16000.json','["仙弈示樵夫，能言忘歸路。", "因看斧柯爛，孫子髮已素。", "孰云遺跡久，舉意如旦暮。"]'),
('dba9ad86-b6a8-4db2-b67a-686ea1dd8670','遊爛柯山 四','謝勮','唐','唐诗','tang','','[]','仙僧會真要，應物常淵默。',36,'全唐诗/poet.tang.16000.json','["仙僧會真要，應物常淵默。", "惟將無住理，轉與信人說。", "月影清江中，可觀不可得。"]'),
('8386aabc-4ddd-4c38-a062-c3e8c7c47486','奉和聖製三日書懷因以示百寮','崔元翰','唐','唐诗','tang','','[]','佳節上元巳，芳時屬暮春。',72,'全唐诗/poet.tang.16000.json','["佳節上元巳，芳時屬暮春。", "流觴想蘭亭，捧劒傳金人。", "風輕水初綠，日遲花更新。", "天文信昭回，皇道頗敷陳。", "恭己每從儉，清心常保真。", "戒茲遊衍樂，書以示羣臣。"]'),
('c8621bb1-0103-4ce2-88ec-af505c36b118','奉和聖製重陽旦日百寮曲江宴示懷','崔元翰','唐','唐诗','tang','','["\u5bb4\u996e", "\u91cd\u9633\u8282"]','偶聖覩昌期，受恩慙弱質。',120,'全唐诗/poet.tang.16000.json','["偶聖覩昌期，受恩慙弱質。", "幸逢良宴會，況是清秋日。", "遠岫對壺觴，澄瀾映簪紱。", "炮羔備豐膳，集鳳調鳴律。", "薄劣廁英豪，歡娛忘衰疾。", "平臯行雁下，曲渚雙鳧出。", "沙岸菊開花，霜枝果垂實。", "天文見成象，帝念資勤恤。", "探道得玄珠，齋心居特室。", "豈如橫汾唱，其事徒驕逸。"]'),
('aa9b7de0-a697-4f5b-b2f9-bac84361a46d','奉和聖製中元日題奉敬寺','崔元翰','唐','唐诗','tang','','["\u6625\u8282"]','妙道非本說，殊途成異名。',108,'全唐诗/poet.tang.16000.json','["妙道非本說，殊途成異名。", "聖人得其要，俱以化羣生。", "鳳吹從上苑，龍宮連外城。", "花鬘列後殿，雲車駐前庭。", "松竹含新秋，軒窗有餘清。", "緬懷崆峒事，須繼簫管聲。", "離相境都寂，忘言理更精。", "域中信稱大，天下乃爲輕。", "屈己由濟物，堯心豈所榮。"]'),
('2d73b38a-6d38-4bcb-98fc-8454a61de134','奉和登玄武樓觀射即事書懷賜孟涉應制','崔元翰','唐','唐诗','tang','','[]','寧歲常有備，殊方靡不賓。',96,'全唐诗/poet.tang.16000.json','["寧歲常有備，殊方靡不賓。", "禁營列武衛，帝座彰威神。", "講事一臨幸，加恩徧撫巡。", "城高鳳樓聳，塲逈獸侯新。", "飲羽連百中，控弦踰六鈞。", "揀材盡爪士，受任皆信臣。", "光賞文藻麗，便繁心膂親。", "復如觀太清，昭爛垂芳辰。"]'),
('6a7c53b1-7214-4fb5-8b94-ba0ded548abb','清明節郭侍御偶與李侍御孔校書王秀才遊開化寺臥病不得同遊賦得十韻兼呈馬十八郎丞公','崔元翰','唐','唐诗','tang','','["\u6e05\u660e\u8282", "\u6e38\u5386"]','山色入層城，鍾聲臨複岫。',120,'全唐诗/poet.tang.16000.json','["山色入層城，鍾聲臨複岫。", "乘閑息邊事，探異憐春候。", "曲閣下重階，迴廊遙對霤。", "石間花徧落，草上雲時覆。", "鑽火見樵人，飲泉逢野獸。", "道情親法侶，時望登朝右。", "執憲糺姦邪，刊書正訛謬。", "茂才當時選，公子生人秀。", "贈荅繼篇章，歡娛重朋舊。", "垂簾獨衰疾，擊缶酬金奏。"]'),
('1cac20d0-4eb1-4b7b-a829-ff529c939a1c','雜言奉和聖製至承光院見自生藤感其得地因以成詠應制','崔元翰','唐','唐诗','tang','','[]','新藤正可翫，得地又逢時。',128,'全唐诗/poet.tang.16000.json','["新藤正可翫，得地又逢時。", "羅生密葉交綠蔓，欲布清陰垂紫蕤。", "已帶朝光暖，猶含輕露滋。", "遙依千華殿，稍上萬年枝。", "餘芳連桂樹，積潤傍蓮池。", "豈如幽谷無人見，空覆荒榛雜兔絲。", "聖心對此應有感，隱迹如斯誰復知。", "懷賢勞永歎，比物賦新詩。", "聘丘園，訪茅茨。", "爲謝中林士，王道本無私。"]'),
('06bcd5bc-f822-48b9-9204-08e3eff83f4d','雨中對後簷叢竹','崔元翰','唐','唐诗','tang','','[]','含風搖硯水，帶雨拂牆衣。',24,'全唐诗/poet.tang.16000.json','["含風搖硯水，帶雨拂牆衣。", "乍似秋江上，漁家半掩扉。"]'),
('1a253649-bc67-4efb-b7a9-6486a4cf591c','賦得沈珠於泉','獨孤良器','唐','唐诗','tang','','[]','皎潔沈泉水，熒煌照乘珠。',72,'全唐诗/poet.tang.16000.json','["皎潔沈泉水，熒煌照乘珠。", "沈非將寶契，還與不貪符。", "風折璿成浪，空涵影似浮。", "深看星幷入，靜向月同無。", "光價憐時重，亡情信道樞。", "不應無脛至，自爲暗投殊。"]'),
('824960be-7ecd-4bfd-902d-689a3a9d39b3','雪席口占','高崇文','唐','唐诗','tang','','[]','崇文宗武不崇文，提戈出塞號將軍。',32,'全唐诗/poet.tang.16000.json','["崇文宗武不崇文，提戈出塞號將軍。", "那箇𩩉兒射雁落，白毛空裏亂紛紛。"]'),
('4b43cff2-ab22-4a9b-b8e3-d6dd4b4dde1b','雪席口占','高崇文','唐','唐诗','tang','','[]','崇文崇武不崇文，提戈出塞舊從軍。',32,'全唐诗/poet.tang.16000.json','["崇文崇武不崇文，提戈出塞舊從軍。", "有似蕃兒射雁落，白毛空裏亂紛紛。"]'),
('2eec7b9f-8420-4c2d-9dfe-cfaec4d6622a','行縣至浮查山寺','羅珦','唐','唐诗','tang','','[]','三十年前此布衣，鹿鳴西上虎符歸。',64,'全唐诗/poet.tang.16000.json','["三十年前此布衣，鹿鳴西上虎符歸。", "行時賓從過前寺，到處松杉長舊圍。", "野老競遮官道拜，沙鷗遙避隼旟飛。", "春風一宿琉璃地，自有泉聲愜素機。"]'),
('cb531005-605f-4a66-8fbd-9512f14e03cf','賦四相詩 中書令漢陽王張柬之','皇甫澈','唐','唐诗','tang','','[]','周曆革元命，天步值艱阻。',72,'全唐诗/poet.tang.16000.json','["周曆革元命，天步值艱阻。", "烈烈張漢陽，左袒清諸武。", "休明神器正，文物舊儀覩。", "南向翊大君，西宮朝聖母。", "茂勳鏤鐘鼎，鴻勞食茅土。", "至今稱五王，卓立邁萬古。"]'),
('ebc87cea-4917-49ad-bb47-87ad0612f826','賦四相詩 中書令鍾紹京','皇甫澈','唐','唐诗','tang','','[]','景龍仙駕遠，中禁奸釁結。',72,'全唐诗/poet.tang.16000.json','["景龍仙駕遠，中禁奸釁結。", "謀猷叶聖朝，披鱗奮英節。", "青宮閶闔啓，滌穢氛沴滅。", "紫氣重昭回，皇天新日月。", "從容廟堂上，肅穆人神悅。", "唐元佐命功，輝煥何烈烈。"]'),
('6852da31-3e1c-4d0f-b825-d783ac0be104','賦四相詩 禮部尚書門下侍郎平章事李峴','皇甫澈','唐','唐诗','tang','','[]','時來遇明聖，道濟寧邦國。',72,'全唐诗/poet.tang.16000.json','["時來遇明聖，道濟寧邦國。", "猗歟瑚璉器，竭我股肱力。", "進賢黜不肖，錯枉舉諸直。", "宦官既却坐，權奸亦移職。", "載踐每若驚，三已無慍色。", "昭昭垂憲章，來世實作則。"]'),
('291140fd-f2f1-4f69-b20c-69ca187a02d9','賦四相詩 門下侍郎平章事王縉','皇甫澈','唐','唐诗','tang','','[]','舟檝濟巨川，山河資秀氣。',72,'全唐诗/poet.tang.16000.json','["舟檝濟巨川，山河資秀氣。", "服膺究儒業，屈指取高位。", "北征戮驕悍，東守輯攜貳。", "論道致巍巍，持衡無事事。", "知己不易遇，宰相固有器。", "瞻事華壁中，來者誰其嗣。"]'),
('72c74470-21f6-448b-876d-a147866b09dd','上巳泛舟得遲字','張登','唐','唐诗','tang','','[]','令節推元巳，天涯喜有期。',72,'全唐诗/poet.tang.16000.json','["令節推元巳，天涯喜有期。", "初筵臨泛地，舊俗祓禳時。", "枉渚潮新上，殘春日正遲。", "竹枝遊女曲，桃葉渡江詞。", "風鷁今方退，沙鷗亦未疑。", "且同山簡醉，倒載莫褰帷。"]'),
('4ab954e0-68ab-4681-abcc-cbf18bb5818f','送王主簿遊南海','張登','唐','唐诗','tang','','[]','平生推久要，留滯共三年。',72,'全唐诗/poet.tang.16000.json','["平生推久要，留滯共三年。", "明日東南路，窮荒霧露天。", "曠懷常寄酒，素業不言錢。", "道在貧非病，時來醜亦妍。", "過山乘蠟屐，涉海附樓船。", "行矣無爲恨，宗門有大賢。"]'),
('32dc9f07-4c78-4901-991c-a66cb0a3c2aa','重陽宴集同用寒字','張登','唐','唐诗','tang','','[]','錫宴逢佳節，窮荒亦共歡。',72,'全唐诗/poet.tang.16000.json','["錫宴逢佳節，窮荒亦共歡。", "恩深百日澤，雨借九秋寒。", "望氣人謠洽，臨風客以難。", "座移山色在，杯盡菊香殘。", "欲識投醪遍，應從落帽看。", "還宵須命燭，舉首謝三官。"]');
